import { useState, useEffect, lazy, Suspense } from 'react'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { BotMessageSquare } from 'lucide-react'
import { getCurrentUser, onAuthStateChange, supabase } from '@shared/utils/supabase'
import { useNotificationLog } from '@shared/hooks/useNotificationLog'
import { useUnreadNotificationCount } from '@shared/hooks/useUnreadNotificationCount'
import '@shared/styles/index.css'
import appStyles from './App.module.css'
import Auth from './views/Auth'
import Loading from '@shared/components/ui/Loading'

// Lazy imports — carregam apenas quando a view é acessada
const Landing = lazy(() => import('./views/Landing'))
const Medicines = lazy(() => import('./views/redesign/Medicines'))
const Stock = lazy(() => import('./views/redesign/Stock'))
const Protocols = lazy(() => import('./views/Protocols'))
const HealthHistory = lazy(() => import('./views/redesign/HealthHistory'))
const Settings = lazy(() => import('./views/redesign/Settings'))
const Emergency = lazy(() => import('./views/redesign/Emergency'))
const Treatment = lazy(() => import('./views/redesign/Treatments'))
const Profile = lazy(() => import('./views/redesign/Profile'))
const Consultation = lazy(() => import('./views/redesign/Consultation'))
const DLQAdmin = lazy(() => import('./views/admin/DLQAdmin'))
const Dashboard = lazy(() => import('./views/redesign/Dashboard'))
const NotificationInbox = lazy(() => import('./views/redesign/NotificationInbox'))
const ChatWindow = lazy(() => import('@features/chatbot/components/ChatWindow'))
const BottomNavRedesign = lazy(() => import('@shared/components/ui/BottomNavRedesign'))
const Sidebar = lazy(() => import('@shared/components/ui/Sidebar'))
const GlobalDoseModal = lazy(() => import('@shared/components/ui/GlobalDoseModal'))
import TestConnection from '@shared/components/TestConnection'
import { OnboardingProvider, OnboardingWizard } from '@shared/components/onboarding'
import { DashboardProvider } from '@dashboard/hooks/useDashboardContext.jsx'
import InstallPrompt from '@shared/components/pwa/InstallPrompt'
import { OfflineBanner } from '@shared/components/ui/OfflineBanner'

/**
 * Placeholder exibido enquanto chunk de view carrega
 */
function ViewSkeleton() {
  return (
    <div
      role="status"
      style={{
        minHeight: '60vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: 'var(--color-text-secondary)',
        fontSize: '14px',
      }}
      aria-busy="true"
      aria-label="Carregando view..."
    >
      <span className="sr-only">Carregando...</span>
    </div>
  )
}

function AppInner() {
  const shouldReduceMotion = useReducedMotion()
  const [session, setSession] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [currentView, setCurrentView] = useState('dashboard')
  const [isChatOpen, setIsChatOpen] = useState(false)
  const [isDoseModalOpen, setIsDoseModalOpen] = useState(false)
  const [doseModalInitialValues, setDoseModalInitialValues] = useState(null)
  const [initialProtocolParams, setInitialProtocolParams] = useState(null)
  const [initialStockParams, setInitialStockParams] = useState(null)
  const [initialTreatmentMedicineId, setInitialTreatmentMedicineId] = useState(null)
  const [showAuth, setShowAuth] = useState(false) // toggles auth UI for unauthenticated visitors

  const { data: notifData } = useNotificationLog({ userId: session?.id, limit: 30, enabled: !!session?.id })
  const { unreadCount } = useUnreadNotificationCount(notifData)

  useEffect(() => {
    // Check initial session
    getCurrentUser()
      .then((user) => {
        setSession(user)
        setIsLoading(false)
      })
      .catch(() => {
        setSession(null)
        setIsLoading(false)
      })

    // Listen for changes
    const {
      data: { subscription },
    } = onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_OUT') {
        // Refresh token pode ter falhado por race condition (PWA + aba do browser concorrentes).
        // Verificar se outro contexto já renovou a sessão antes de deslogar o usuário.
        const { data: { session: latestSession } } = await supabase.auth.getSession()
        setSession(latestSession?.user ?? null)
        return
      }
      setSession(session?.user ?? null)
    })

    return () => subscription.unsubscribe()
  }, [])

  const navigateToProtocol = (medicineId) => {
    setInitialTreatmentMedicineId(medicineId)
    setCurrentView('treatment')
  }

  const navigateToStock = (medicineId) => {
    setInitialStockParams({ medicineId })
    setCurrentView('stock')
  }

  if (isLoading) {
    return (
      <div
        className="app-container"
        style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}
      >
        <Loading text="Carregando..." />
      </div>
    )
  }

  const isAuthenticated = !!session

  const renderCurrentView = () => {
    if (!session) {
      return showAuth ? (
        <Auth
          onAuthSuccess={() => {
            setShowAuth(false)
            setCurrentView('dashboard')
          }}
          onClose={() => setShowAuth(false)}
        />
      ) : (
        <Suspense fallback={<ViewSkeleton />}>
          <Landing isAuthenticated={false} onOpenAuth={() => setShowAuth(true)} />
        </Suspense>
      )
    }

    switch (currentView) {
      case 'landing':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Landing
              isAuthenticated={isAuthenticated}
              onOpenAuth={() => setShowAuth(true)}
              onContinue={() => setCurrentView('dashboard')}
            />
          </Suspense>
        )
      case 'medicines':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Medicines onNavigateToProtocol={navigateToProtocol} />
          </Suspense>
        )
      case 'stock':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Stock
              initialParams={initialStockParams}
              onClearParams={() => setInitialStockParams(null)}
            />
          </Suspense>
        )
      case 'protocols':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Protocols
              initialParams={initialProtocolParams}
              onClearParams={() => setInitialProtocolParams(null)}
              onNavigateToStock={navigateToStock}
            />
          </Suspense>
        )
      case 'treatment':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Treatment
              onNavigateToProtocol={() => setCurrentView('treatment')}
              onNavigate={setCurrentView}
              initialMedicineId={initialTreatmentMedicineId}
              onClearInitialMedicine={() => setInitialTreatmentMedicineId(null)}
            />
          </Suspense>
        )
      case 'profile':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Profile onNavigate={setCurrentView} />
          </Suspense>
        )
      case 'health-history':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <HealthHistory key="health-history" onNavigate={setCurrentView} />
          </Suspense>
        )
      case 'history':
        // W3-06: historico agora vive em HealthHistory
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <HealthHistory key="history" onNavigate={setCurrentView} />
          </Suspense>
        )
      case 'consultation':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Consultation onBack={() => setCurrentView('profile')} />
          </Suspense>
        )
      case 'settings':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Settings onNavigate={setCurrentView} />
          </Suspense>
        )
      case 'emergency':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Emergency onNavigate={setCurrentView} />
          </Suspense>
        )
      case 'admin-dlq':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <DLQAdmin />
          </Suspense>
        )
      case 'notifications':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <NotificationInbox
              userId={session?.id}
              onNavigate={setCurrentView}
              onBack={() => setCurrentView('dashboard')}
              onOpenDoseModal={(initialValues) => {
                setDoseModalInitialValues(initialValues)
                setIsDoseModalOpen(true)
              }}
            />
          </Suspense>
        )
      case 'dashboard':
      default: {
        const dashboardNavigate = (view, params) => {
          if (view === 'stock' && params?.medicineId) {
            setInitialStockParams({ medicineId: params.medicineId })
          } else if (view === 'protocols' && params?.medicineId) {
            setInitialProtocolParams({ medicineId: params.medicineId })
          }
          setCurrentView(view)
        }
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Dashboard onNavigate={dashboardNavigate} />
          </Suspense>
        )
      }
    }
  }

  return (
    <OnboardingProvider>
      <DashboardProvider>
        {/* Skip to main content — visível apenas no focus, para navegação por teclado */}
        <a href="#main-content" className="skip-to-content">
          Ir para conteúdo principal
        </a>

        <div className="app-container">
          {/* Sidebar — desktop, apenas usuários autenticados */}
          {isAuthenticated && (
            <Suspense fallback={null}>
              <Sidebar
                currentView={currentView}
                setCurrentView={setCurrentView}
                onNewDose={() => setIsDoseModalOpen(true)}
                unreadCount={unreadCount}
              />
            </Suspense>
          )}

          <main
            id="main-content"
            className={isAuthenticated ? 'app-main main-with-sidebar' : 'app-main'}
          >
            <AnimatePresence mode="wait" initial={false}>
              <motion.div
                key={currentView}
                initial={shouldReduceMotion ? undefined : { opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={shouldReduceMotion ? undefined : { opacity: 0, y: -4 }}
                transition={{ duration: shouldReduceMotion ? 0 : 0.25, ease: 'easeOut' }}
              >
                {renderCurrentView()}
              </motion.div>
            </AnimatePresence>
            <footer
              style={{
                textAlign: 'center',
                marginTop: 'var(--space-8)',
                paddingBottom: 'var(--space-8)',
                color: 'var(--text-tertiary)',
                fontSize: 'var(--font-size-sm)',
              }}
            >
              {' '}
            </footer>
          </main>

          <OfflineBanner />

          {/* BottomNav — redesign version */}
          {isAuthenticated && (
            <Suspense fallback={null}>
              <BottomNavRedesign currentView={currentView} setCurrentView={setCurrentView} unreadCount={unreadCount} />
            </Suspense>
          )}

          {/* Chatbot IA — lazy-loaded, disponivel para usuarios autenticados */}
          {isAuthenticated && (
            <>
              <button
                onClick={() => setIsChatOpen(true)}
                aria-label="Abrir assistente IA"
                className={appStyles.chatFab}
              >
                <BotMessageSquare size={24} />
              </button>
              {isChatOpen && (
                <Suspense fallback={null}>
                  <ChatWindow isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} />
                </Suspense>
              )}
            </>
          )}

          {/* FAB móvel "Registrar Dose" — visível apenas mobile */}
          {isAuthenticated && (
            <button
              onClick={() => setIsDoseModalOpen(true)}
              aria-label="Registrar dose"
              className={appStyles.doseFab}
            >
              + Dose
            </button>
          )}

          {/* Modal global de registro de dose */}
          {isAuthenticated && isDoseModalOpen && (
            <Suspense fallback={null}>
              <GlobalDoseModal
                isOpen={isDoseModalOpen}
                initialValues={doseModalInitialValues}
                onClose={() => { setIsDoseModalOpen(false); setDoseModalInitialValues(null) }}
              />
            </Suspense>
          )}

          {/* Onboarding Wizard - apenas para usuários autenticados */}
          {isAuthenticated && <OnboardingWizard />}

          {/* PWA Install Prompt - para todos os usuários */}
          <InstallPrompt />
        </div>
      </DashboardProvider>
    </OnboardingProvider>
  )
}

function App() {
  return <AppInner />
}

export default App

import { useState } from 'react'
import { debugLog } from '@shared/utils/logger'
import './AdherenceHeatmap.css'

/**
 * Nomes dos dias da semana
 */
const DAY_NAMES = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']

/**
 * Nomes dos períodos do dia
 */
const PERIOD_NAMES = ['Madrugada', 'Manhã', 'Tarde', 'Noite']

/**
 * Componente de heatmap de adesão por dia da semana e período do dia
 *
 * Props:
 * - pattern: { grid, worstCell, narrative, hasEnoughData } (saída de analyzeAdherencePatterns)
 *
 * Renderiza:
 * - Desktop (>= 380px): Grid 7x4 via CSS
 * - Mobile (< 380px): Stacked cards via CSS
 * (A responsividade é controlada por media queries no CSS, não por lógica JS)
 */
export default function AdherenceHeatmap({ pattern }) {
  // States
  const [hoveredCell, setHoveredCell] = useState(null)
  const [touchedCell, setTouchedCell] = useState(null)

  debugLog('AdherenceHeatmap', 'Pattern recebido:', pattern)

  // Guard clause: dados insuficientes
  if (!pattern || !pattern.hasEnoughData) {
    debugLog('AdherenceHeatmap', 'Dados insuficientes:', {
      hasPattern: !!pattern,
      hasEnoughData: pattern?.hasEnoughData,
      narrative: pattern?.narrative,
    })
    return (
      <div className="adherence-heatmap adherence-heatmap--empty" role="status">
        <p className="adherence-heatmap__empty-message">
          {pattern?.narrative || 'Registre pelo menos 21 dias de doses para análise de padrões.'}
        </p>
      </div>
    )
  }

  /**
   * Calcula opacidade baseada na adherência (0-100%)
   * 100% = 1.0 (verde opaco)
   * 50% = 0.5 (verde translúcido)
   * 0% = 0.1 (verde bem transparente)
   * null = N/D (cinza neutro)
   */
  const getOpacity = (adherence) => {
    if (adherence === null) return 1.0
    if (adherence >= 90) return 1.0
    if (adherence >= 75) return 0.8
    if (adherence >= 50) return 0.5
    if (adherence >= 25) return 0.25
    return 0.1
  }

  /**
   * Retorna cor CSS com opacidade adequada
   * null = cinza neutro (sem protocolo)
   */
  const getCellColor = (adherence) => {
    if (adherence === null) return 'rgba(120, 120, 140, 0.15)' // cinza neutro para N/D
    const opacity = getOpacity(adherence)
    return `rgba(34, 197, 94, ${opacity})` // green-500 com opacidade variável
  }

  /**
   * Constrói o texto do tooltip com informações corretas de adesão
   */
  const buildTooltip = (dayIndex, periodIndex) => {
    const cell = pattern.grid[dayIndex][periodIndex]
    const adherenceText = cell.adherence === null ? 'N/D' : `${cell.adherence}%`
    // totalExpected = doses esperadas por dia × quantas vezes esse dia ocorre nos logs
    const totalExpected = cell.expected * (pattern.dayOccurrences?.[dayIndex] || 1)
    return `${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}: ${adherenceText} (${cell.taken}/${totalExpected} doses)`
  }

  /**
   * Handler para tooltip ao passar mouse
   */
  const handleCellInteraction = (dayIndex, periodIndex) => {
    setHoveredCell(buildTooltip(dayIndex, periodIndex))
  }

  /**
   * Handler para tooltip ao tocar em mobile
   */
  const handleCellTouchEnd = (dayIndex, periodIndex) => {
    const tooltip = buildTooltip(dayIndex, periodIndex)
    setTouchedCell(tooltip === touchedCell ? null : tooltip)
  }

  const handleCellMouseLeave = () => {
    setHoveredCell(null)
  }

  // Renderização: Grid (visível em desktop via CSS) + Stacked (visível em mobile via CSS)
  return (
    <div
      className="adherence-heatmap"
      role="region"
      aria-label="Heatmap de adesão por dia e período"
    >
      {/* Grid: Desktop (>=380px) */}
      <div className="adherence-heatmap__grid-container">
        <div className="adherence-heatmap__container">
          {' '}
          {/* Inner container for grid styling */}
          {/* Cabeçalho com períodos */}
          <div className="adherence-heatmap__header">
            <div className="adherence-heatmap__corner" />
            {PERIOD_NAMES.map((period, idx) => (
              <div key={idx} className="adherence-heatmap__period-header">
                {period}
              </div>
            ))}
          </div>
          {/* Grid de células */}
          {pattern.grid.map((row, dayIndex) => (
            <div key={dayIndex} className="adherence-heatmap__row">
              {/* Label do dia */}
              <div className="adherence-heatmap__day-label">{DAY_NAMES[dayIndex]}</div>

              {/* Células do grid */}
              {row.map((cell, periodIndex) => {
                const cellKey = `${dayIndex}-${periodIndex}`
                const isActive =
                  hoveredCell !== null &&
                  hoveredCell.includes(`${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}`)

                return (
                  <div
                    key={cellKey}
                    className={`adherence-heatmap__cell ${isActive ? 'adherence-heatmap__cell--active' : ''} ${cell.adherence === null ? 'adherence-heatmap__cell--na' : ''}`}
                    style={{ backgroundColor: getCellColor(cell.adherence) }}
                    onMouseEnter={() => handleCellInteraction(dayIndex, periodIndex)}
                    onMouseLeave={handleCellMouseLeave}
                    onTouchEnd={() => handleCellTouchEnd(dayIndex, periodIndex)}
                    role="gridcell"
                    aria-label={`${DAY_NAMES[dayIndex]} ${PERIOD_NAMES[periodIndex]}: ${cell.adherence === null ? 'N/D' : `${cell.adherence}%`}`}
                    tabIndex={0}
                  >
                    <span className="adherence-heatmap__cell-text">
                      {cell.adherence === null ? '—' : `${cell.adherence}%`}
                    </span>
                  </div>
                )
              })}
            </div>
          ))}
          {/* Tooltip flutuante */}
          {hoveredCell && (
            <div className="adherence-heatmap__tooltip" role="tooltip">
              {hoveredCell}
            </div>
          )}
          {/* Tooltip para mobile (persistente) */}
          {touchedCell && (
            <div
              className="adherence-heatmap__tooltip adherence-heatmap__tooltip--mobile"
              role="status"
            >
              {touchedCell}
            </div>
          )}
        </div>
      </div>

      {/* Stacked: Mobile (<380px) */}
      <div className="adherence-heatmap__stacked-wrapper">
        <div className="adherence-heatmap__stacked-container">
          {pattern.grid.map((row, dayIndex) => (
            <div key={dayIndex} className="adherence-heatmap__day-card">
              <h4 className="adherence-heatmap__day-card-title">{DAY_NAMES[dayIndex]}</h4>
              <div className="adherence-heatmap__day-card-periods">
                {row.map((cell, periodIndex) => (
                  <div
                    key={periodIndex}
                    className={`adherence-heatmap__period-bar ${cell.adherence === null ? 'adherence-heatmap__period-bar--na' : ''}`}
                  >
                    <span className="adherence-heatmap__period-name">
                      {PERIOD_NAMES[periodIndex]}
                    </span>
                    <div className="adherence-heatmap__period-fill-bg">
                      <div
                        className="adherence-heatmap__period-fill"
                        style={{
                          width: `${cell.adherence === null ? 0 : cell.adherence}%`,
                          backgroundColor: getCellColor(cell.adherence),
                        }}
                      />
                    </div>
                    <span className="adherence-heatmap__period-percent">
                      {cell.adherence === null ? '—' : `${cell.adherence}%`}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Narrativa (única para ambos os layouts) */}
      {pattern.narrative && (
        <div className="adherence-heatmap__narrative" role="status">
          💡 {pattern.narrative}
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { adherenceService } from '@services/api/adherenceService'
import AdherenceProgress from './AdherenceProgress'
import StreakBadge from './StreakBadge'
import Loading from '@shared/components/ui/Loading'
import './AdherenceWidget.css'

/**
 * @typedef {Object} ProtocolScore
 * @property {string} protocolId - ID do protocolo
 * @property {string} name - Nome do protocolo
 * @property {string} [medicineName] - Nome do medicamento associado
 * @property {number} score - Porcentagem de adesão (0-100)
 */

/**
 * @typedef {Object} AdherenceData
 * @property {number} overallScore - Score geral de adesão (0-100)
 * @property {number} overallTaken - Total de doses tomadas
 * @property {number} overallExpected - Total de doses esperadas
 * @property {number} [currentStreak] - Dias consecutivos atual
 * @property {number} [longestStreak] - Recorde de dias consecutivos
 * @property {ProtocolScore[]} [protocolScores] - Scores por protocolo
 */

/**
 * @typedef {Object} AdherenceWidgetProps
 * @property {string} [defaultPeriod='30d'] - Período inicial: '7d' | '30d' | '90d'
 */

/**
 * AdherenceWidget - Widget completo de adesão ao tratamento
 *
 * **Propósito:**
 * Widget completo que carrega e exibe dados de adesão ao tratamento,
 * incluindo score geral, streak, adesão por protocolo e dicas personalizadas.
 * Este componente gerencia seu próprio estado de dados e chamadas à API.
 *
 * **Funcionalidades incluídas:**
 * - Score geral de adesão com indicador visual circular
 * - Seletor de período (7 dias, 30 dias, 90 dias)
 * - Streak atual e recorde de dias consecutivos
 * - Breakdown de adesão por protocolo
 * - Dicas contextualizadas baseadas no score
 * - Estados de loading e erro
 *
 * **Quando usar:**
 * - No dashboard para visão geral de adesão
 * - Quando você precisa que os dados sejam carregados automaticamente
 * - Para widgets completos com interatividade (mudança de período)
 *
 * **Quando NÃO usar (use AdherenceProgress em vez disso):**
 * - Quando você já tem o valor calculado e só precisa exibir
 * - Para indicadores visuais simples em cards ou listas
 * - Quando precisa de controle total sobre o layout e dados
 *
 * **Dependências de dados:**
 * Este componente usa {@link adherenceService} para carregar:
 * - Resumo de adesão via `adherenceService.getAdherenceSummary(period)`
 *
 * @param {AdherenceWidgetProps} props
 * @returns {JSX.Element}
 *
 * @example
 * // Uso padrão com período inicial de 30 dias
 * <AdherenceWidget />
 *
 * @example
 * // Período inicial customizado
 * <AdherenceWidget defaultPeriod="7d" />
 *
 * @see {@link AdherenceProgress} - Para componente visual puro sem dados
 * @see {@link StreakBadge} - Para exibir streak em outros contextos
 */
export default function AdherenceWidget({ defaultPeriod = '30d' }) {
  const [period, setPeriod] = useState(defaultPeriod)
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  const loadAdherenceData = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)
      const summary = await adherenceService.getAdherenceSummary(period)
      setData(summary)
    } catch (err) {
      console.error('Erro ao carregar adesão:', err)
      setError('Não foi possível carregar os dados de adesão')
    } finally {
      setLoading(false)
    }
  }, [period])

  useEffect(() => {
    loadAdherenceData()
  }, [loadAdherenceData])

  const getScoreLabel = (score) => {
    if (score >= 90) return 'Excelente'
    if (score >= 80) return 'Muito Bom'
    if (score >= 60) return 'Bom'
    if (score >= 40) return 'Regular'
    return 'Precisa de Atenção'
  }

  const getScoreStatus = (score) => {
    if (score >= 80) return 'good'
    if (score >= 60) return 'warning'
    return 'poor'
  }

  if (loading) {
    return (
      <div className="adherence-widget loading">
        <Loading text="Calculando adesão..." size="sm" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="adherence-widget error">
        <p className="error-text">{error}</p>
        <button onClick={loadAdherenceData} className="retry-btn">
          Tentar novamente
        </button>
      </div>
    )
  }

  return (
    <div className="adherence-widget">
      {/* Header com período selector */}
      <div className="adherence-header">
        <h3 className="adherence-title">Score de Adesão</h3>
        <div className="period-selector">
          {['7d', '30d', '90d'].map((p) => (
            <button
              key={p}
              className={`period-btn ${period === p ? 'active' : ''}`}
              onClick={() => setPeriod(p)}
            >
              {p.replace('d', ' dias')}
            </button>
          ))}
        </div>
      </div>

      {/* Score principal e streak */}
      <div className="adherence-main">
        <div className="score-section">
          <AdherenceProgress score={data?.overallScore || 0} size={140} strokeWidth={12} />
          <div className="score-info">
            <span className={`score-label ${getScoreStatus(data?.overallScore || 0)}`}>
              {getScoreLabel(data?.overallScore || 0)}
            </span>
            <span className="score-detail">
              {data?.overallTaken || 0} de {data?.overallExpected || 0} doses
            </span>
          </div>
        </div>

        {/* Streak info */}
        {(data?.currentStreak > 0 || data?.longestStreak > 0) && (
          <div className="streak-section">
            {data?.currentStreak > 0 && (
              <div className="streak-item">
                <StreakBadge streak={data.currentStreak} size="lg" />
                <span className="streak-description">dias seguidos</span>
              </div>
            )}
            {data?.longestStreak > data?.currentStreak && (
              <div className="streak-item record">
                <span className="record-label">Recorde:</span>
                <span className="record-value">{data.longestStreak} dias</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Adesão por protocolo */}
      {data?.protocolScores?.length > 0 && (
        <div className="protocol-scores">
          <h4 className="protocols-title">Por Protocolo</h4>
          <div className="protocols-list">
            {data.protocolScores.map((protocol) => (
              <div key={protocol.protocolId} className="protocol-item">
                <div className="protocol-info">
                  <span className="protocol-name">{protocol.name}</span>
                  {protocol.medicineName && (
                    <span className="protocol-medicine">{protocol.medicineName}</span>
                  )}
                </div>
                <div className="protocol-score">
                  <div className="mini-progress">
                    <div
                      className="mini-progress-bar"
                      style={{
                        width: `${protocol.score}%`,
                        backgroundColor:
                          protocol.score >= 80
                            ? '#00ff88'
                            : protocol.score >= 60
                              ? '#ffd700'
                              : '#ff3366',
                      }}
                    />
                  </div>
                  <span className="protocol-score-value">{protocol.score}%</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Dicas baseadas no score */}
      <div className="adherence-tips">
        {(data?.overallScore || 0) < 60 && (
          <p className="tip-text">💡 Dica: Configure lembretes para não esquecer suas doses</p>
        )}
        {(data?.overallScore || 0) >= 90 && (
          <p className="tip-text success">🌟 Parabéns! Você está mantendo uma adesão excelente!</p>
        )}
      </div>
    </div>
  )
}

import { validateAnalyzeAdherencePatternsInput } from '@schemas/adherencePatternSchema'
import { getSaoPauloTime, parseISO, formatLocalDate } from '@utils/dateUtils'

/**
 * Nomes dos dias da semana
 */
const DAY_NAMES = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']

/**
 * Nomes dos períodos do dia
 */
const PERIOD_NAMES = ['Madrugada', 'Manhã', 'Tarde', 'Noite']

/**
 * Períodos do dia em horas (0-6, 6-12, 12-18, 18-24)
 */
const PERIOD_HOURS = [
  { start: 0, end: 6 }, // 0: Madrugada
  { start: 6, end: 12 }, // 1: Manhã
  { start: 12, end: 18 }, // 2: Tarde
  { start: 18, end: 24 }, // 3: Noite
]

/**
 * Determina o índice do período baseado na hora
 * @param {number} hour - Hora (0-23)
 * @returns {number} Índice do período (0-3)
 */
function getPeriodIndex(hour) {
  if (hour < 6) return 0 // Madrugada
  if (hour < 12) return 1 // Manhã
  if (hour < 18) return 2 // Tarde
  return 3 // Noite
}

/**
 * Conta quantos dias únicos com dados existem nos logs
 * @param {Array} logs - Array de logs de doses
 * @returns {number} Quantidade de dias únicos com dados
 */
function countUniqueDaysWithLogs(logs) {
  const uniqueDays = new Set(
    logs.map((log) => {
      const date = parseISO(log.taken_at)
      return formatLocalDate(date) // Retorna YYYY-MM-DD no fuso SP
    })
  )
  return uniqueDays.size
}

/**
 * Pré-processa protocolos para mapear time_schedule por dia da semana
 * Retorna um mapa: { dayIndex: { periodIndex: count } }
 * @param {Array} protocols - Array de protocolos com time_schedule
 * @returns {Object} Mapa de doses esperadas por dia/período
 */
function preprocessProtocolsExpected(protocols) {
  const expectedMap = {}

  // Inicializar grid vazio
  for (let day = 0; day < 7; day++) {
    expectedMap[day] = { 0: 0, 1: 0, 2: 0, 3: 0 }
  }

  // Para cada protocolo, mapear doses esperadas por dia da semana
  protocols.forEach((protocol) => {
    if (!protocol.time_schedule || protocol.time_schedule.length === 0) {
      return
    }

    const daysOfWeek = getDaysOfWeekForProtocol(protocol.frequency)

    daysOfWeek.forEach((dayIndex) => {
      protocol.time_schedule.forEach((timeStr) => {
        const [hour] = timeStr.split(':').map(Number)
        const periodIndex = getPeriodIndex(hour)
        expectedMap[dayIndex][periodIndex] += 1
      })
    })
  })

  return expectedMap
}

/**
 * Retorna dias da semana esperados para um protocolo baseado em frequência
 * @param {string} frequency - Frequência do protocolo
 * @returns {Array<number>} Array de índices de dias (0-6)
 */
function getDaysOfWeekForProtocol(frequency) {
  switch (frequency) {
    case 'diário':
      return [0, 1, 2, 3, 4, 5, 6] // Todos os dias
    case 'dias_alternados':
      return [0, 2, 4, 6] // Padrão: dias pares
    case 'semanal':
      return [0] // Uma vez por semana (domingo)
    case 'quando_necessário':
    case 'personalizado':
      return [] // Não contar doses esperadas para esses casos
    default:
      return []
  }
}

/**
 * Analisa padrões de adesão por dia da semana e período do dia.
 *
 * @param {Object} params
 * @param {Array} params.logs - Logs de doses (mínimo 21 dias recomendado)
 * @param {Array} params.protocols - Protocolos ativos com time_schedule
 * @returns {{
 *   grid: Array<Array<{adherence: number, taken: number, expected: number}>>,
 *   worstCell: { dayIndex: number, periodIndex: number, adherence: number, dayName: string, periodName: string } | null,
 *   narrative: string,
 *   hasEnoughData: boolean
 * }}
 */
export function analyzeAdherencePatterns({ logs, protocols }) {
  // Validar entrada com Zod
  const validation = validateAnalyzeAdherencePatternsInput({ logs, protocols })
  if (!validation.success) {
    throw new Error(`Validação falhou: ${validation.errors.map((e) => e.message).join(', ')}`)
  }

  // Inicializar grid 7x4 com zeros
  const grid = Array.from({ length: 7 }, () =>
    Array.from({ length: 4 }, () => ({ taken: 0, expected: 0, adherence: 0 }))
  )

  // Pré-processar protocolos para obter doses esperadas (por dia da semana)
  const expectedMap = preprocessProtocolsExpected(protocols)

  // Contar doses tomadas por célula (CONTAR REGISTROS, NÃO COMPRIMIDOS)
  // Cada registro = 1 dose tomada (independente de quantity_taken)
  logs.forEach((log) => {
    const spDate = getSaoPauloTime(parseISO(log.taken_at))
    const hour = spDate.getHours()
    const dayIndex = spDate.getDay() // 0-6 (Domingo-Sábado)
    const periodIndex = getPeriodIndex(hour)

    grid[dayIndex][periodIndex].taken += 1
  })

  // Contar quantas vezes cada dia da semana ocorre nos logs
  const dayOccurrences = [0, 0, 0, 0, 0, 0, 0]
  const uniqueDates = new Set()
  logs.forEach((log) => {
    const spDate = getSaoPauloTime(parseISO(log.taken_at))
    const dateStr = spDate.toISOString().split('T')[0] // YYYY-MM-DD

    if (!uniqueDates.has(dateStr)) {
      uniqueDates.add(dateStr)
      const dayIndex = spDate.getDay()
      dayOccurrences[dayIndex] += 1
    }
  })

  // Preencher expected e calcular adherence (normalizado)
  for (let dayIndex = 0; dayIndex < 7; dayIndex++) {
    for (let periodIndex = 0; periodIndex < 4; periodIndex++) {
      const expectedPerDay = expectedMap[dayIndex][periodIndex]
      const occurrences = dayOccurrences[dayIndex]
      const totalExpected = expectedPerDay * occurrences
      const taken = grid[dayIndex][periodIndex].taken

      // Armazenar expected (por dia) no grid
      grid[dayIndex][periodIndex].expected = expectedPerDay

      if (totalExpected > 0) {
        // Calcular adherence normalizando: (taken / totalExpected) * 100
        grid[dayIndex][periodIndex].adherence = Math.min(
          100,
          Math.round((taken / totalExpected) * 100)
        )
      } else if (expectedPerDay === 0) {
        // Se não há doses esperadas neste período, marcar como N/D
        grid[dayIndex][periodIndex].adherence = null
      } else if (occurrences === 0) {
        // Se o dia não ocorre nos logs, não calcular adherence
        grid[dayIndex][periodIndex].adherence = null
      }
    }
  }

  // Contar dias únicos com dados
  const daysWithData = countUniqueDaysWithLogs(logs)
  const hasEnoughData = daysWithData >= 21

  // Encontrar pior célula (mínimo 3 doses esperadas)
  let worstCell = null
  if (hasEnoughData) {
    let worstAdherence = 100
    let worstDayIndex = null
    let worstPeriodIndex = null

    for (let dayIndex = 0; dayIndex < 7; dayIndex++) {
      for (let periodIndex = 0; periodIndex < 4; periodIndex++) {
        const cell = grid[dayIndex][periodIndex]
        if (cell.expected >= 3 && cell.adherence < worstAdherence) {
          worstAdherence = cell.adherence
          worstDayIndex = dayIndex
          worstPeriodIndex = periodIndex
        }
      }
    }

    if (worstDayIndex !== null && worstPeriodIndex !== null) {
      worstCell = {
        dayIndex: worstDayIndex,
        periodIndex: worstPeriodIndex,
        adherence: worstAdherence,
        dayName: DAY_NAMES[worstDayIndex],
        periodName: PERIOD_NAMES[worstPeriodIndex],
      }
    }
  }

  // Gerar narrativa
  let narrative = ''
  if (hasEnoughData && worstCell) {
    narrative = `Seu pior horário é ${worstCell.dayName} à ${worstCell.periodName.toLowerCase()}`
  } else if (!hasEnoughData) {
    narrative = `Dados insuficientes. Registre pelo menos 21 dias de doses para análise completa.`
  } else {
    narrative = 'Sua adesão está excelente em todos os períodos!'
  }

  return {
    grid,
    dayOccurrences,
    worstCell: hasEnoughData ? worstCell : null,
    narrative,
    hasEnoughData,
  }
}

export default analyzeAdherencePatterns

/**
 * DoseCalendar - Calendário visual de doses com indicadores de status
 *
 * Componente que exibe um calendário mensal com indicadores coloridos
 * mostrando o status de adesão para cada dia.
 *
 * @module DoseCalendar
 */
import { useState, useMemo, useCallback, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import Calendar from '@shared/components/ui/Calendar'
import {
  calculateMonthlyDoseMap,
  calculateMonthlyStats,
} from '@calendar/services/doseCalendarService'
import { formatLocalDate, parseLocalDate, getNow, parseISO, getSaoPauloTime } from '@utils/dateUtils'
import './DoseCalendar.css'

/**
 * Cores para cada status de dose.
 * @constant {Object.<string, string>}
 */
const STATUS_COLORS = {
  completo: '#10b981', // Verde
  parcial: '#f59e0b', // Âmbar
  perdido: '#ef4444', // Vermelho
  sem_doses: '#6b7280', // Cinza
  futuro: '#6b7280', // Cinza (mesma cor para dias futuros)
}

/**
 * Rótulos em português para cada status.
 * @constant {Object.<string, string>}
 */
const STATUS_LABELS = {
  completo: 'Completo',
  parcial: 'Parcial',
  perdido: 'Perdido',
  sem_doses: 'Sem doses',
  futuro: 'Futuro',
}

/**
 * DoseCalendar - Componente de calendário visual de doses
 *
 * @returns {JSX.Element} Calendário com indicadores de status de doses
 */
function DoseCalendar() {
  // 1. States first (R-010)
  const [selectedDate, setSelectedDate] = useState(null)
  const [isPanelOpen, setIsPanelOpen] = useState(false)
  const [viewDate, setViewDate] = useState(getNow())

  // 2. Context/Hooks
  const { logs, protocols } = useDashboard()

  // 3. Memos
  /**
   * Calcula o mapa de doses para o mês atual em exibição.
   */
  const doseMap = useMemo(() => {
    const year = viewDate.getFullYear()
    const month = viewDate.getMonth() + 1 // JavaScript months are 0-indexed

    return calculateMonthlyDoseMap(logs, protocols, year, month)
  }, [logs, protocols, viewDate])

  /**
   * Calcula estatísticas do mês atual.
   */
  const monthlyStats = useMemo(() => {
    return calculateMonthlyStats(doseMap)
  }, [doseMap])

  /**
   * Gera lista de datas marcadas com suas cores para o Calendar.
   * Formato esperado pelo Calendar: array de strings de data
   */
  const markedDates = useMemo(() => {
    return Object.keys(doseMap).filter((dateStr) => {
      const dayInfo = doseMap[dateStr]
      return dayInfo.expected > 0
    })
  }, [doseMap])

  /**
   * Detalhes do dia selecionado para exibir no painel.
   */
  const selectedDayDetails = useMemo(() => {
    if (!selectedDate) return null

    const dateStr = formatLocalDate(selectedDate)
    const dayInfo = doseMap[dateStr]

    if (!dayInfo) return null

    // Verificar se é um dia futuro
    const todayStr = formatLocalDate(getNow())
    const isSelectedFuture = dateStr > todayStr

    // Agrupar doses por protocolo
    const protocolDetails = protocols
      .filter((protocol) => {
        // Verificar se o protocolo estava ativo na data selecionada
        const protocolStart = protocol.start_date ? parseLocalDate(protocol.start_date) : null
        const protocolEnd = protocol.end_date ? parseLocalDate(protocol.end_date) : null

        if (protocolStart && selectedDate < protocolStart) return false
        if (protocolEnd && selectedDate > protocolEnd) return false

        return protocol.active
      })
      .map((protocol) => {
        // Contar doses esperadas e tomadas para este protocolo nesta data
        const logsForProtocol = logs.filter((log) => {
          if (log.protocol_id !== protocol.id) return false
          // R-020: parseISO + normalization para evitar day-drift em logs
          const logDate = getSaoPauloTime(parseISO(log.taken_at))
          return formatLocalDate(logDate) === dateStr
        })

        const expectedDoses = protocol.time_schedule?.length || 0
        const takenDoses = logsForProtocol.length

        let status = 'sem_doses'
        if (expectedDoses > 0) {
          if (takenDoses === expectedDoses) status = 'completo'
          else if (takenDoses > 0) status = 'parcial'
          else status = isSelectedFuture ? 'futuro' : 'perdido'
        }

        return {
          id: protocol.id,
          name: protocol.medicines?.name || protocol.medicine_name || 'Medicamento',
          expected: expectedDoses,
          taken: takenDoses,
          status,
          color: STATUS_COLORS[status],
        }
      })

    return {
      date: selectedDate,
      dateStr,
      ...dayInfo,
      status: isSelectedFuture ? 'futuro' : dayInfo.status,
      color: STATUS_COLORS[isSelectedFuture ? 'futuro' : dayInfo.status],
      protocols: protocolDetails,
    }
  }, [selectedDate, doseMap, logs, protocols])

  // 4. Effects
  /**
   * Fecha o painel ao pressionar Escape.
   */
  useEffect(() => {
    const handleEscape = (e) => {
      if (e.key === 'Escape' && isPanelOpen) {
        setIsPanelOpen(false)
      }
    }

    document.addEventListener('keydown', handleEscape)
    return () => document.removeEventListener('keydown', handleEscape)
  }, [isPanelOpen])

  // 5. Handlers last (R-010)
  /**
   * Manipula clique em um dia do calendário.
   *
   * @param {Date} date - Data clicada
   */
  const handleDayClick = useCallback((date) => {
    setSelectedDate(date)
    setIsPanelOpen(true)
  }, [])

  /**
   * Fecha o painel de detalhes.
   */
  const handleClosePanel = useCallback(() => {
    setIsPanelOpen(false)
  }, [])

  /**
   * Callback para carregar dados do mês (lazy loading).
   * Como usamos useDashboard, os dados já estão disponíveis.
   *
   * @param {number} year - Ano
   * @param {number} month - Mês (0-indexed)
   * @returns {Promise<void>}
   */
  const handleLoadMonth = useCallback(async (year, month) => {
    // Atualiza viewDate para disparar recálculo do doseMap
    // Usando parseLocalDate para garantir interpretação local (SP) da data de visualização
    setViewDate(parseLocalDate(`${year}-${String(month + 1).padStart(2, '0')}-01`))
    return Promise.resolve()
  }, [])

  /**
   * Formata data para exibição no painel.
   *
   * @param {Date} date - Data a formatar
   * @returns {string} Data formatada
   */
  const formatDateDisplay = (date) => {
    const options = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }
    return date.toLocaleDateString('pt-BR', options)
  }

  return (
    <div className="dose-calendar">
      <div className="dose-calendar__header">
        <h2 className="dose-calendar__title">Calendário de Doses</h2>
        {monthlyStats && (
          <div className="dose-calendar__stats">
            <span className="dose-calendar__stat">
              <span className="dose-calendar__stat-value">{monthlyStats.adherenceRate}%</span>
              <span className="dose-calendar__stat-label">Adesão</span>
            </span>
            <span className="dose-calendar__stat">
              <span className="dose-calendar__stat-value">{monthlyStats.completeDays}</span>
              <span className="dose-calendar__stat-label">Dias Completos</span>
            </span>
          </div>
        )}
      </div>

      <div className="dose-calendar__legend">
        {Object.entries(STATUS_LABELS).map(([status, label]) => (
          <div key={status} className="dose-calendar__legend-item">
            <span
              className="dose-calendar__legend-dot"
              style={{ backgroundColor: STATUS_COLORS[status] }}
            />
            <span className="dose-calendar__legend-label">{label}</span>
          </div>
        ))}
      </div>

      <Calendar
        markedDates={markedDates}
        selectedDate={selectedDate}
        onDayClick={handleDayClick}
        enableLazyLoad={false}
        onLoadMonth={handleLoadMonth}
        enableSwipe={true}
        enableMonthPicker={true}
      />

      {/* Painel de detalhes com animação */}
      <AnimatePresence>
        {isPanelOpen && selectedDayDetails && (
          <>
            {/* Overlay */}
            <motion.div
              className="dose-calendar__overlay"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={handleClosePanel}
            />

            {/* Painel */}
            <motion.div
              className="dose-calendar__panel"
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            >
              <div className="dose-calendar__panel-header">
                <h3 className="dose-calendar__panel-title">
                  {formatDateDisplay(selectedDayDetails.date)}
                </h3>
                <button
                  className="dose-calendar__panel-close"
                  onClick={handleClosePanel}
                  aria-label="Fechar painel"
                >
                  ×
                </button>
              </div>

              <div className="dose-calendar__panel-summary">
                <div
                  className="dose-calendar__panel-status"
                  style={{ backgroundColor: selectedDayDetails.color }}
                >
                  <span className="dose-calendar__panel-status-label">
                    {STATUS_LABELS[selectedDayDetails.status]}
                  </span>
                  <span className="dose-calendar__panel-status-count">
                    {selectedDayDetails.taken}/{selectedDayDetails.expected} doses
                  </span>
                </div>
              </div>

              <div className="dose-calendar__panel-protocols">
                <h4 className="dose-calendar__panel-subtitle">Por Protocolo</h4>
                {selectedDayDetails.protocols.length === 0 ? (
                  <p className="dose-calendar__panel-empty">Nenhum protocolo ativo nesta data</p>
                ) : (
                  <ul className="dose-calendar__protocol-list">
                    {selectedDayDetails.protocols.map((protocol) => (
                      <li
                        key={protocol.id}
                        className="dose-calendar__protocol-item"
                        style={{ borderLeftColor: protocol.color }}
                      >
                        <span className="dose-calendar__protocol-name">{protocol.name}</span>
                        <span className="dose-calendar__protocol-status">
                          {protocol.taken}/{protocol.expected} - {STATUS_LABELS[protocol.status]}
                        </span>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  )
}

export default DoseCalendar

/**
 * Dose Calendar Service - Cálculo de mapa mensal de doses
 *
 * Serviço para calcular o status de doses diárias para exibição em calendário visual.
 * Todas as funções são puras e não fazem chamadas de API.
 *
 * @module doseCalendarService
 */

import { parseLocalDate, formatLocalDate, isProtocolActiveOnDate, getSaoPauloTime, parseISO, getLastDayOfMonth } from '@utils/dateUtils'
import { isDoseInToleranceWindow } from '@utils/adherenceLogic'

/**
 * Status possíveis para um dia no calendário de doses.
 * @typedef {'completo' | 'parcial' | 'perdido' | 'sem_doses'} DayStatus
 */

/**
 * Mapa diário de doses com contagem e status.
 * @typedef {Object} DailyDoseInfo
 * @property {number} expected - Total de doses esperadas no dia
 * @property {number} taken - Total de doses tomadas no dia
 * @property {DayStatus} status - Status do dia
 */

/**
 * Mapa mensal de doses indexado por data (YYYY-MM-DD).
 * @typedef {Object.<string, DailyDoseInfo>} MonthlyDoseMap
 */

/**
 * Calcula o número de dias em um mês.
 *
 * @param {number} year - Ano (ex: 2026)
 * @param {number} month - Mês (1-12, onde 1 é Janeiro)
 * @returns {number} Número de dias no mês
 */
function getDaysInMonth(year, month) {
  // month é 1-indexado, então passamos month-1 para a utility (0-11)
  return getLastDayOfMonth(year, month - 1)
}

/**
 * Verifica se um protocolo deve gerar doses esperadas em uma data específica.
 * Considera frequência, dias alternados, semanal, etc.
 *
 * @param {Object} protocol - Protocolo a verificar
 * @param {string} dateStr - Data no formato YYYY-MM-DD
 * @returns {boolean} True se o protocolo deve gerar doses na data
 */
function shouldExpectDosesOnDate(protocol, dateStr) {
  // Protocolos inativos não geram doses esperadas
  if (!protocol.active) return false

  // Verificar se está dentro do período de vigência
  if (!isProtocolActiveOnDate(protocol, dateStr)) return false

  const frequency = (protocol.frequency || 'diário').toLowerCase()

  // "Quando necessário" não gera doses esperadas
  if (frequency === 'quando_necessário' || frequency === 'when_needed' || frequency === 'prn') {
    return false
  }

  const targetDate = parseLocalDate(dateStr)
  const dayOfWeek = targetDate.getDay() // 0=Domingo, 1=Segunda, etc.

  switch (frequency) {
    case 'diário':
    case 'diariamente':
    case 'daily':
      return true

    case 'semanal':
    case 'semanalmente':
    case 'weekly':
      // Verificar se o dia da semana está nos dias configurados
      if (protocol.days && Array.isArray(protocol.days)) {
        const dayMap = {
          domingo: 0,
          sunday: 0,
          segunda: 1,
          'segunda-feira': 1,
          monday: 1,
          terça: 2,
          'terça-feira': 2,
          tuesday: 2,
          quarta: 3,
          'quarta-feira': 3,
          wednesday: 3,
          quinta: 4,
          'quinta-feira': 4,
          thursday: 4,
          sexta: 5,
          'sexta-feira': 5,
          friday: 5,
          sábado: 6,
          sabado: 6,
          saturday: 6,
        }
        return protocol.days.some((day) => dayMap[day.toLowerCase()] === dayOfWeek)
      }
      return false

    case 'dias_alternados':
    case 'dia_sim_dia_nao':
    case 'dia sim, dia não':
    case 'every_other_day':
    case 'alternating':
      // Calcular dias desde a data de início
      if (protocol.start_date) {
        const startDate = parseLocalDate(protocol.start_date)
        const diffTime = targetDate.getTime() - startDate.getTime()
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24))
        // Dia sim, dia não: dias pares = dose, ímpares = sem dose
        return diffDays % 2 === 0
      }
      // Se não tiver data de início, assumir que começa hoje (dia 0 = dose)
      return true

    case 'personalizado':
    case 'custom':
      // Frequência personalizada requer lógica específica não definida
      return false

    default:
      // Frequências desconhecidas não geram doses esperadas (segurança)
      return false
  }
}

/**
 * Conta quantas doses esperadas um protocolo tem em uma data.
 *
 * @param {Object} protocol - Protocolo a verificar
 * @param {string} dateStr - Data no formato YYYY-MM-DD
 * @returns {number} Número de doses esperadas
 */
function countExpectedDosesForDate(protocol, dateStr) {
  if (!shouldExpectDosesOnDate(protocol, dateStr)) return 0

  // Número de horários no time_schedule
  const schedule = protocol.time_schedule || []
  return schedule.length
}

/**
 * Conta quantas doses foram tomadas em uma data para um protocolo específico.
 * Considera a janela de tolerância de 2 horas.
 *
 * @param {Array} logs - Lista de logs de medicamentos
 * @param {string} protocolId - ID do protocolo
 * @param {string} dateStr - Data no formato YYYY-MM-DD
 * @param {Array} timeSchedule - Array de horários esperados (strings HH:mm)
 * @returns {number} Número de doses tomadas dentro da tolerância
 */
function countTakenDosesForDate(logs, protocolId, dateStr, timeSchedule) {
  if (!logs || logs.length === 0) return 0

  // Filtrar logs do protocolo e da data
  const relevantLogs = logs.filter((log) => {
    if (log.protocol_id !== protocolId) return false

    // Extrair data local do log (Normalizado para SP - R-020)
    const logDate = getSaoPauloTime(parseISO(log.taken_at))
    const logDateStr = formatLocalDate(logDate)

    return logDateStr === dateStr
  })

  if (relevantLogs.length === 0) return 0
  if (!timeSchedule || timeSchedule.length === 0) return relevantLogs.length

  // Para cada horário esperado, verificar se há um log dentro da tolerância
  let takenCount = 0
  const unmatchedLogs = [...relevantLogs]

  timeSchedule.forEach((scheduledTime) => {
    const matchedIndex = unmatchedLogs.findIndex((log) =>
      isDoseInToleranceWindow(scheduledTime, log.taken_at)
    )

    if (matchedIndex >= 0) {
      takenCount++
      unmatchedLogs.splice(matchedIndex, 1)
    }
  })

  // Logs extras (fora dos horários esperados) também contam como tomados
  takenCount += unmatchedLogs.length

  return takenCount
}

/**
 * Determina o status do dia baseado nas doses esperadas e tomadas.
 *
 * @param {number} expected - Total de doses esperadas
 * @param {number} taken - Total de doses tomadas
 * @returns {DayStatus} Status do dia
 */
function determineDayStatus(expected, taken) {
  if (expected === 0) return 'sem_doses'
  if (taken === 0) return 'perdido'
  if (taken >= expected) return 'completo'
  // Se chegou aqui, é porque 0 < taken < expected
  return 'parcial'
}

/**
 * Calcula o mapa mensal de doses para exibição em calendário visual.
 *
 * Esta função pura processa logs e protocolos para gerar um mapa
 * indexado por data com contagem de doses esperadas, tomadas e status.
 *
 * @param {Array} logs - Lista de logs de medicamentos (do logService)
 * @param {Array} protocols - Lista de protocolos ativos (do protocolService)
 * @param {number} year - Ano do período (ex: 2026)
 * @param {number} month - Mês do período (1-12, onde 1 é Janeiro)
 * @returns {MonthlyDoseMap} Mapa de doses por data
 *
 * @example
 * const logs = await logService.getByMonth(2026, 1)
 * const protocols = await protocolService.getActive()
 * const doseMap = calculateMonthlyDoseMap(logs.data, protocols, 2026, 2)
 * // Retorna: { '2026-02-01': { expected: 2, taken: 2, status: 'completo' }, ... }
 */
export function calculateMonthlyDoseMap(logs, protocols, year, month) {
  const doseMap = {}
  const daysInMonth = getDaysInMonth(year, month)

  // Inicializar mapa com todos os dias do mês
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`
    doseMap[dateStr] = {
      expected: 0,
      taken: 0,
      status: 'sem_doses',
    }
  }

  // Se não há protocolos, retornar mapa vazio
  if (!protocols || protocols.length === 0) {
    return doseMap
  }

  // Processar cada dia do mês
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`

    let dayExpected = 0
    let dayTaken = 0

    // Processar cada protocolo
    protocols.forEach((protocol) => {
      const expectedForProtocol = countExpectedDosesForDate(protocol, dateStr)
      dayExpected += expectedForProtocol

      if (expectedForProtocol > 0) {
        const takenForProtocol = countTakenDosesForDate(
          logs || [],
          protocol.id,
          dateStr,
          protocol.time_schedule
        )
        dayTaken += takenForProtocol
      }
    })

    // Determinar status do dia
    const status = determineDayStatus(dayExpected, dayTaken)

    doseMap[dateStr] = {
      expected: dayExpected,
      taken: dayTaken,
      status,
    }
  }

  return doseMap
}

/**
 * Calcula estatísticas resumidas do mês.
 *
 * @param {MonthlyDoseMap} doseMap - Mapa de doses calculado
 * @returns {Object} Estatísticas do mês
 * @returns {number} returns.totalExpected - Total de doses esperadas no mês
 * @returns {number} returns.totalTaken - Total de doses tomadas no mês
 * @returns {number} returns.completeDays - Dias com status 'completo'
 * @returns {number} returns.partialDays - Dias com status 'parcial'
 * @returns {number} returns.missedDays - Dias com status 'perdido'
 * @returns {number} returns.adherenceRate - Taxa de adesão (0-100)
 */
export function calculateMonthlyStats(doseMap) {
  let totalExpected = 0
  let totalTaken = 0
  let completeDays = 0
  let partialDays = 0
  let missedDays = 0

  Object.values(doseMap).forEach((dayInfo) => {
    totalExpected += dayInfo.expected
    totalTaken += dayInfo.taken

    switch (dayInfo.status) {
      case 'completo':
        completeDays++
        break
      case 'parcial':
        partialDays++
        break
      case 'perdido':
        missedDays++
        break
    }
  })

  const adherenceRate = totalExpected > 0 ? Math.round((totalTaken / totalExpected) * 100) : 0

  return {
    totalExpected,
    totalTaken,
    completeDays,
    partialDays,
    missedDays,
    adherenceRate,
  }
}

import { useState, useCallback, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Trash2, X } from 'lucide-react'
import {
  sendChatMessage,
  loadPersistedHistory,
  savePersistedHistory,
  clearPersistedHistory,
} from '@/features/chatbot/services/chatbotService'
import { createWelcomeMessage } from '@/features/chatbot/config/chatbotConfig'
import {
  getNow,
  getTodayLocal,
  getYesterdayLocal,
  formatLocalDate,
  parseTimestamp,
} from '@utils/dateUtils.js'
import ConfirmDialog from '@shared/components/ui/ConfirmDialog'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import styles from './ChatWindow.module.css'

// Funções auxiliares puras (fora do componente para melhor performance e organização)

/**
 * Renderiza conteúdo com suporte básico a markdown inline:
 * _texto_ → <em>texto</em> (itálico para disclaimers e ênfase)
 * Quebras de linha \n → <br>
 */
function renderMessageContent(content) {
  return content.split('\n').map((line, lineIdx) => {
    const parts = line.split(/(_[^_]+_)/g)
    return (
      <span key={lineIdx}>
        {lineIdx > 0 && <br />}
        {parts.map((part, i) => {
          if (part.startsWith('_') && part.endsWith('_') && part.length > 2) {
            return <em key={i}>{part.slice(1, -1)}</em>
          }
          return <span key={i}>{part}</span>
        })}
      </span>
    )
  })
}

/**
 * Formata timestamp para exibição relativa (e.g., "às 14:30", "Ontem às 09:15").
 */
const formatMessageTime = (timestamp) => {
  const date = parseTimestamp(timestamp)
  const dateStr = formatLocalDate(date)
  const today = getTodayLocal()
  const yesterday = getYesterdayLocal()

  const isToday = dateStr === today
  const isYesterday = dateStr === yesterday

  const timeStr = date.toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo',
  })

  if (isToday) return `às ${timeStr}`
  if (isYesterday) return `Ontem às ${timeStr}`
  return `${date.toLocaleDateString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    timeZone: 'America/Sao_Paulo',
  })} às ${timeStr}`
}

/**
 * Verifica se deve exibir separador de data antes da mensagem atual.
 */
const shouldShowDateSeparator = (msgs, idx) => {
  if (idx === 0) return false
  const prev = formatLocalDate(parseTimestamp(msgs[idx - 1].timestamp))
  const curr = formatLocalDate(parseTimestamp(msgs[idx].timestamp))
  return prev !== curr
}

/**
 * Formata label do separador de data (e.g., "Hoje", "Ontem", "15/03").
 */
const formatDaySeparator = (timestamp) => {
  const date = parseTimestamp(timestamp)
  const dateStr = formatLocalDate(date)
  const today = getTodayLocal()
  const yesterday = getYesterdayLocal()

  if (dateStr === today) return 'Hoje'
  if (dateStr === yesterday) return 'Ontem'

  return date.toLocaleDateString('pt-BR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    timeZone: 'America/Sao_Paulo',
  })
}

/**
 * Drawer lateral de chat com o assistente IA.
 * Lazy-loaded — nao impacta main bundle.
 * Acessa dados do DashboardContext diretamente para montar contexto do paciente.
 *
 * @param {Object} props
 * @param {boolean} props.isOpen
 * @param {Function} props.onClose
 */
export default function ChatWindow({ isOpen, onClose }) {
  const { medicines, protocols, logs, stockSummary, stats } = useDashboard()

  const [messages, setMessages] = useState(() => {
    const persisted = loadPersistedHistory()
    if (persisted.length > 0) return persisted
    return [createWelcomeMessage(getNow().getTime())]
  })
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [showClearConfirm, setShowClearConfirm] = useState(false)
  const messagesEndRef = useRef(null)

  // Auto-scroll para ultima mensagem
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Adiciona mensagem ao estado e persiste histórico
  const addMessage = useCallback((message) => {
    setMessages((prev) => {
      const next = [...prev, message]
      savePersistedHistory(next)
      return next
    })
  }, [])

  const handleSend = useCallback(async () => {
    if (!input.trim() || isLoading) return

    const userMessage = input.trim()
    setInput('')
    addMessage({ role: 'user', content: userMessage, timestamp: getNow().getTime() })
    setIsLoading(true)

    try {
      const result = await sendChatMessage({
        message: userMessage,
        history: messages,
        patientData: { medicines, protocols, logs, stockSummary, stats },
      })

      addMessage({
        role: 'assistant',
        content: result.response || result.reason || '',
        timestamp: getNow().getTime(),
      })
    } finally {
      setIsLoading(false)
    }
  }, [input, isLoading, messages, addMessage, medicines, protocols, logs, stockSummary, stats])

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  const quickSuggestions = [
    'Tomei meu remédio hoje?',
    'Como está minha adesão?',
    'Quando preciso repor estoque?',
  ]

  const handleClearHistory = () => {
    setShowClearConfirm(true)
  }

  const handleConfirmClear = () => {
    clearPersistedHistory()
    setMessages([createWelcomeMessage(getNow().getTime())])
    setShowClearConfirm(false)
  }

  const handleCancelClear = () => {
    setShowClearConfirm(false)
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className={styles.overlay}
            onClick={onClose}
          />

          {/* Drawer */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className={styles.drawer}
          >
            {/* Header */}
            <div className={styles.header}>
              <span className={styles.headerTitle}>Assistente IA</span>
              <div className={styles.headerActions}>
                <button
                  onClick={handleClearHistory}
                  className={styles.clearButton}
                  title="Limpar histórico"
                  aria-label="Limpar histórico de conversa"
                >
                  <Trash2 size={16} aria-hidden="true" />
                </button>
                <button onClick={onClose} className={styles.closeButton} aria-label="Fechar chat">
                  <X size={18} aria-hidden="true" />
                </button>
              </div>
            </div>

            {/* Messages */}
            <div className={styles.messages}>
              {messages.map((msg, i) => (
                <div key={i}>
                  {shouldShowDateSeparator(messages, i) && (
                    <div className={styles.dateSeparator}>{formatDaySeparator(msg.timestamp)}</div>
                  )}
                  <div
                    className={`${styles.messageBubble} ${
                      msg.role === 'user' ? styles.messageBubbleUser : styles.messageBubbleAssistant
                    }`}
                  >
                    {renderMessageContent(msg.content)}
                    {msg.timestamp && (
                      <span className={styles.messageTime}>{formatMessageTime(msg.timestamp)}</span>
                    )}
                  </div>
                </div>
              ))}

              {isLoading && <div className={styles.thinkingBubble}>Pensando...</div>}

              <div ref={messagesEndRef} />
            </div>

            {/* Quick suggestions (quando poucas mensagens) */}
            {messages.length <= 2 && (
              <div className={styles.suggestions}>
                {quickSuggestions.map((suggestion, i) => (
                  <button
                    key={i}
                    onClick={() => setInput(suggestion)}
                    className={styles.suggestionButton}
                  >
                    {suggestion}
                  </button>
                ))}
              </div>
            )}

            {/* Input */}
            <div className={styles.inputRow}>
              <input
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Digite sua pergunta..."
                disabled={isLoading}
                className={styles.textInput}
              />
              <button
                onClick={handleSend}
                disabled={isLoading || !input.trim()}
                className={styles.sendButton}
              >
                Enviar
              </button>
            </div>
          </motion.div>
        </>
      )}

      {/* Modal de confirmação — limpar histórico */}
      <ConfirmDialog
        isOpen={showClearConfirm}
        title="Limpar histórico"
        message="Tem certeza que deseja limpar todo o histórico de conversa? Esta ação não pode ser desfeita."
        confirmLabel="Limpar"
        cancelLabel="Cancelar"
        onConfirm={handleConfirmClear}
        onCancel={handleCancelClear}
        variant="danger"
      />
    </AnimatePresence>
  )
}

