/**
 * Cria insight sobre melhor horário para lembretes (baseado em analytics)
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createBestTimeInsight(onNavigate) {
  const mostActive = getMostActiveHour()

  if (!mostActive || mostActive.count < 3) return null

  const timeLabel = formatHour(mostActive.hour)

  return {
    id: 'best_time',
    type: INSIGHT_TYPES.IMPROVEMENT_OPPORTUNITY,
    priority: 'info',
    icon: '🕐',
    text: `Você costuma registrar doses às ${timeLabel}. Considere agendar mais lembretes neste horário!`,
    highlight: timeLabel,
    actionLabel: 'Configurar Lembretes',
    onAction: () => {
      analyticsService.track('insight_action', { insight_id: 'best_time' })
      onNavigate?.('profile')
    },
  }
}

/**
 * Cria insight sobre feature não utilizada
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createFeatureDiscoveryInsight(onNavigate) {
  const usage = getFeatureUsage()

  // Se usuário nunca usou sparkline mas usa swipe regularmente
  if (usage.leastUsed === 'sparkline_tapped' && usage.mostUsed === 'swipe_used') {
    return {
      id: 'feature_discovery_sparkline',
      type: INSIGHT_TYPES.IMPROVEMENT_OPPORTUNITY,
      priority: 'info',
      icon: '📊',
      text: 'Você sabia que pode tocar no gráfico de adesão para ver detalhes diários?',
      highlight: 'tocar no gráfico',
      actionLabel: 'Experimentar',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'feature_discovery_sparkline' })
        onNavigate?.('stats')
      },
    }
  }

  return null
}

/**
 * Cria insight sobre dia da semana com menor adesão
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createWeakDayInsight(onNavigate) {
  const dayAnalysis = getAdherenceByDayOfWeek()

  if (!dayAnalysis || !dayAnalysis.worstDay || dayAnalysis.bestCount === 0) return null

  // Se o pior dia tem significativamente menos doses (menos de 50% do melhor)
  if (dayAnalysis.worstCount > 0 && dayAnalysis.worstCount < dayAnalysis.bestCount * 0.5) {
    return {
      id: 'weak_day',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '📅',
      text: `Sua adesão é menor aos ${dayAnalysis.worstDay}. Configure lembretes extras para este dia!`,
      highlight: dayAnalysis.worstDay,
      actionLabel: 'Configurar Lembretes',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'weak_day' })
        onNavigate?.('profile')
      },
    }
  }

  return null
}

/**
 * Gera todos os insights possíveis baseados nos dados do usuário
 * @param {Object} params - Parâmetros de dados do usuário
 * @returns {Array} - Lista de insights aplicáveis
 */
export function generateAllInsights({ stats, dailyAdherence, stockSummary, logs, onNavigate }) {
  const insights = []

  // Insight: Celebração de Streak (threshold reduzido para ser mais inclusivo)
  if (stats.currentStreak >= 5) {
    insights.push({
      id: 'streak_achievement',
      type: INSIGHT_TYPES.STREAK_CELEBRATION,
      priority: 'low',
      icon: '🔥',
      text: `Você está em uma sequência de ${stats.currentStreak} dias! Continue assim!`,
      highlight: `${stats.currentStreak} dias`,
      actionLabel: 'Ver Histórico',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'streak_achievement' })
        onNavigate?.('history')
      },
    })
  }

  // Insight: Semana Perfeita
  if (stats.adherence === 100) {
    insights.push({
      id: 'perfect_week',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '⭐',
      text: 'Semana perfeita! 100% de adesão nos últimos 7 dias.',
      highlight: '100% de adesão',
      actionLabel: 'Compartilhar',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'perfect_week' })
        shareAchievement()
      },
    })
  }

  // Insight: Boa Semana (adesão >= 80%)
  if (stats.adherence >= 80 && stats.adherence < 100) {
    insights.push({
      id: 'good_week',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '👍',
      text: `Sua adesão esta semana está em ${Math.round(stats.adherence)}%. Muito bem! Continue assim!`,
      highlight: `${Math.round(stats.adherence)}%`,
      actionLabel: 'Ver Histórico',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'good_week' })
        onNavigate?.('history')
      },
    })
  }

  // Insight: Melhoria de Adesão
  const trend = calculateTrendFromData(dailyAdherence)
  if (trend.direction === 'up' && trend.percentage >= 10) {
    insights.push({
      id: 'improvement',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '📈',
      text: `Sua adesão melhorou ${trend.percentage}% em relação à semana anterior!`,
      highlight: `${trend.percentage}% melhor`,
      actionLabel: 'Ver Detalhes',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'improvement' })
        onNavigate?.('stats')
      },
    })
  }

  // Insight: Estoque Saudável
  const lowStockCount = stockSummary?.filter((s) => s.isLow || s.isZero).length || 0
  if (lowStockCount === 0 && stockSummary?.length > 0) {
    insights.push({
      id: 'stock_healthy',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'info',
      icon: '✅',
      text: 'Todos os medicamentos com estoque saudável. Ótimo planejamento!',
      highlight: 'estoque saudável',
      actionLabel: 'Ver Estoque',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'stock_healthy' })
        onNavigate?.('stock')
      },
    })
  }

  // Insight: Doses Pendentes Hoje
  const todayMissed = countTodayMissedDoses(logs, dailyAdherence)
  if (todayMissed > 0 && todayMissed <= 2) {
    insights.push({
      id: 'missed_doses_today',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '⏰',
      text: `Você tem ${todayMissed} doses pendentes hoje. Que tal completar agora?`,
      highlight: `${todayMissed} doses pendentes`,
      actionLabel: 'Registrar Doses',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'missed_doses_today' })
        onNavigate?.('register')
      },
    })
  }

  // Insight: Adesão Baixa (threshold ajustado para motivar users entre 50-80%)
  if (stats.adherence < 80 && stats.adherence > 0) {
    insights.push({
      id: 'low_adherence_week',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '💪',
      text: `Sua adesão esta semana está em ${Math.round(stats.adherence)}%. Vamos melhorar juntos!`,
      highlight: `${Math.round(stats.adherence)}%`,
      actionLabel: 'Ver Protocolos',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'low_adherence_week' })
        onNavigate?.('protocols')
      },
    })
  }

  // Insight: Streak Quebrado
  if (stats.currentStreak === 0 && stats.longestStreak >= 3) {
    insights.push({
      id: 'streak_broken',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'high',
      icon: '🔄',
      text: `Seu streak foi interrompido. Seu recorde foi ${stats.longestStreak} dias. Recomece agora!`,
      highlight: `${stats.longestStreak} dias`,
      actionLabel: 'Registrar Dose',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'streak_broken' })
        onNavigate?.('register')
      },
    })
  }

  // Insight: Protocolos Ativos
  const activeProtocols = stats.activeProtocols || 0
  if (activeProtocols > 0 && activeProtocols <= 3) {
    insights.push({
      id: 'protocol_reminder',
      type: INSIGHT_TYPES.PROTOCOL_REMINDER,
      priority: 'info',
      icon: '📋',
      text: `Você tem ${activeProtocols} protocolo${activeProtocols > 1 ? 's' : ''} ativo${activeProtocols > 1 ? 's' : ''}. Todos em dia!`,
      highlight: `${activeProtocols} protocolo${activeProtocols > 1 ? 's' : ''}`,
      actionLabel: 'Ver Protocolos',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'protocol_reminder' })
        onNavigate?.('protocols')
      },
    })
  }

  // Insights Baseados em Analytics (Capítulo 10)
  const bestTimeInsight = createBestTimeInsight(onNavigate)
  if (bestTimeInsight) insights.push(bestTimeInsight)

  const featureDiscoveryInsight = createFeatureDiscoveryInsight(onNavigate)
  if (featureDiscoveryInsight) insights.push(featureDiscoveryInsight)

  const weakDayInsight = createWeakDayInsight(onNavigate)
  if (weakDayInsight) insights.push(weakDayInsight)

  return insights.filter((insight) => insight !== null)
}

/**
 * Calcula tendência a partir dos dados diários
 * @param {Array} dailyAdherence - Dados de adesão diária
 * @returns {Object} - Tendência calculada
 */
function calculateTrendFromData(dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length < 7) {
    return { direction: 'neutral', percentage: 0 }
  }

  const currentWeek = dailyAdherence.slice(-7)
  const previousWeek = dailyAdherence.slice(-14, -7)

  if (previousWeek.length === 0) {
    return { direction: 'neutral', percentage: 0 }
  }

  const currentAvg = currentWeek.reduce((sum, d) => sum + d.adherence, 0) / currentWeek.length
  const previousAvg = previousWeek.reduce((sum, d) => sum + d.adherence, 0) / previousWeek.length

  const percentageChange = previousAvg > 0 ? ((currentAvg - previousAvg) / previousAvg) * 100 : 0

  let direction = 'neutral'
  if (percentageChange > 5) direction = 'up'
  else if (percentageChange < -5) direction = 'down'

  return {
    direction,
    percentage: Math.abs(Math.round(percentageChange)),
  }
}

/**
 * Conta doses perdidas hoje
 * @param {Array} logs - Logs de doses
 * @param {Array} dailyAdherence - Dados de adesão diária
 * @returns {number} - Quantidade de doses perdidas
 */
function countTodayMissedDoses(logs, dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length === 0) return 0

  const today = dailyAdherence[dailyAdherence.length - 1]
  if (!today) return 0

  const taken = today.taken || 0
  const expected = today.expected || 0

  return Math.max(0, expected - taken)
}

//=============================================================================
// FUNÇÕES DE SELEÇÃO DE INSIGHTS
//=============================================================================

/**
 * Seleciona o melhor insight para exibir com rotação entre insights
 * @param {Object} params - Parâmetros de dados do usuário
 * @returns {Object} - Insight selecionado
 */
export function selectBestInsight(params) {
  const insights = generateAllInsights(params)

  // Filtrar insights aplicáveis (sem frequency capping)
  const applicableInsights = insights.filter(
    (insight) => insight.condition === undefined || insight.condition
  )

  if (applicableInsights.length === 0) {
    return getDefaultInsight(params.onNavigate)
  }

  // Rotacionar entre insights: tentar mostrar um diferente do último
  const history = getInsightHistory()
  const lastShownId = history[0]?.id

  // Filtrar para mostrar insight diferente do último
  const differentInsights = applicableInsights.filter((i) => i.id !== lastShownId)
  const candidates = differentInsights.length > 0 ? differentInsights : applicableInsights

  // Ordenar por prioridade
  const sortedInsights = candidates.sort(
    (a, b) => INSIGHT_PRIORITY[a.priority] - INSIGHT_PRIORITY[b.priority]
  )

  const selectedInsight = sortedInsights[0]

  // Rastrear insight mostrado
  try {
    analyticsService.track('insight_shown', {
      insight_id: selectedInsight.id,
      priority: selectedInsight.priority,
    })
  } catch (err) {
    console.error('[InsightService] Erro ao rastrear insight:', err)
  }

  // Salvar no histórico
  saveInsightToHistory(selectedInsight.id)

  return selectedInsight
}

/**
 * Retorna insight padrão quando não há insights aplicáveis
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object} - Insight padrão
 */
export function getDefaultInsight(onNavigate) {
  return {
    id: 'default',
    type: INSIGHT_TYPES.IMPROVEMENT_OPPORTUNITY,
    priority: 'info',
    icon: '💡',
    text: 'Continue registrando suas doses para manter o controle do seu tratamento.',
    highlight: '',
    actionLabel: 'Saiba mais',
    onAction: () => {
      analyticsService.track('insight_action', { insight_id: 'default' })
      onNavigate?.('help')
    },
  }
}

/**
 * Verifica se um insight pode ser mostrado (frequency capping)
 * @param {string} insightId - ID do insight
 * @returns {boolean} - Se pode ser mostrado
 */
export function shouldShowInsight(insightId) {
  const history = getInsightHistory()
  const lastShown = history.find((h) => h.id === insightId)

  if (!lastShown) return true

  const timeSinceLastShown = getNow() - lastShown.timestamp
  return timeSinceLastShown >= MIN_DISPLAY_INTERVAL
}

/**
 * Obtém histórico de insights mostrados
 * @returns {Array} - Histórico de insights
 */
export function getInsightHistory() {
  try {
    const data = localStorage.getItem(STORAGE_KEY)
    return data ? JSON.parse(data) : []
  } catch {
    return []
  }
}

/**
 * Salva insight no histórico
 * @param {string} insightId - ID do insight
 */
export function saveInsightToHistory(insightId) {
  try {
    const history = getInsightHistory()
    history.unshift({
      id: insightId,
      timestamp: getNow().getTime(),
    })

    const trimmedHistory = history.slice(0, MAX_HISTORY)
    localStorage.setItem(STORAGE_KEY, JSON.stringify(trimmedHistory))
    console.log('[InsightService] Insight salvo no histórico:', insightId)
  } catch {
    console.warn('[InsightService] Erro ao salvar histórico de insights')
  }
}

/**
 * Limpa histórico de insights
 */
export function clearInsightHistory() {
  try {
    localStorage.removeItem(STORAGE_KEY)
  } catch {
    // Silenciar erro
  }
}

/**
 * Compartilha conquista (placeholder para Web Share API)
 */
function shareAchievement() {
  console.log('[InsightService] Compartilhar conquista - funcionalidade não implementada')
}

export default {
  generateAllInsights,
  selectBestInsight,
  getDefaultInsight,
  shouldShowInsight,
  getInsightHistory,
  saveInsightToHistory,
  clearInsightHistory,
  INSIGHT_PRIORITY,
  INSIGHT_TYPES,
}

import { useState, useMemo, useCallback } from 'react'
import Button from '@shared/components/ui/Button'
import Card from '@shared/components/ui/Card'
import { BLOOD_TYPES, BLOOD_TYPE_LABELS, validateEmergencyCard } from '@schemas/emergencyCardSchema'
import { emergencyCardService } from '@features/emergency/services/emergencyCardService'
import './EmergencyCard.css'

/**
 * Formulário para edição do Cartão de Emergência.
 *
 * Permite cadastrar contatos de emergência, alergias, tipo sanguíneo e observações.
 * Validação com Zod no submit. Suporta até 5 contatos de emergência.
 *
 * @param {Object} props - Propriedades do componente
 * @param {Object} [props.initialData] - Dados iniciais do cartão
 * @param {Function} props.onSave - Callback executado após salvar com sucesso
 * @param {Function} props.onCancel - Callback executado ao cancelar
 * @returns {JSX.Element} Formulário de edição do cartão de emergência
 */
export default function EmergencyCardForm({ initialData, onSave, onCancel }) {
  // ===== STATES (R-010: Hook Order) =====
  const [contacts, setContacts] = useState(
    initialData?.emergency_contacts || [{ name: '', phone: '', relationship: '' }]
  )
  const [allergies, setAllergies] = useState(initialData?.allergies || [])
  const [allergyInput, setAllergyInput] = useState('')
  const [bloodType, setBloodType] = useState(initialData?.blood_type || 'desconhecido')
  const [notes, setNotes] = useState(initialData?.notes || '')
  const [errors, setErrors] = useState({})
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [submitMessage, setSubmitMessage] = useState(null)

  // ===== MEMOS (R-010: Hook Order) =====
  const canAddContact = useMemo(() => contacts.length < 5, [contacts.length])

  const formattedErrors = useMemo(() => {
    if (!errors || Object.keys(errors).length === 0) return null
    return errors
  }, [errors])

  // ===== HANDLERS (R-010: Hook Order) =====

  /**
   * Adiciona um novo contato vazio à lista.
   */
  const handleAddContact = useCallback(() => {
    if (canAddContact) {
      setContacts((prev) => [...prev, { name: '', phone: '', relationship: '' }])
    }
  }, [canAddContact])

  /**
   * Remove um contato da lista pelo índice.
   * @param {number} index - Índice do contato a ser removido
   */
  const handleRemoveContact = useCallback((index) => {
    setContacts((prev) => prev.filter((_, i) => i !== index))
  }, [])

  /**
   * Atualiza um campo específico de um contato.
   * @param {number} index - Índice do contato
   * @param {string} field - Campo a ser atualizado (name, phone, relationship)
   * @param {string} value - Novo valor
   */
  const handleContactChange = useCallback(
    (index, field, value) => {
      setContacts((prev) =>
        prev.map((contact, i) => (i === index ? { ...contact, [field]: value } : contact))
      )
      // Limpa erro do campo específico
      if (errors[`emergency_contacts.${index}.${field}`]) {
        setErrors((prev) => {
          const newErrors = { ...prev }
          delete newErrors[`emergency_contacts.${index}.${field}`]
          return newErrors
        })
      }
    },
    [errors]
  )

  /**
   * Adiciona uma alergia à lista.
   */
  const handleAddAllergy = useCallback(() => {
    const trimmedAllergy = allergyInput.trim()
    if (trimmedAllergy && !allergies.includes(trimmedAllergy) && allergies.length < 20) {
      setAllergies((prev) => [...prev, trimmedAllergy])
      setAllergyInput('')
    }
  }, [allergyInput, allergies])

  /**
   * Remove uma alergia da lista.
   * @param {string} allergy - Alergia a ser removida
   */
  const handleRemoveAllergy = useCallback((allergy) => {
    setAllergies((prev) => prev.filter((a) => a !== allergy))
  }, [])

  /**
   * Manipula o envio do formulário.
   * @param {Event} e - Evento de submit
   */
  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsSubmitting(true)
    setErrors({})
    setSubmitMessage(null)

    // Preparar dados para validação
    const dataToValidate = {
      emergency_contacts: contacts.filter((c) => c.name.trim() || c.phone.trim()),
      allergies,
      blood_type: bloodType,
      notes: notes.trim() || null,
    }

    // Validar com Zod
    const validation = validateEmergencyCard(dataToValidate)

    if (!validation.success) {
      // Mapear erros para formato de formulário
      const formErrors = {}
      validation.errors.forEach((err) => {
        formErrors[err.field] = err.message
      })
      setErrors(formErrors)
      setIsSubmitting(false)
      return
    }

    // Salvar via serviço
    const result = await emergencyCardService.save(validation.data)

    if (result.success) {
      setSubmitMessage({
        type: 'success',
        text: result.warning || 'Cartão de emergência salvo com sucesso!',
      })
      if (onSave) {
        onSave(result.data)
      }
    } else {
      setSubmitMessage({
        type: 'error',
        text: 'Erro ao salvar cartão. Tente novamente.',
      })
      if (result.errors) {
        const formErrors = {}
        result.errors.forEach((err) => {
          formErrors[err.field] = err.message
        })
        setErrors(formErrors)
      }
    }

    setIsSubmitting(false)
  }

  /**
   * Manipula a tecla Enter no campo de alergia.
   * @param {KeyboardEvent} e - Evento de teclado
   */
  const handleAllergyKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault()
      handleAddAllergy()
    }
  }

  return (
    <form className="emergency-card-form" onSubmit={handleSubmit}>
      {/* Contatos de Emergência */}
      <Card className="emergency-card-section" hover={false}>
        <h3 className="section-title">📞 Contatos de Emergência</h3>
        <p className="section-description">
          Adicione até 5 contatos que possam ser acionados em uma emergência.
        </p>

        {contacts.map((contact, index) => (
          <div key={index} className="contact-item">
            <div className="contact-header">
              <span className="contact-number">Contato {index + 1}</span>
              {contacts.length > 1 && (
                <button
                  type="button"
                  className="btn-remove-contact"
                  onClick={() => handleRemoveContact(index)}
                  aria-label={`Remover contato ${index + 1}`}
                >
                  ✕
                </button>
              )}
            </div>

            <div className="form-group">
              <label htmlFor={`contact-name-${index}`}>Nome</label>
              <input
                id={`contact-name-${index}`}
                type="text"
                value={contact.name}
                onChange={(e) => handleContactChange(index, 'name', e.target.value)}
                placeholder="Nome completo"
                maxLength={200}
                className={errors[`emergency_contacts.${index}.name`] ? 'input-error' : ''}
              />
              {errors[`emergency_contacts.${index}.name`] && (
                <span className="error-message">{errors[`emergency_contacts.${index}.name`]}</span>
              )}
            </div>

            <div className="form-group">
              <label htmlFor={`contact-phone-${index}`}>Telefone</label>
              <input
                id={`contact-phone-${index}`}
                type="tel"
                value={contact.phone}
                onChange={(e) => handleContactChange(index, 'phone', e.target.value)}
                placeholder="(XX) XXXXX-XXXX"
                maxLength={20}
                className={errors[`emergency_contacts.${index}.phone`] ? 'input-error' : ''}
              />
              {errors[`emergency_contacts.${index}.phone`] && (
                <span className="error-message">{errors[`emergency_contacts.${index}.phone`]}</span>
              )}
            </div>

            <div className="form-group">
              <label htmlFor={`contact-relationship-${index}`}>Parentesco</label>
              <input
                id={`contact-relationship-${index}`}
                type="text"
                value={contact.relationship}
                onChange={(e) => handleContactChange(index, 'relationship', e.target.value)}
                placeholder="Ex: Cônjuge, Filho(a), Irmão(ã)"
                maxLength={100}
                className={errors[`emergency_contacts.${index}.relationship`] ? 'input-error' : ''}
              />
              {errors[`emergency_contacts.${index}.relationship`] && (
                <span className="error-message">
                  {errors[`emergency_contacts.${index}.relationship`]}
                </span>
              )}
            </div>
          </div>
        ))}

        {canAddContact && (
          <Button type="button" variant="secondary" size="sm" onClick={handleAddContact}>
            + Adicionar Contato
          </Button>
        )}

        {errors['emergency_contacts'] && (
          <span className="error-message">{errors['emergency_contacts']}</span>
        )}
      </Card>

      {/* Alergias */}
      <Card className="emergency-card-section" hover={false}>
        <h3 className="section-title">⚠️ Alergias</h3>
        <p className="section-description">
          Liste suas alergias conhecidas (até 20). Isso é crucial para tratamento de emergência.
        </p>

        <div className="allergy-input-container">
          <input
            type="text"
            value={allergyInput}
            onChange={(e) => setAllergyInput(e.target.value)}
            onKeyDown={handleAllergyKeyDown}
            placeholder="Digite uma alergia"
            maxLength={200}
            className="allergy-input"
          />
          <Button
            type="button"
            variant="secondary"
            size="sm"
            onClick={handleAddAllergy}
            disabled={!allergyInput.trim() || allergies.length >= 20}
          >
            Adicionar
          </Button>
        </div>

        {allergies.length > 0 && (
          <div className="allergy-tags">
            {allergies.map((allergy, index) => (
              <span key={index} className="allergy-tag">
                {allergy}
                <button
                  type="button"
                  className="allergy-tag-remove"
                  onClick={() => handleRemoveAllergy(allergy)}
                  aria-label={`Remover alergia ${allergy}`}
                >
                  ✕
                </button>
              </span>
            ))}
          </div>
        )}

        {allergies.length === 0 && <p className="empty-state">Nenhuma alergia cadastrada</p>}
      </Card>

      {/* Tipo Sanguíneo */}
      <Card className="emergency-card-section" hover={false}>
        <h3 className="section-title">🩸 Tipo Sanguíneo</h3>
        <p className="section-description">
          Selecione seu tipo sanguíneo. Isso pode ser vital em uma emergência.
        </p>

        <div className="form-group">
          <label htmlFor="blood-type">Tipo Sanguíneo</label>
          <select
            id="blood-type"
            value={bloodType}
            onChange={(e) => setBloodType(e.target.value)}
            className="blood-type-select"
          >
            {BLOOD_TYPES.map((type) => (
              <option key={type} value={type}>
                {BLOOD_TYPE_LABELS[type]}
              </option>
            ))}
          </select>
        </div>
      </Card>

      {/* Observações */}
      <Card className="emergency-card-section" hover={false}>
        <h3 className="section-title">📝 Observações</h3>
        <p className="section-description">
          Informações adicionais importantes (condições médicas, medicamentos em uso contínuo,
          etc.).
        </p>

        <div className="form-group">
          <label htmlFor="notes">Observações</label>
          <textarea
            id="notes"
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Ex: Portador de marcapasso, usa anticoagulante..."
            maxLength={1000}
            rows={4}
            className="notes-textarea"
          />
          <span className="char-count">{notes.length}/1000</span>
        </div>
      </Card>

      {/* Mensagem de Status */}
      {submitMessage && (
        <div className={`submit-message submit-message-${submitMessage.type}`}>
          {submitMessage.text}
        </div>
      )}

      {/* Erros Gerais */}
      {formattedErrors && Object.keys(formattedErrors).length > 0 && !submitMessage && (
        <div className="submit-message submit-message-error">
          Verifique os campos destacados no formulário.
        </div>
      )}

      {/* Botões de Ação */}
      <div className="form-actions">
        <Button type="button" variant="secondary" onClick={onCancel} disabled={isSubmitting}>
          Cancelar
        </Button>
        <Button type="submit" variant="primary" disabled={isSubmitting}>
          {isSubmitting ? 'Salvando...' : 'Salvar Cartão'}
        </Button>
      </div>
    </form>
  )
}

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import { emergencyCardService } from '@features/emergency/services/emergencyCardService'
import { BLOOD_TYPE_LABELS } from '@schemas/emergencyCardSchema'
import { parseISO } from '@utils/dateUtils'
import EmergencyQRCode from './EmergencyQRCode'
import './EmergencyCard.css'

/**
 * Visualização do Cartão de Emergência.
 *
 * Exibe informações críticas em formato de fácil leitura para situações de emergência.
 * Inclui medicamentos ativos do usuário, contatos, alergias e tipo sanguíneo.
 * Indicador de offline quando sem conexão. Layout otimizado para impressão.
 *
 * @param {Object} props - Propriedades do componente
 * @param {Object} [props.data] - Dados do cartão (se não fornecido, carrega do serviço)
 * @param {Function} [props.onEdit] - Callback para edição do cartão
 * @returns {JSX.Element} Visualização do cartão de emergência
 */
export default function EmergencyCardView({ data, onEdit }) {
  // ===== STATES (R-010: Hook Order) =====
  const [cardData, setCardData] = useState(data || null)
  const [isLoading, setIsLoading] = useState(!data)
  const [isOffline, setIsOffline] = useState(!navigator.onLine)

  // ===== CONTEXT (R-010: Hook Order) =====
  const { medicines, protocols, isLoading: isDashboardLoading } = useDashboard()

  // ===== MEMOS (R-010: Hook Order) =====

  /**
   * Filtra medicamentos ativos com base nos protocolos ativos.
   */
  const activeMedications = useMemo(() => {
    if (isDashboardLoading || !medicines || !protocols) return []

    // IDs dos protocolos ativos
    const activeProtocolMedicineIds = new Set(
      protocols.filter((p) => p.active).map((p) => p.medicine_id)
    )

    // Filtra medicamentos que têm protocolos ativos
    return medicines
      .filter((med) => activeProtocolMedicineIds.has(med.id))
      .map((med) => ({
        name: med.name,
        dosage: med.dosage_per_pill,
        unit: med.dosage_unit || '',
      }))
  }, [medicines, protocols, isDashboardLoading])

  /**
   * Formata a data de última atualização.
   */
  const formattedLastUpdated = useMemo(() => {
    if (!cardData?.last_updated) return 'Não disponível'

    try {
      const date = parseISO(cardData.last_updated)
      return date.toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
      })
    } catch {
      return 'Data inválida'
    }
  }, [cardData])

  // ===== EFFECTS (R-010: Hook Order) =====

  /**
   * Carrega dados do cartão se não fornecidos via props.
   */
  useEffect(() => {
    if (!data) {
      const loadCardData = async () => {
        setIsLoading(true)
        const result = await emergencyCardService.load()
        if (result.success) {
          setCardData(result.data)
        }
        setIsLoading(false)
      }

      loadCardData()
    }
  }, [data])

  /**
   * Monitora status de conexão.
   */
  useEffect(() => {
    const handleOnline = () => setIsOffline(false)
    const handleOffline = () => setIsOffline(true)

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [])

  // ===== HANDLERS (R-010: Hook Order) =====

  /**
   * Imprime o cartão de emergência.
   */
  const handlePrint = useCallback(() => {
    window.print()
  }, [])

  // ===== RENDER =====

  if (isLoading) {
    return (
      <div className="emergency-card-view emergency-card-loading">
        <div className="loading-spinner"></div>
        <p>Carregando cartão de emergência...</p>
      </div>
    )
  }

  if (!cardData) {
    return (
      <div className="emergency-card-view emergency-card-empty">
        <div className="empty-icon">📋</div>
        <h2>Nenhum Cartão de Emergência</h2>
        <p>Você ainda não configurou seu cartão de emergência.</p>
        <button className="btn btn-primary" onClick={onEdit}>
          Configurar Agora
        </button>
      </div>
    )
  }

  return (
    <div className="emergency-card-view">
      {/* Indicador Offline */}
      {isOffline && (
        <div className="offline-indicator">
          <span className="offline-icon">📡</span>
          <span>Modo Offline - Dados podem estar desatualizados</span>
        </div>
      )}

      {/* Cabeçalho do Cartão */}
      <header className="emergency-card-header">
        <h1 className="emergency-title">🚨 CARTÃO DE EMERGÊNCIA</h1>
        <p className="emergency-subtitle">Informações médicas críticas</p>
      </header>

      {/* Tipo Sanguíneo - Destaque */}
      <section className="emergency-section blood-type-section">
        <h2 className="section-label">Tipo Sanguíneo</h2>
        <div className="blood-type-display">
          {BLOOD_TYPE_LABELS[cardData.blood_type] || 'Desconhecido'}
        </div>
      </section>

      {/* Alergias */}
      <section className="emergency-section allergies-section">
        <h2 className="section-label">⚠️ Alergias</h2>
        {cardData.allergies && cardData.allergies.length > 0 ? (
          <ul className="allergies-list">
            {cardData.allergies.map((allergy, index) => (
              <li key={index} className="allergy-item">
                {allergy}
              </li>
            ))}
          </ul>
        ) : (
          <p className="no-data">Nenhuma alergia registrada</p>
        )}
      </section>

      {/* Medicamentos em Uso */}
      <section className="emergency-section medications-section">
        <h2 className="section-label">💊 Medicamentos em Uso</h2>
        {activeMedications.length > 0 ? (
          <ul className="medications-list">
            {activeMedications.map((med, index) => (
              <li key={index} className="medication-item">
                <span className="med-name">{med.name}</span>
                {med.dosage && (
                  <span className="med-dosage">
                    {' '}
                    - {med.dosage} {med.unit}
                  </span>
                )}
              </li>
            ))}
          </ul>
        ) : (
          <p className="no-data">Nenhum medicamento ativo</p>
        )}
      </section>

      {/* Contatos de Emergência */}
      <section className="emergency-section contacts-section">
        <h2 className="section-label">📞 Contatos de Emergência</h2>
        {cardData.emergency_contacts && cardData.emergency_contacts.length > 0 ? (
          <div className="contacts-grid">
            {cardData.emergency_contacts.map((contact, index) => (
              <div key={index} className="contact-card">
                <div className="contact-name">{contact.name}</div>
                <div className="contact-phone">
                  <a href={`tel:${contact.phone}`}>{contact.phone}</a>
                </div>
                <div className="contact-relationship">{contact.relationship}</div>
              </div>
            ))}
          </div>
        ) : (
          <p className="no-data">Nenhum contato registrado</p>
        )}
      </section>

      {/* Observações */}
      {cardData.notes && (
        <section className="emergency-section notes-section">
          <h2 className="section-label">📝 Observações</h2>
          <p className="notes-content">{cardData.notes}</p>
        </section>
      )}

      {/* QR Code para Emergências */}
      <section className="emergency-section qr-section">
        <h2 className="section-label">📱 QR Code de Emergência</h2>
        <EmergencyQRCode
          cardData={cardData}
          medications={activeMedications}
          lastUpdated={cardData.last_updated}
        />
      </section>

      {/* Rodapé */}
      <footer className="emergency-card-footer">
        <p className="last-updated">Última atualização: {formattedLastUpdated}</p>
        <div className="footer-actions">
          <button className="btn btn-secondary btn-sm" onClick={handlePrint}>
            🖨️ Imprimir
          </button>
          {onEdit && (
            <button className="btn btn-primary btn-sm" onClick={onEdit}>
              ✏️ Editar
            </button>
          )}
        </div>
      </footer>
    </div>
  )
}

/**
 * @fileoverview Componente de QR Code para o Cartão de Emergência.
 * Gera um QR code com dados médicos críticos codificados em base64.
 * Permite download da imagem para uso como tela de bloqueio.
 *
 * @module features/emergency/components/EmergencyQRCode
 * @version 1.0.0
 */

import { useState, useEffect, useCallback, useMemo } from 'react'
import QRCode from 'qrcode'
import { getServerTimestamp, parseISO } from '@utils/dateUtils'
import './EmergencyQRCode.css'

/**
 * Props para o componente EmergencyQRCode
 * @typedef {Object} EmergencyQRCodeProps
 * @property {Object} cardData - Dados do cartão de emergência
 * @property {string} cardData.name - Nome do paciente
 * @property {string} [cardData.blood_type] - Tipo sanguíneo
 * @property {string[]} [cardData.allergies] - Lista de alergias
 * @property {Array<{name: string, dosage: string, unit: string}>} medications - Medicamentos ativos
 * @property {string} [lastUpdated] - Data da última atualização
 */

/**
 * Componente que gera e exibe um QR code com dados médicos de emergência.
 *
 * O QR code contém informações essenciais em formato JSON compacto e codificado
 * em base64, permitindo que profissionais de saúde acessem rapidamente os dados
 * em situações de emergência, mesmo sem internet.
 *
 * @param {EmergencyQRCodeProps} props - Propriedades do componente
 * @returns {JSX.Element} Componente de QR code com controles de download
 */
export default function EmergencyQRCode({ cardData, medications, lastUpdated }) {
  // ===== STATES (R-010: Hook Order) =====
  const [qrDataUrl, setQrDataUrl] = useState('')
  const [error, setError] = useState(null)
  const [isGenerating, setIsGenerating] = useState(true)

  // ===== MEMOS (R-010: Hook Order) =====

  /**
   * Formata os dados do cartão para o formato do QR code.
   * Estrutura compacta para economizar espaço no QR.
   *
   * Formato:
   * {
   *   v: "1",           // Versão do formato
   *   n: "Nome",        // Nome do paciente
   *   m: [...],         // Medicamentos (n: nome, d: dose, f: frequência)
   *   a: [...],         // Alergias
   *   bt: "A+",         // Tipo sanguíneo (opcional)
   *   dt: "2026-03-05"  // Data de atualização
   * }
   */
  const qrPayload = useMemo(() => {
    if (!cardData) return null

    const payload = {
      v: '1',
      n: cardData.name || 'Paciente',
      m:
        medications?.map((med) => ({
          n: med.name,
          d: med.dosage ? `${med.dosage}${med.unit ? ` ${med.unit}` : ''}` : '',
          f: med.frequency || '',
        })) || [],
      a: cardData.allergies || [],
      dt: lastUpdated
        ? parseISO(lastUpdated).toISOString().split('T')[0]
        : getServerTimestamp().split('T')[0],
    }

    // Adiciona tipo sanguíneo apenas se não for desconhecido
    if (cardData.blood_type && cardData.blood_type !== 'desconhecido') {
      payload.bt = cardData.blood_type
    }

    return payload
  }, [cardData, medications, lastUpdated])

  /**
   * Gera a string de dados para o QR code.
   * Usa JSON.stringify + base64 para compactação.
   */
  const qrDataString = useMemo(() => {
    if (!qrPayload) return ''

    try {
      const jsonString = JSON.stringify(qrPayload)
      // Usa btoa para base64 (browser API)
      return btoa(unescape(encodeURIComponent(jsonString)))
    } catch (err) {
      console.error('[EmergencyQRCode] Erro ao codificar dados:', err)
      return ''
    }
  }, [qrPayload])

  // ===== EFFECTS (R-010: Hook Order) =====

  /**
   * Gera o QR code quando os dados mudam.
   */
  useEffect(() => {
    if (!qrDataString) {
      // Use timeout para evitar setState síncrono no effect
      const timeoutId = setTimeout(() => setIsGenerating(false), 0)
      return () => clearTimeout(timeoutId)
    }

    // eslint-disable-next-line react-hooks/set-state-in-effect
    setIsGenerating(true)

    setError(null)

    /**
     * Gera o QR code usando a biblioteca qrcode.
     * Configuração otimizada para legibilidade e tamanho.
     */
    const generateQR = async () => {
      try {
        const dataUrl = await QRCode.toDataURL(qrDataString, {
          width: 256,
          margin: 2,
          color: {
            dark: '#000000',
            light: '#FFFFFF',
          },
          errorCorrectionLevel: 'M', // Medium - bom equilíbrio entre capacidade e tamanho
          type: 'image/png',
        })

        setQrDataUrl(dataUrl)
        setIsGenerating(false)
      } catch (err) {
        console.error('[EmergencyQRCode] Erro ao gerar QR:', err)
        setError('Não foi possível gerar o QR code. Tente novamente.')
        setIsGenerating(false)
      }
    }

    generateQR()
  }, [qrDataString])

  // ===== HANDLERS (R-010: Hook Order) =====

  /**
   * Faz o download da imagem do QR code.
   * Salva como PNG com nome descritivo.
   */
  const handleDownload = useCallback(() => {
    if (!qrDataUrl) return

    try {
      const link = document.createElement('a')
      link.href = qrDataUrl
      link.download = `cartao-emergencia-${qrPayload?.n?.replace(/\s+/g, '-').toLowerCase() || 'dosiq'}.png`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
    } catch (err) {
      console.error('[EmergencyQRCode] Erro ao baixar:', err)
      setError('Não foi possível baixar a imagem. Tente novamente.')
    }
  }, [qrDataUrl, qrPayload])

  /**
   * Compartilha a imagem usando a Web Share API (mobile).
   * Fallback para download em desktops.
   */
  const handleShare = useCallback(async () => {
    if (!qrDataUrl) return

    try {
      // Converte data URL para Blob
      const response = await fetch(qrDataUrl)
      const blob = await response.blob()
      const file = new File([blob], 'cartao-emergencia.png', { type: 'image/png' })

      // Tenta usar Web Share API
      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          title: 'Cartão de Emergência',
          text: 'Meu cartão de emergência médica',
          files: [file],
        })
      } else {
        // Fallback para download
        handleDownload()
      }
    } catch (err) {
      // Ignora erro de cancelamento pelo usuário
      if (err.name !== 'AbortError') {
        console.error('[EmergencyQRCode] Erro ao compartilhar:', err)
        handleDownload()
      }
    }
  }, [qrDataUrl, handleDownload])

  // ===== RENDER =====

  if (isGenerating) {
    return (
      <div className="emergency-qr-code loading">
        <div className="qr-loading-spinner"></div>
        <p>Gerando QR code...</p>
      </div>
    )
  }

  if (error) {
    return (
      <div className="emergency-qr-code error">
        <div className="qr-error-icon">⚠️</div>
        <p>{error}</p>
        <button className="btn btn-secondary btn-sm" onClick={() => setError(null)}>
          Tentar Novamente
        </button>
      </div>
    )
  }

  if (!qrDataUrl) {
    return (
      <div className="emergency-qr-code empty">
        <p>Dados insuficientes para gerar QR code.</p>
      </div>
    )
  }

  return (
    <div className="emergency-qr-code">
      <div className="qr-code-container">
        <img
          src={qrDataUrl}
          alt="QR Code do Cartão de Emergência"
          className="qr-code-image"
          width={256}
          height={256}
        />
        <p className="qr-hint">📱 Escaneie para ver informações médicas em emergências</p>
      </div>

      <div className="qr-actions">
        <button className="btn btn-primary" onClick={handleDownload}>
          💾 Salvar Imagem
        </button>
        <button className="btn btn-secondary" onClick={handleShare}>
          📤 Compartilhar
        </button>
      </div>

      <div className="qr-info">
        <p className="qr-info-text">
          <strong>Dica:</strong> Salve esta imagem como tela de bloqueio do seu celular para acesso
          rápido em emergências.
        </p>
      </div>
    </div>
  )
}

import { supabase, getUserId } from '@shared/utils/supabase'
import { validateEmergencyCard } from '@schemas/emergencyCardSchema'
import { getServerTimestamp } from '@utils/dateUtils'

/**
 * Emergency Card Service - Gerenciamento do cartão de emergência
 *
 * ESTRATÉGIA OFFLINE-FIRST:
 * - Primário: localStorage (chave: mr_emergency_card)
 * - Secundário: Supabase user_settings.emergency_card (JSONB)
 *
 * WRITE-THROUGH:
 * 1. Validar com schema Zod
 * 2. Salvar no localStorage
 * 3. Salvar no Supabase (se online)
 *
 * READ:
 * 1. Tentar localStorage primeiro
 * 2. Fallback para Supabase se localStorage vazio
 */

const STORAGE_KEY = 'mr_emergency_card'

/**
 * Log estruturado para o serviço de cartão de emergência
 * @param {string} level - Nível do log ('info', 'warn', 'error', 'debug')
 * @param {string} message - Mensagem do log
 * @param {Object} data - Dados adicionais para contexto
 */
function log(level, message, data = {}) {
  const logEntry = {
    timestamp: getServerTimestamp(),
    service: 'emergencyCardService',
    level,
    message,
    ...data,
  }

  // Em produção, isso seria enviado para um serviço de logging
  if (process.env.NODE_ENV === 'development' || level === 'error') {
    console.log(JSON.stringify(logEntry))
  }
}

/**
 * Verifica se o localStorage deve ser ignorado (ambiente de teste)
 * @returns {boolean} True se deve ignorar localStorage
 */
function shouldSkipLocalStorage() {
  return process.env.NODE_ENV === 'test'
}

/**
 * Salva dados no localStorage
 * @param {Object} data - Dados do cartão de emergência
 */
function saveToLocalStorage(data) {
  if (shouldSkipLocalStorage()) {
    log('debug', 'localStorage ignorado em ambiente de teste')
    return
  }

  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data))
    log('info', 'Dados salvos no localStorage')
  } catch (error) {
    log('error', 'Erro ao salvar no localStorage', { error: error.message })
  }
}

/**
 * Recupera dados do localStorage
 * @returns {Object|null} Dados do cartão ou null se vazio/erro
 */
function getFromLocalStorage() {
  if (shouldSkipLocalStorage()) {
    log('debug', 'localStorage ignorado em ambiente de teste')
    return null
  }

  try {
    const stored = localStorage.getItem(STORAGE_KEY)
    if (stored) {
      log('info', 'Dados recuperados do localStorage')
      return JSON.parse(stored)
    }
  } catch (error) {
    log('error', 'Erro ao ler localStorage', { error: error.message })
  }

  return null
}

/**
 * Mapeia dados do schema para formato do Supabase
 * @param {Object} data - Dados validados do cartão
 * @returns {Object} Dados formatados para Supabase
 */
function _mapToSupabase(data) {
  return {
    emergency_contacts: data.emergency_contacts,
    allergies: data.allergies,
    blood_type: data.blood_type,
    notes: data.notes || null,
    last_updated: data.last_updated || getServerTimestamp(),
  }
}

/**
 * Mapeia dados do Supabase para formato do schema
 * @param {Object} row - Registro do Supabase
 * @returns {Object|null} Dados formatados ou null se vazio
 */
function _mapFromSupabase(row) {
  if (!row || !row.emergency_card) {
    return null
  }

  const card = row.emergency_card

  return {
    emergency_contacts: card.emergency_contacts || [],
    allergies: card.allergies || [],
    blood_type: card.blood_type || 'desconhecido',
    notes: card.notes || null,
    last_updated: card.last_updated || getServerTimestamp(),
  }
}

/**
 * Salva o cartão de emergência no Supabase
 * @param {Object} data - Dados validados do cartão
 * @returns {Promise<{success: boolean, error?: string}>}
 */
async function saveToSupabase(data) {
  try {
    const userId = await getUserId()
    const emergencyCard = _mapToSupabase(data)

    // Usa upsert para criar ou atualizar
    const { error } = await supabase.from('user_settings').upsert(
      {
        user_id: userId,
        emergency_card: emergencyCard,
        updated_at: getServerTimestamp(),
      },
      {
        onConflict: 'user_id',
      }
    )

    if (error) {
      // Se a coluna não existir, loga aviso mas não falha
      if (error.message?.includes('column') || error.code === 'PGRST204') {
        log('warn', 'Coluna emergency_card não existe na tabela user_settings', {
          error: error.message,
        })
        return { success: true, warning: 'Dados salvos apenas localmente' }
      }

      log('error', 'Erro ao salvar no Supabase', { error: error.message })
      return { success: false, error: error.message }
    }

    log('info', 'Dados salvos no Supabase')
    return { success: true }
  } catch (error) {
    log('error', 'Exceção ao salvar no Supabase', { error: error.message })
    return { success: false, error: error.message }
  }
}

/**
 * Recupera o cartão de emergência do Supabase
 * @returns {Promise<Object|null>} Dados do cartão ou null
 */
async function getFromSupabase() {
  try {
    const userId = await getUserId()

    const { data, error } = await supabase
      .from('user_settings')
      .select('emergency_card')
      .eq('user_id', userId)
      .single()

    if (error) {
      // Se não encontrou registro, retorna null
      if (error.code === 'PGRST116') {
        log('info', 'Nenhum registro encontrado no Supabase')
        return null
      }

      log('error', 'Erro ao buscar no Supabase', { error: error.message })
      return null
    }

    log('info', 'Dados recuperados do Supabase')
    return _mapFromSupabase(data)
  } catch (error) {
    log('error', 'Exceção ao buscar no Supabase', { error: error.message })
    return null
  }
}

export const emergencyCardService = {
  /**
   * Salva o cartão de emergência com estratégia write-through
   *
   * Fluxo:
   * 1. Valida dados com schema Zod
   * 2. Salva no localStorage (síncrono)
   * 3. Salva no Supabase (assíncrono, se online)
   *
   * @param {Object} data - Dados do cartão de emergência
   * @returns {Promise<{success: boolean, data?: Object, errors?: Array<{field: string, message: string}>, warning?: string}>}
   */
  async save(data) {
    log('info', 'Iniciando salvamento do cartão de emergência')

    // 1. Validar com schema Zod
    const validation = validateEmergencyCard(data)

    if (!validation.success) {
      log('warn', 'Validação falhou', { errors: validation.errors })
      return { success: false, errors: validation.errors }
    }

    // Adiciona timestamp de atualização
    const dataToSave = {
      ...validation.data,
      last_updated: getServerTimestamp(),
    }

    // 2. Salvar no localStorage (síncrono)
    saveToLocalStorage(dataToSave)

    // 3. Salvar no Supabase (assíncrono)
    const supabaseResult = await saveToSupabase(dataToSave)

    if (!supabaseResult.success) {
      // Dados estão salvos localmente, mas falhou no Supabase
      log('warn', 'Salvo localmente, mas falhou no Supabase', {
        error: supabaseResult.error,
      })
      return {
        success: true,
        data: dataToSave,
        warning: 'Dados salvos localmente. Sincronização com nuvem falhou.',
      }
    }

    log('info', 'Cartão de emergência salvo com sucesso')
    return {
      success: true,
      data: dataToSave,
      warning: supabaseResult.warning,
    }
  },

  /**
   * Carrega o cartão de emergência com estratégia offline-first
   *
   * Fluxo:
   * 1. Tenta localStorage primeiro
   * 2. Fallback para Supabase se localStorage vazio
   *
   * @returns {Promise<{success: boolean, data?: Object, source?: 'local' | 'supabase'}>}
   */
  async load() {
    log('info', 'Carregando cartão de emergência')

    // 1. Tentar localStorage primeiro
    const localData = getFromLocalStorage()

    if (localData) {
      log('info', 'Dados carregados do localStorage')
      return { success: true, data: localData, source: 'local' }
    }

    // 2. Fallback para Supabase
    const supabaseData = await getFromSupabase()

    if (supabaseData) {
      // Salva no localStorage para próximas consultas
      saveToLocalStorage(supabaseData)
      log('info', 'Dados carregados do Supabase e salvos localmente')
      return { success: true, data: supabaseData, source: 'supabase' }
    }

    // Nenhum dado encontrado
    log('info', 'Nenhum cartão de emergência encontrado')
    return { success: true, data: null }
  },

  /**
   * Recupera o cartão de emergência APENAS do localStorage (síncrono)
   *
   * Use esta função quando precisar dos dados offline sem chamadas assíncronas.
   * Ideal para exibição em telas de emergência onde a velocidade é crítica.
   *
   * @returns {Object|null} Dados do cartão ou null se vazio
   */
  getOfflineCard() {
    log('info', 'Recuperando cartão offline (síncrono)')
    return getFromLocalStorage()
  },

  /**
   * Limpa o cartão de emergência do localStorage
   * (Não remove do Supabase - apenas limpa cache local)
   */
  clearLocalCache() {
    if (shouldSkipLocalStorage()) {
      return
    }

    try {
      localStorage.removeItem(STORAGE_KEY)
      log('info', 'Cache local limpo')
    } catch (error) {
      log('error', 'Erro ao limpar cache local', { error: error.message })
    }
  },
}

export default emergencyCardService

/**
 * ExportDialog - Dialog para exportação de dados do usuário
 *
 * @module ExportDialog
 * @description Componente modal que permite ao usuário exportar seus dados
 * em formatos CSV ou JSON, com filtros por tipo de dado e período.
 *
 * REGRAS SEGUIDAS:
 * - R-010: Hook order (States → Memos → Effects → Handlers)
 * - R-050: JSDoc em português
 */

import { useState, useMemo, useCallback } from 'react'
import { FileBracesCorner, FileDigit } from 'lucide-react'
import Modal from '@shared/components/ui/Modal'
import Button from '@shared/components/ui/Button'
import { exportAsJSON, exportAsCSV } from '@features/export/services/exportService'
import { parseLocalDate } from '@utils/dateUtils'
import './ExportDialog.css'

/** Opções de formato de exportação */
const FORMAT_OPTIONS = [
  { value: 'json', label: 'JSON', icon: FileBracesCorner },
  { value: 'csv', label: 'CSV', icon: FileDigit },
]

/** Labels para tipos de dados */
const DATA_TYPE_LABELS = {
  protocols: 'Protocolos',
  logs: 'Registros de Dose',
  stock: 'Estoque',
  medicines: 'Medicamentos',
}

/**
 * Componente de dialog para exportação de dados
 *
 * @param {Object} props - Propriedades do componente
 * @param {boolean} props.isOpen - Se o dialog está aberto
 * @param {Function} props.onClose - Callback para fechar o dialog
 * @returns {JSX.Element} Componente ExportDialog
 */
export default function ExportDialog({ isOpen, onClose }) {
  // 1. States (R-010: Hook order)
  const [format, setFormat] = useState('json')
  const [dateRange, setDateRange] = useState({ start: '', end: '' })
  const [includeProtocols, setIncludeProtocols] = useState(true)
  const [includeLogs, setIncludeLogs] = useState(true)
  const [includeStock, setIncludeStock] = useState(true)
  const [includeMedicines, setIncludeMedicines] = useState(true)
  const [isExporting, setIsExporting] = useState(false)
  const [exportError, setExportError] = useState(null)

  // 2. Memos (R-010: Hook order)
  const isExportDisabled = useMemo(() => {
    return !includeProtocols && !includeLogs && !includeStock && !includeMedicines
  }, [includeProtocols, includeLogs, includeStock, includeMedicines])

  const hasDateFilter = useMemo(() => {
    return dateRange.start || dateRange.end
  }, [dateRange])

  // 3. Handlers (R-010: Hook order)
  const handleFormatChange = useCallback((value) => {
    setFormat(value)
    setExportError(null)
  }, [])

  const handleDateChange = useCallback(
    (field) => (e) => {
      setDateRange((prev) => ({
        ...prev,
        [field]: e.target.value,
      }))
      setExportError(null)
    },
    []
  )

  const handleCheckboxChange = useCallback(
    (setter) => (e) => {
      setter(e.target.checked)
      setExportError(null)
    },
    []
  )

  const handleExport = useCallback(async () => {
    if (isExportDisabled) return

    setIsExporting(true)
    setExportError(null)

    try {
      const options = {
        includeProtocols,
        includeLogs,
        includeStock,
        includeMedicines,
        dateRange: hasDateFilter
          ? {
              start: dateRange.start ? parseLocalDate(dateRange.start) : null,
              end: dateRange.end ? parseLocalDate(dateRange.end) : null,
            }
          : null,
      }

      // Track analytics event
      if (typeof window !== 'undefined' && window.gtag) {
        window.gtag('event', 'export_data', {
          format,
          includeProtocols,
          includeLogs,
          includeStock,
          includeMedicines,
          hasDateFilter,
        })
      }

      // Execute export based on format
      if (format === 'json') {
        await exportAsJSON(options)
      } else {
        await exportAsCSV(options)
      }

      // Close dialog on success
      onClose()
    } catch (err) {
      console.error('Export error:', err)
      setExportError('Erro ao exportar dados. Tente novamente.')
    } finally {
      setIsExporting(false)
    }
  }, [
    format,
    includeProtocols,
    includeLogs,
    includeStock,
    includeMedicines,
    hasDateFilter,
    dateRange,
    isExportDisabled,
    onClose,
  ])

  const handleClose = useCallback(() => {
    if (!isExporting) {
      onClose()
    }
  }, [isExporting, onClose])

  return (
    <Modal isOpen={isOpen} onClose={handleClose} title="Exportar Dados">
      <div className="export-dialog">
        {/* Format Selector */}
        <div className="export-section">
          <label className="export-label">Formato</label>
          <div className="format-toggle">
            {FORMAT_OPTIONS.map((option) => {
              const OptionIcon = option.icon
              return (
                <button
                  key={option.value}
                  type="button"
                  className={`format-toggle-btn${format === option.value ? ' active' : ''}`}
                  onClick={() => handleFormatChange(option.value)}
                  disabled={isExporting}
                >
                  <OptionIcon size={18} />
                  {option.label}
                </button>
              )
            })}
          </div>
        </div>

        {/* Date Range */}
        <div className="export-section">
          <label className="export-label">Período (opcional)</label>
          <div className="date-range">
            <div className="date-input-group">
              <label htmlFor="export-date-start">De</label>
              <input
                id="export-date-start"
                type="date"
                value={dateRange.start}
                onChange={handleDateChange('start')}
                disabled={isExporting}
                className="date-input"
              />
            </div>
            <div className="date-input-group">
              <label htmlFor="export-date-end">Até</label>
              <input
                id="export-date-end"
                type="date"
                value={dateRange.end}
                onChange={handleDateChange('end')}
                disabled={isExporting}
                className="date-input"
              />
            </div>
          </div>
        </div>

        {/* Data Types */}
        <div className="export-section">
          <label className="export-label">Dados a exportar</label>
          <div className="checkbox-group">
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={includeProtocols}
                onChange={handleCheckboxChange(setIncludeProtocols)}
                disabled={isExporting}
              />
              <span>{DATA_TYPE_LABELS.protocols}</span>
            </label>
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={includeLogs}
                onChange={handleCheckboxChange(setIncludeLogs)}
                disabled={isExporting}
              />
              <span>{DATA_TYPE_LABELS.logs}</span>
            </label>
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={includeStock}
                onChange={handleCheckboxChange(setIncludeStock)}
                disabled={isExporting}
              />
              <span>{DATA_TYPE_LABELS.stock}</span>
            </label>
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={includeMedicines}
                onChange={handleCheckboxChange(setIncludeMedicines)}
                disabled={isExporting}
              />
              <span>{DATA_TYPE_LABELS.medicines}</span>
            </label>
          </div>
        </div>

        {/* Error Message */}
        {exportError && <div className="export-error">{exportError}</div>}

        {/* Actions */}
        <div className="export-actions">
          <Button variant="outline" onClick={handleClose} disabled={isExporting}>
            Cancelar
          </Button>
          <Button onClick={handleExport} disabled={isExportDisabled || isExporting}>
            {isExporting ? 'Exportando...' : 'Exportar'}
          </Button>
        </div>
      </div>
    </Modal>
  )
}

import { useState, useCallback, useRef, useEffect } from 'react'
import './Autocomplete.css'

/**
 * Componente genérico de autocomplete reutilizável.
 *
 * Debounce de 300ms + dropdown com navegação por teclado.
 * Abstrai a lógica de autocomplete para reutilização com diferentes fontes de dados.
 *
 * Props:
 * - value: string — valor do input
 * - onChange: (value) => void — callback ao digitar
 * - onSelect: (item) => void — callback ao selecionar
 * - searchFn: async (query, limit) => Promise<Array> — função de busca
 * - renderSuggestion: (item, index) => ReactNode — renderiza cada sugestão
 * - placeholder: string (default: "Digite para buscar...")
 * - disabled: boolean (default: false)
 * - dropdownId: string — ID ARIA para o dropdown
 */
export default function GenericAutocomplete({
  value = '',
  onChange,
  onSelect,
  searchFn,
  renderSuggestion,
  placeholder = 'Digite para buscar...',
  disabled = false,
  dropdownId = 'autocomplete-dropdown',
  inputId,
  ariaDescribedBy,
  ariaInvalid = false,
}) {
  const [suggestions, setSuggestions] = useState([])
  const [isOpen, setIsOpen] = useState(false)
  const [selectedIndex, setSelectedIndex] = useState(-1)
  const [isLoading, setIsLoading] = useState(false)
  const debounceRef = useRef(null)
  const inputRef = useRef(null)
  const dropdownRef = useRef(null)

  /**
   * Executa busca com debounce de 300ms
   */
  const debouncedSearch = useCallback(
    async (query) => {
      if (!query || query.trim().length < 3) {
        setSuggestions([])
        setIsOpen(false)
        return
      }

      setIsLoading(true)
      try {
        const results = await searchFn(query, 10)
        setSuggestions(results)
        setIsOpen(results.length > 0)
        setSelectedIndex(-1)
      } catch (error) {
        console.error('Erro ao buscar sugestões:', error)
        setSuggestions([])
        setIsOpen(false)
      } finally {
        setIsLoading(false)
      }
    },
    [searchFn]
  )

  /**
   * Debounce wrapper
   */
  const handleSearch = useCallback(
    (query) => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current)
      }
      debounceRef.current = setTimeout(() => {
        debouncedSearch(query)
      }, 300)
    },
    [debouncedSearch]
  )

  /**
   * Ao digitar no input
   */
  const handleInputChange = (e) => {
    const newValue = e.target.value
    onChange?.(newValue)
    handleSearch(newValue)
  }

  /**
   * Ao selecionar uma sugestão
   */
  const handleSelectSuggestion = (item) => {
    onSelect?.(item)
    setIsOpen(false)
    setSuggestions([])
    setSelectedIndex(-1)
  }

  /**
   * Navegação por teclado (setas, Enter, Escape)
   */
  const handleKeyDown = (e) => {
    if (!isOpen || suggestions.length === 0) {
      if (e.key === 'Escape') {
        setIsOpen(false)
      }
      return
    }

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault()
        setSelectedIndex((prev) => (prev < suggestions.length - 1 ? prev + 1 : prev))
        break

      case 'ArrowUp':
        e.preventDefault()
        setSelectedIndex((prev) => (prev > 0 ? prev - 1 : -1))
        break

      case 'Enter':
        e.preventDefault()
        if (selectedIndex >= 0 && selectedIndex < suggestions.length) {
          handleSelectSuggestion(suggestions[selectedIndex])
        }
        break

      case 'Escape':
        e.preventDefault()
        setIsOpen(false)
        break

      default:
        break
    }
  }

  /**
   * Fechar dropdown ao clicar fora
   */
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        if (inputRef.current && !inputRef.current.contains(event.target)) {
          setIsOpen(false)
        }
      }
    }

    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [])

  /**
   * Scroll para item selecionado
   */
  useEffect(() => {
    if (selectedIndex >= 0 && dropdownRef.current) {
      const items = dropdownRef.current.querySelectorAll('[role="option"]')
      if (items[selectedIndex]) {
        items[selectedIndex].scrollIntoView({ block: 'nearest' })
      }
    }
  }, [selectedIndex])

  return (
    <div className="autocomplete-wrapper">
      <div className="autocomplete-input-container">
        <input
          ref={inputRef}
          id={inputId}
          type="text"
          value={value}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          autoComplete="off"
          disabled={disabled}
          className="autocomplete-input"
          aria-autocomplete="list"
          aria-expanded={isOpen && suggestions.length > 0}
          aria-controls={dropdownId}
          aria-describedby={ariaDescribedBy}
          aria-invalid={ariaInvalid}
        />
        {isLoading && <span className="autocomplete-spinner">⟳</span>}
      </div>

      {isOpen && suggestions.length > 0 && (
        <div ref={dropdownRef} id={dropdownId} className="autocomplete-dropdown" role="listbox">
          {suggestions.map((item, index) => (
            <div
              key={index}
              role="option"
              aria-selected={selectedIndex === index}
              className={`autocomplete-item ${selectedIndex === index ? 'selected' : ''}`}
              onClick={() => handleSelectSuggestion(item)}
              onMouseEnter={() => setSelectedIndex(index)}
            >
              {renderSuggestion(item, index)}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

import { useState } from 'react'
import Button from '@shared/components/ui/Button'
import ShakeEffect from '@shared/components/ui/animations/ShakeEffect'
import MedicineAutocomplete from './MedicineAutocomplete'
import LaboratoryAutocomplete from './LaboratoryAutocomplete'
import {
  MEDICINE_TYPES,
  DOSAGE_UNITS,
  DOSAGE_UNIT_LABELS,
  REGULATORY_CATEGORIES,
  REGULATORY_CATEGORY_LABELS,
} from '@schemas/medicineSchema'
import { toTitleCase, toSentenceCase } from '@utils/stringUtils'
import { getFieldDescribedBy } from '@utils/formUtils'
import { AlertCircle } from 'lucide-react'
import './MedicineForm.css'

/**
 * @typedef {Object} MedicineFormProps
 * @property {Object} [medicine] - Dados para edição (modo edição)
 * @property {Function} onSave - Callback ao salvar (recebe dados validados)
 * @property {Function} [onCancel] - Callback ao cancelar
 * @property {Function} [onSuccess] - Callback após sucesso (para onboarding)
 * @property {boolean} [autoAdvance=false] - Se true, chama onSuccess após delay
 * @property {boolean} [showSuccessMessage=true] - Mostrar mensagem de sucesso
 * @property {boolean} [showCancelButton=true] - Mostrar botão cancelar
 * @property {string} [submitButtonLabel] - Label customizado do botão submit
 * @property {string} [title] - Título customizado do formulário
 */

export default function MedicineForm({
  medicine,
  onSave,
  onCancel,
  onSuccess,
  autoAdvance = false,
  showSuccessMessage = true,
  showCancelButton = true,
  submitButtonLabel,
  title,
}) {
  const [formData, setFormData] = useState({
    name: medicine?.name || '',
    laboratory: medicine?.laboratory || '',
    active_ingredient: medicine?.active_ingredient || '',
    dosage_per_pill: medicine?.dosage_per_pill || '',
    type: medicine?.type || 'medicamento',
    dosage_unit: medicine?.dosage_unit || 'mg',
    therapeutic_class: medicine?.therapeutic_class || null,
    regulatory_category: medicine?.regulatory_category || null,
  })

  const [errors, setErrors] = useState({})
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [shakeFields, setShakeFields] = useState({})
  const [saveSuccess, setSaveSuccess] = useState(false)

  const handleChange = (e) => {
    const { name, value } = e.target
    setFormData((prev) => ({ ...prev, [name]: value }))
    // Limpa erro do campo quando usuário começa a digitar
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }))
    }
    // Limpa mensagem de sucesso ao editar
    if (saveSuccess) {
      setSaveSuccess(false)
    }
  }

  /**
   * Ao selecionar medicamento do autocomplete ANVISA
   */
  const handleMedicineSelect = (medicine) => {
    setFormData((prev) => ({
      ...prev,
      name: medicine.name,
      active_ingredient: toTitleCase(medicine.activeIngredient),
      therapeutic_class: toSentenceCase(medicine.therapeuticClass) || null,
      regulatory_category: medicine.regulatoryCategory || null,
      laboratory: medicine.laboratory || '',
    }))
    if (saveSuccess) setSaveSuccess(false)
  }

  /**
   * Ao selecionar laboratório do autocomplete ANVISA
   */
  const handleLaboratorySelect = (laboratory) => {
    setFormData((prev) => ({
      ...prev,
      laboratory: laboratory.laboratory,
    }))
    if (saveSuccess) setSaveSuccess(false)
  }

  const validate = () => {
    const newErrors = {}

    if (!formData.name.trim()) {
      newErrors.name = 'Nome é obrigatório'
    }

    // Dosage is optional for supplements, but must be active number if provided
    if (formData.dosage_per_pill && isNaN(formData.dosage_per_pill)) {
      newErrors.dosage_per_pill = 'Deve ser um número'
    }

    setErrors(newErrors)

    // Extrair campos com erro para shake effect
    if (Object.keys(newErrors).length > 0) {
      const fieldsWithError = Object.keys(newErrors)
      setShakeFields(fieldsWithError.reduce((acc, field) => ({ ...acc, [field]: true }), {}))

      // Limpar shake após animação
      setTimeout(() => setShakeFields({}), 500)
    }

    return Object.keys(newErrors).length === 0
  }

  const handleSubmit = async (e) => {
    e.preventDefault()

    if (!validate()) return

    setIsSubmitting(true)

    try {
      // Converte strings vazias para null e números para o tipo correto
      const dataToSave = {
        name: formData.name.trim(),
        laboratory: formData.laboratory.trim() || null,
        active_ingredient: formData.active_ingredient.trim() || null,
        dosage_per_pill: formData.dosage_per_pill ? parseFloat(formData.dosage_per_pill) : null,
        type: formData.type,
        dosage_unit: formData.dosage_unit,
        therapeutic_class: formData.therapeutic_class || null,
        regulatory_category: formData.regulatory_category || null,
      }

      const savedMedicine = await onSave(dataToSave)

      if (showSuccessMessage) {
        setSaveSuccess(true)
      }

      if (autoAdvance && onSuccess) {
        setTimeout(() => {
          onSuccess(savedMedicine)
        }, 800)
      }
    } catch (error) {
      console.error('Erro ao salvar medicamento:', error)
      const errorMessage = error?.message || 'Erro desconhecido ao salvar medicamento'
      setErrors({ submit: errorMessage })
    } finally {
      setIsSubmitting(false)
    }
  }

  // Determina o título do formulário
  const formTitle = title || (medicine ? 'Editar Medicamento' : 'Novo Medicamento')

  return (
    <form className="medicine-form" onSubmit={handleSubmit}>
      <h3>{formTitle}</h3>

      {saveSuccess && showSuccessMessage && (
        <div className="success-message">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          <span>Medicamento salvo com sucesso!</span>
        </div>
      )}

      <div className="form-group">
        <label htmlFor="type">Tipo</label>
        <select
          id="type"
          name="type"
          value={formData.type}
          onChange={handleChange}
          disabled={isSubmitting}
        >
          {MEDICINE_TYPES.map((type) => (
            <option key={type} value={type}>
              {type === 'medicamento' ? 'Medicamento' : 'Suplemento'}
            </option>
          ))}
        </select>
      </div>

      <div className="form-group">
        <label htmlFor="name">
          Nome {formData.type === 'suplemento' ? '(Comercial)' : 'do Remédio'}{' '}
          <span className="required">*</span>
          {formData.name && !medicine?.name && (
            <span className="autocomplete-badge" title="Preenchido via Base ANVISA">
              Fonte: ANVISA
            </span>
          )}
        </label>
        <ShakeEffect trigger={shakeFields.name}>
          <MedicineAutocomplete
            value={formData.name}
            onChange={(value) => {
              setFormData((prev) => ({ ...prev, name: value }))
              if (errors.name) setErrors((prev) => ({ ...prev, name: '' }))
              if (saveSuccess) setSaveSuccess(false)
            }}
            onSelect={handleMedicineSelect}
            inputId="name"
            placeholder="Ex: Paracetamol ou digite para buscar..."
            disabled={isSubmitting}
            ariaDescribedBy={getFieldDescribedBy('name')}
            ariaInvalid={Boolean(errors.name)}
          />
        </ShakeEffect>
        {errors.name && (
          <span id="name-error" className="error-message">
            {errors.name}
          </span>
        )}
      </div>

      <div className="form-group">
        <label htmlFor="active_ingredient">
          Princípio Ativo
          {formData.active_ingredient && !medicine?.active_ingredient && (
            <span className="autocomplete-badge" title="Preenchido via Base ANVISA">
              Fonte: ANVISA
            </span>
          )}
        </label>
        <input
          type="text"
          id="active_ingredient"
          name="active_ingredient"
          value={formData.active_ingredient}
          onChange={handleChange}
          placeholder="Ex: Paracetamol"
          disabled={isSubmitting}
          readOnly={formData.active_ingredient && !medicine?.active_ingredient}
          aria-describedby="active_ingredient-hint"
        />
        <small id="active_ingredient-hint" className="field-hint">
          Preenchido automaticamente ao selecionar medicamento
        </small>
      </div>

      <div className="form-group">
        <label htmlFor="therapeutic_class">
          Classe Terapêutica
          {formData.therapeutic_class && !medicine?.therapeutic_class && (
            <span className="autocomplete-badge" title="Preenchido via Base ANVISA">
              Fonte: ANVISA
            </span>
          )}
        </label>
        <input
          type="text"
          id="therapeutic_class"
          name="therapeutic_class"
          value={formData.therapeutic_class || ''}
          onChange={handleChange}
          placeholder="Ex: Analgésicos não narcóticos"
          disabled={isSubmitting}
          maxLength={100}
        />
      </div>

      <div className="form-group">
        <label htmlFor="laboratory">Marca / Laboratório</label>
        <LaboratoryAutocomplete
          value={formData.laboratory}
          onChange={(value) => {
            setFormData((prev) => ({ ...prev, laboratory: value }))
            if (saveSuccess) setSaveSuccess(false)
          }}
          onSelect={handleLaboratorySelect}
          inputId="laboratory"
          placeholder="Ex: EMS, Medley ou digite para buscar..."
          disabled={isSubmitting}
          ariaDescribedBy="laboratory-hint"
        />
        <small id="laboratory-hint" className="field-hint">
          Opcional. Base ANVISA com 278 laboratórios registrados
        </small>
      </div>

      <div className="form-group">
        <label htmlFor="regulatory_category">
          Categoria Regulatória
          {formData.regulatory_category && !medicine?.regulatory_category && (
            <span className="autocomplete-badge" title="Preenchido via Base ANVISA">
              Fonte: ANVISA
            </span>
          )}
        </label>
        <select
          id="regulatory_category"
          name="regulatory_category"
          value={formData.regulatory_category || ''}
          onChange={handleChange}
          disabled={isSubmitting}
          aria-describedby="regulatory_category-hint"
        >
          <option value="">Selecione (opcional)</option>
          {REGULATORY_CATEGORIES.map((category) => (
            <option key={category} value={category}>
              {REGULATORY_CATEGORY_LABELS[category] || category}
            </option>
          ))}
        </select>
        <small id="regulatory_category-hint" className="field-hint">
          Preenchido via ANVISA e usado no fluxo de compras do estoque redesign.
        </small>
      </div>

      <div className="form-group">
        <label htmlFor="dosage_per_pill">
          Dosagem <strong>(Específica da sua prescrição)</strong>
        </label>
        <div
          className="dosage-input-group"
          style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '8px' }}
        >
          <ShakeEffect trigger={shakeFields.dosage_per_pill}>
            <input
              type="number"
              id="dosage_per_pill"
              name="dosage_per_pill"
              value={formData.dosage_per_pill}
              onChange={handleChange}
              className={errors.dosage_per_pill ? 'error' : ''}
              placeholder={formData.type === 'suplemento' ? 'Opcional' : '500'}
              step="0.01"
              disabled={isSubmitting}
              aria-describedby={getFieldDescribedBy('dosage_per_pill', 'dosage_per_pill-hint')}
              aria-invalid={Boolean(errors.dosage_per_pill)}
            />
          </ShakeEffect>
          <select
            name="dosage_unit"
            value={formData.dosage_unit}
            onChange={handleChange}
            disabled={isSubmitting}
          >
            {DOSAGE_UNITS.map((unit) => (
              <option key={unit} value={unit}>
                {DOSAGE_UNIT_LABELS[unit] || unit}
              </option>
            ))}
          </select>
        </div>
        <small id="dosage_per_pill-hint" className="field-hint">
          Preencha com a dosagem prescrita pelo seu médico
        </small>
        {errors.dosage_per_pill && (
          <span id="dosage_per_pill-error" className="error-message">
            {errors.dosage_per_pill}
          </span>
        )}
      </div>

      {errors.submit && (
        <div className="error-banner">
          <AlertCircle size={18} /> {errors.submit}
        </div>
      )}

      <div className="form-actions">
        {showCancelButton && (
          <Button type="button" variant="ghost" onClick={onCancel} disabled={isSubmitting}>
            Cancelar
          </Button>
        )}
        <Button type="submit" variant="primary" disabled={isSubmitting}>
          {isSubmitting
            ? 'Salvando...'
            : submitButtonLabel || (medicine ? 'Atualizar' : 'Cadastrar')}
        </Button>
      </div>
    </form>
  )
}

/**
 * NotificationCard — Card de item de notificação para a inbox web.
 *
 * Exibe ícone semântico, título contextual, data relativa e ação contextual.
 * ADR-012 (radius ≥ 0.75rem), ADR-023 (weight ≥ 400), R-138 (ícone+label).
 *
 * Props:
 *   notification — objeto notificationLog do DB
 *   onNavigate   — callback de navegação (recebe view id)
 *   index        — índice para stagger de animação
 *   wasTaken     — booleano calculado pelo pai (dose_reminder já foi tomada)
 *   doseLogs     — não usado diretamente; wasTaken já vem processado
 */
import { useState } from 'react'
import { motion } from 'framer-motion'
import { Clock, Package, AlertTriangle, BarChart2, TrendingUp, Bell, ChevronRight, BellOff, CheckCircle2 } from 'lucide-react'
import { getNotificationIcon, formatRelativeTime } from '@dosiq/core'
import { NOTIFICATION_TYPES, DOSE_RELATED_NOTIFICATION_TYPES } from '@schemas'
import { parseISO } from '@utils/dateUtils'
import './NotificationCard.css'

const ICON_MAP = { Clock, Package, AlertTriangle, BarChart2, TrendingUp, Bell }

// Mapeamento de tipo → CTA
const CTA_MAP = {
  [NOTIFICATION_TYPES.DOSE_REMINDER]:         { label: 'Registrar dose',    action: 'dashboard' },
  [NOTIFICATION_TYPES.DOSE_REMINDER_BY_PLAN]: { label: 'Registrar plano',   action: 'dashboard' },
  [NOTIFICATION_TYPES.DOSE_REMINDER_MISC]:    { label: 'Registrar doses',   action: 'dashboard' },
  [NOTIFICATION_TYPES.STOCK_ALERT]:           { label: 'Ver estoque',        action: 'stock' },
  [NOTIFICATION_TYPES.MISSED_DOSE]:           { label: 'Registrar atrasada', action: 'history' },
  [NOTIFICATION_TYPES.TITRATION_UPDATE]:      { label: 'Ver tratamento',     action: 'treatment' },
  [NOTIFICATION_TYPES.DAILY_DIGEST]:          null,
}

/**
 * Resolve o título do card de acordo com o tipo da notificação.
 * Prioriza medicine_name / protocol_name / treatment_plan_name sobre o label genérico.
 */
function resolveTitle(notification, label) {
  const { notification_type, medicine_name, protocol_name, treatment_plan_name } = notification
  switch (notification_type) {
    case NOTIFICATION_TYPES.DOSE_REMINDER:
    case NOTIFICATION_TYPES.STOCK_ALERT:
    case NOTIFICATION_TYPES.MISSED_DOSE:
      return medicine_name ?? label
    case NOTIFICATION_TYPES.TITRATION_UPDATE:
      return protocol_name ?? label
    case NOTIFICATION_TYPES.DAILY_DIGEST:
      return 'Resumo do dia'
    case NOTIFICATION_TYPES.DOSE_REMINDER_BY_PLAN:
      return treatment_plan_name ?? 'Plano de tratamento'
    case NOTIFICATION_TYPES.DOSE_REMINDER_MISC:
      return 'Doses agendadas'
    default:
      return label
  }
}

export default function NotificationCard({
  notification,
  onNavigate,
  onOpenDoseModal,
  index = 0,
  wasTaken,
}) {
  // 1. States
  const [expanded, setExpanded] = useState(false)

  // 2. Derivados
  const {
    notification_type,
    status,
    sent_at,
    body,
  } = notification

  const { iconName, color, bgColor, label } = getNotificationIcon(notification_type)
  const IconComponent = ICON_MAP[iconName] ?? Bell
  const relativeTime  = formatRelativeTime(sent_at)
  const isFailed      = ['falhou', 'failed'].includes(status?.toLowerCase())
  const isMuted       = status?.toLowerCase() === 'muted'
  const isDailyDigest = notification_type === NOTIFICATION_TYPES.DAILY_DIGEST
  const isDoseRelated = DOSE_RELATED_NOTIFICATION_TYPES.includes(notification_type)

  // Título: sempre resolve pelo tipo (medicine_name, protocol_name, etc.)
  const displayTitle = resolveTitle(notification, label)

  const displayBody = body ?? null
  const doses       = notification.doses ?? null

  // CTA
  const cta = CTA_MAP[notification_type] ?? null

  return (
    <motion.article
      className="notif-card"
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2, delay: index * 0.04, ease: 'easeOut' }}
      role="listitem"
    >
      {/* Ícone circular */}
      <div
        className="notif-card__icon"
        style={{ backgroundColor: bgColor }}
        aria-hidden="true"
      >
        <IconComponent size={20} color={color} strokeWidth={2} />
      </div>

      {/* Conteúdo */}
      <div className="notif-card__body">

        {/* Cabeçalho: título + timestamp (+ ícone de falha se aplicável) */}
        <div className="notif-card__header">
          <span className="notif-card__label">{displayTitle}</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: 4, flexShrink: 0 }}>
            <time
              className="notif-card__time"
              dateTime={sent_at}
              title={sent_at ? parseISO(sent_at).toLocaleString('pt-BR') : ''}
            >
              {relativeTime}
            </time>
            {isFailed && (
              <AlertTriangle
                size={12}
                color="#dc2626"
                strokeWidth={2.5}
                aria-label="Falhou ao enviar"
              />
            )}
            {isMuted && (
              <span className="notif-card__muted-badge">
                <BellOff size={10} strokeWidth={2.5} />
                Silenciada
              </span>
            )}
          </div>
        </div>

        {/* Corpo */}
        {doses?.length > 0 ? (
          <ul className="notif-card__dose-list">
            {doses.map((dose, i) => (
              <li key={i} className="notif-card__dose-item">
                {`${dose.dosage}x ${dose.medicineName}`}
              </li>
            ))}
          </ul>
        ) : displayBody ? (
          <>
            <p
              className={`notif-card__preview ${isDailyDigest && !expanded ? 'notif-card__preview--collapsed' : ''}`}
            >
              {displayBody}
            </p>
            {isDailyDigest && (
              <button
                className="notif-card__expand"
                onClick={() => setExpanded(prev => !prev)}
                aria-expanded={expanded}
              >
                {expanded ? 'Ver menos' : 'Ver mais'}
              </button>
            )}
          </>
        ) : null}

        {/* Rodapé: CTA */}
        <div className="notif-card__footer">
          {isDoseRelated && wasTaken === true ? (
            <span className="notif-card__taken">
              <CheckCircle2 size={14} /> Tomada
            </span>
          ) : cta && (onNavigate || onOpenDoseModal) ? (
            <button
              className="notif-card__action"
              onClick={() => {
                const isPlan = notification_type === NOTIFICATION_TYPES.DOSE_REMINDER_BY_PLAN
                const isMisc = notification_type === NOTIFICATION_TYPES.DOSE_REMINDER_MISC
                const isIndividual = notification_type === NOTIFICATION_TYPES.DOSE_REMINDER
                if (isIndividual && onOpenDoseModal && notification.protocol_id) {
                  onOpenDoseModal({ type: 'protocol', protocol_id: notification.protocol_id })
                } else if ((isPlan || isMisc) && onOpenDoseModal) {
                  onOpenDoseModal({
                    type: isPlan ? 'plan' : 'protocol',
                    treatment_plan_id: notification.treatment_plan_id ?? '',
                  })
                } else {
                  onNavigate(cta.action)
                }
              }}
              aria-label={`${cta.label} — ${displayTitle}`}
            >
              {cta.label}
              <ChevronRight size={13} strokeWidth={2.5} aria-hidden="true" />
            </button>
          ) : null}
        </div>

      </div>
    </motion.article>
  )
}

/**
 * NotificationList — Lista de notificações (web).
 * R-115: react-virtuoso se > 30 itens.
 * Estados: loading (skeleton), vazio, erro, dados.
 *
 * Agrupa notificações por dia (Hoje / Ontem / Esta semana / Mais antigos).
 * Calcula wasTaken para cada dose_reminder e passa para NotificationCard.
 */
import { useMemo, useState, useEffect } from 'react'
import { Virtuoso } from 'react-virtuoso'
import { Bell } from 'lucide-react'
import { NOTIFICATION_TYPES, DOSE_RELATED_NOTIFICATION_TYPES } from '@schemas'
import { formatLocalDate, addDays, parseLocalDate, getNow, getTodayLocal, parseISO, daysDifference } from '@utils/dateUtils'
import NotificationCard from './NotificationCard'
import './NotificationList.css'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Agrupa notificações por faixa temporal em relação ao dia atual.
 * @param {Array} notifications
 * @returns {Array<{title: string, items: Array}>}
 */
function groupByDay(notifications, todayStr = getTodayLocal()) {
  const groups = [
    { title: 'Hoje',         items: [] },
    { title: 'Ontem',        items: [] },
    { title: 'Esta semana',  items: [] },
    { title: 'Mais antigos', items: [] },
  ]

  for (const n of notifications) {
    const diff = daysDifference(n.sent_at, todayStr)

    if (diff === 0)       groups[0].items.push(n)
    else if (diff === 1)  groups[1].items.push(n)
    else if (diff <= 7)   groups[2].items.push(n)
    else                  groups[3].items.push(n)
  }

  return groups.filter(g => g.items.length > 0)
}

/**
 * Para uma notificação dose_reminder, verifica se há um log posterior ao envio.
 * @param {Object} notification
 * @param {Array} doseLogs
 * @returns {boolean}
 */
function calcWasTaken(notification, doseLogs) {
  if (!doseLogs?.length) return false
  const { notification_type, protocol_id, treatment_plan_id, sent_at } = notification
  const sentAtDate = parseISO(sent_at)

  return doseLogs.some(log => {
    const takenAtDate = parseISO(log.taken_at)
    if (takenAtDate <= sentAtDate) return false

    if (notification_type === NOTIFICATION_TYPES.DOSE_REMINDER && protocol_id) {
      return log.protocol_id === protocol_id
    }
    if (notification_type === NOTIFICATION_TYPES.DOSE_REMINDER_BY_PLAN && treatment_plan_id) {
      return log.treatment_plan_id === treatment_plan_id
    }
    if (notification_type === NOTIFICATION_TYPES.DOSE_REMINDER_MISC) {
      // Para misc, se houver qualquer log posterior, assumimos como parcial ou totalmente registrado
      // O ideal seria verificar todos os protocolos na lista, mas logs simplificados ajudam na UX
      return true
    }
    return false
  })
}

