// Sub-componentes
// ---------------------------------------------------------------------------

const GROUP_HEADER_STYLE = {
  fontSize: 12,
  fontWeight: 600,
  color: '#6b7280',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  padding: '12px 0 6px',
}

function GroupHeader({ title }) {
