                  variant="ghost"
                  onClick={() => {
                    setStep(1)
                    setResult(null)
                    setMedicineData({
                      name: '',
                      type: 'medicamento',
                      dosage_per_pill: '',
                      dosage_unit: 'mg',
                      laboratory: '',
                      active_ingredient: '',
                      therapeutic_class: null,
                    })
                    setProtocolData({
                      frequency: 'diário',
                      time_schedule: ['08:00'],
                      dosage_per_intake: 1,
                      start_date: formatLocalDate(getNow()),
                    })
                    setStockData({
                      quantity: '',
                      purchase_date: formatLocalDate(getNow()),
                      unit_price: '',
                      expiration_date: '',
                    })
                  }}
                >
                  Cadastrar outro
                </Button>
              </div>
            </div>
          )}
        </motion.div>
      </AnimatePresence>
    </div>
  )
}

/**
 * ProtocolRow — Row reutilizável com dois variantes
 *
 * variant="card" (padrão — Modo Simples):
 * - Layout vertical (flex-column) em mobile
 * - Cards empilhados com nome, dosagem, frequência, adesão, estoque
 * - Expandível para titulação e notas
 *
 * variant="tabular" (Modo Complexo Desktop):
 * - 4 células separadas: nome | frequência | adesão | estoque
 * - Renderiza sem button, sem expand (cada célula é independente)
 * - CSS Grid do container pai distribui as 4 células horizontalmente
 */
import { Trash2 } from 'lucide-react'
import { AnimatePresence, motion } from 'framer-motion'
import AdherenceBar7d from './AdherenceBar7d'
import AdherenceLabel from './AdherenceLabel'
import StockPill from './StockPill'
import TitrationBadge from './TitrationBadge'

/**
 * ProtocolRow — Row reutilizável com dois variantes
 * S7.5.5: Adicionar isHovered prop para iluminar linha inteira em desktop
 * Célula 1 convertida de button para div (clique agora no wrapper pai)
 */
export default function ProtocolRow({
  item,
  isComplex,
  expanded,
  onToggleExpand,
  onEdit,
  onDelete,
  activeTab,
  variant = 'card',
  isHovered = false, // S7.5.5
  onRowMouseEnter, // S7.5.5
  onRowMouseLeave, // S7.5.5
  onRowClick, // S7.5.5
}) {
  const showAdherence = activeTab === 'ativos'

  // ────────────────────────────────────────────────────────────────
  // VARIANTE: TABULAR (Modo Complexo Desktop)
  // ────────────────────────────────────────────────────────────────
  if (variant === 'tabular') {
    const hoverClass = isHovered ? 'protocol-row-tabular__cell--hovered' : '' // S7.5.5

    return (
      <>
        {/* CÉLULA 1: Nome + Dosagem — S7.5.5: recebe mouse events e click */}
        <div
          className={`protocol-row-tabular__cell protocol-row-tabular__name-cell ${hoverClass}`}
          style={{ minHeight: '3.5rem' }}
          onMouseEnter={onRowMouseEnter}
          onMouseLeave={onRowMouseLeave}
          onClick={onRowClick}
          role="row"
          tabIndex={0}
          onKeyDown={(e) => {
            if ((e.key === 'Enter' || e.key === ' ') && onRowClick) {
              e.preventDefault()
              onRowClick()
            }
          }}
        >
          <div className="protocol-row-tabular__name-row">
            <span className="protocol-row-tabular__medicine-name">{item.medicineName}</span>
            {item.concentrationLabel && (
              <span className="protocol-row__dosage">{item.concentrationLabel}</span>
            )}
          </div>
          <div className="protocol-row-tabular__intake">{item.intakeLabel}</div>
          {onDelete && isHovered && (
            <button
              className="protocol-row-tabular__delete-btn"
              onClick={(e) => {
                e.stopPropagation()
                onDelete(item)
              }}
              aria-label={`Excluir tratamento ${item.medicineName}`}
              title="Excluir tratamento"
            >
              <Trash2 size={14} />
            </button>
          )}
        </div>

        {/* CÉLULA 2: Frequência + Horários — S7.5.5: aplicar hover class */}
        <div
          className={`protocol-row-tabular__cell protocol-row-tabular__schedule-cell ${hoverClass}`}
        >
          <div className="protocol-row-tabular__frequency">{item.frequencyLabel}</div>
          {item.timeSchedule.length > 0 && (
            <div className="protocol-row-tabular__times">{item.timeSchedule.join(' / ')}</div>
          )}
        </div>

        {/* CÉLULA 3: Adesão 7d (apenas em aba ativos) — S7.5.5: aplicar hover class */}
        <div
          className={`protocol-row-tabular__cell protocol-row-tabular__adherence-cell ${hoverClass}`}
        >
          {showAdherence && <AdherenceBar7d score={item.adherenceScore7d} />}
        </div>

        {/* CÉLULA 4: Estoque — S7.5.5: aplicar hover class */}
        <div
          className={`protocol-row-tabular__cell protocol-row-tabular__stock-cell ${hoverClass}`}
        >
          <StockPill status={item.stockStatus} daysRemaining={item.daysRemaining} />
        </div>
      </>
    )
  }

  // ────────────────────────────────────────────────────────────────
  // VARIANTE: CARD (Modo Simples)
  // ────────────────────────────────────────────────────────────────
  const canExpand = isComplex && (item.hasTitration || item.notes)

  function handleClick() {
    // Se em modo complexo e tem conteúdo para expandir, expande
    if (canExpand) {
      onToggleExpand()
    } else if (onEdit) {
      // Caso contrário, abre o modal de edição
      onEdit(item)
    }
  }

  return (
    <div className="protocol-row">
      {onDelete && (
        <button
          className="protocol-row__delete-btn"
          onClick={(e) => {
            e.stopPropagation()
            onDelete(item)
          }}
          aria-label={`Excluir tratamento ${item.medicineName}`}
          title="Excluir tratamento"
        >
          <Trash2 size={14} />
        </button>
      )}
      <button
        className="protocol-row__main"
        onClick={handleClick}
        aria-expanded={canExpand ? expanded : undefined}
        style={{ minHeight: '3.5rem' }}
      >
        {/* Linha 1: nome + badge (esq) · stock pill (dir) */}
        <div className="protocol-row__top-row">
          <div className="protocol-row__header">
            <span className="protocol-row__name">{item.medicineName}</span>
            {item.concentrationLabel && (
              <span className="protocol-row__dosage">{item.concentrationLabel}</span>
            )}
          </div>
          <StockPill status={item.stockStatus} daysRemaining={item.daysRemaining} />
        </div>

        {/* Linha 2: quantidade por dose */}
        <div className="protocol-row__intake">{item.intakeLabel}</div>

        {/* Linha 3: frequência/horários (esq) · adesão (dir) */}
        <div className="protocol-row__bottom-row">
          <div className="protocol-row__schedule">
            {item.frequencyLabel}
            {item.timeSchedule.length > 0 && ` · ${item.timeSchedule.join(' / ')}`}
          </div>
          {showAdherence &&
            (isComplex ? (
              <AdherenceBar7d score={item.adherenceScore7d} />
            ) : (
              <AdherenceLabel score={item.adherenceScore7d} />
            ))}
        </div>

        {canExpand && (
          <span className="protocol-row__chevron" aria-hidden="true">
            {expanded ? '▲' : '▼'}
          </span>
        )}
      </button>

      <AnimatePresence initial={false}>
        {expanded && canExpand && (
          <motion.div
            key="expanded"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: 'easeInOut' }}
            className="protocol-row__details"
          >
            {item.hasTitration && <TitrationBadge summary={item.titrationSummary} />}
            {item.notes && <p className="protocol-row__notes">{item.notes}</p>}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

import { useState, useEffect, useCallback, useMemo } from 'react'
import { supabase, getUserId } from '@shared/utils/supabase'
import { adherenceService } from '@services/api/adherenceService'
import { stockService } from '@shared/services'
import { predictRefill } from '@stock/services/refillPredictionService'
import {
  getTitrationSummary,
  isTitrationActive,
  formatDose,
} from '@protocols/services/titrationService'
import { formatLocalDate, getNow } from '@utils/dateUtils'

const FREQUENCY_LABELS = {
  diario: 'Diário',
  diário: 'Diário',
  dias_alternados: 'Dias alternados',
  semanal: 'Semanal',
  personalizado: 'Personalizado',
  quando_necessario: 'Quando necessário',
  quando_necessário: 'Quando necessário',
}

const STOCK_STATUS_COLORS = {
  critical: '#ef4444',
  low: '#f59e0b',
  normal: '#22c55e',
  high: '#3b82f6',
}

/**
 * Derivar status de estoque (critical/low/normal/high) baseado em daysRemaining
 * CRÍTICO: usar Infinity para estoque ilimitado/sem consumo
 */
function getStockStatus(daysRemaining) {
  if (!isFinite(daysRemaining)) return 'high'
  if (daysRemaining < 7) return 'critical'
  if (daysRemaining < 14) return 'low'
  if (daysRemaining < 30) return 'normal'
  return 'high'
}

/**
 * Derivar tabStatus de um protocolo
 * CRÍTICO: usar parseLocalDate() para comparações de data, NUNCA new Date('YYYY-MM-DD')
 */
function resolveTabStatus(protocol) {
  const today = formatLocalDate(getNow())
  if (protocol.end_date && protocol.end_date < today) return 'finalizado'
  if (protocol.active === false) return 'pausado'
  return 'ativo'
}

/**
 * Resolver grupo (groupKey, label, emoji, cor) de um protocolo
 * Prioridade: treatment_plan > therapeutic_class > avulsos
 */
function resolveGroup(protocol) {
  if (protocol.treatment_plan) {
    return {
      groupKey: `plan:${protocol.treatment_plan.id}`,
      groupLabel: protocol.treatment_plan.name,
      groupEmoji: protocol.treatment_plan.emoji || '💊',
      groupColor: protocol.treatment_plan.color || '#6366f1',
    }
  }
  if (protocol.medicine?.therapeutic_class) {
    const slug = protocol.medicine.therapeutic_class.toLowerCase().replace(/\s+/g, '-')
    return {
      groupKey: `class:${slug}`,
      groupLabel: protocol.medicine.therapeutic_class,
      groupEmoji: '💊',
      groupColor: '#6366f1',
    }
  }
  return {
    groupKey: 'avulsos',
    groupLabel: 'Medicamentos Avulsos',
    groupEmoji: '💊',
    groupColor: '#94a3b8',
  }
}

export function useTreatmentList() {
  // Estados
  const [items, setItems] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  // Fetch todos os dados em paralelo
  const fetchAll = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const userId = await getUserId()

      // Query 1: Todos os protocolos (ativos + pausados + finalizados)
      const { data: protocols, error: pErr } = await supabase
        .from('protocols')
        .select('*, medicine:medicines(*), treatment_plan:treatment_plans(id, name, emoji, color)')
        .eq('user_id', userId)
        .order('created_at', { ascending: false })
      if (pErr) throw pErr

      // Query 2: Adesão 7d por protocolo
      // calculateAllProtocolsAdherence retorna Array<{protocolId, name, score}>
      const adherenceList = await adherenceService.calculateAllProtocolsAdherence('7d', userId)
      const adherenceMap = Object.fromEntries(
        (adherenceList || []).map((a) => [a.protocolId, a.score ?? 0])
      )

      // Query 3: Estoque por medicine_id único
      const uniqueMedicineIds = [...new Set(protocols.map((p) => p.medicine_id))]
      const stockSummaries = await Promise.all(
        uniqueMedicineIds.map((id) => stockService.getStockSummary(id))
      )
      const stockMap = Object.fromEntries(
        stockSummaries.map((s) => [s.medicine_id, s.total_quantity || 0])
      )

      // Montar TreatmentItem[]
      const allItems = protocols.map((p) => {
        const groupInfo = resolveGroup(p)
        const tabStatus = resolveTabStatus(p)
        const totalStock = stockMap[p.medicine_id] ?? 0
        const titSummary = getTitrationSummary(p)
        const hasTitration = isTitrationActive(p)

        // Calcular daysRemaining via predictRefill (sem logs neste hook — usa cálculo teórico)
        const { daysRemaining } = predictRefill({
          medicineId: p.medicine_id,
          currentStock: totalStock,
          logs: [],
          protocols: [p],
        })

        const dosageLabel = formatDose(
          p.dosage_per_intake,
          p.medicine?.dosage_unit || 'mg',
          p.medicine?.dosage_per_pill
        )
        // Concentração do comprimido: badge (ex: "500mg") — null se não disponível
        const concentrationLabel =
          p.medicine?.dosage_per_pill && p.medicine?.dosage_unit
            ? `${p.medicine.dosage_per_pill}${p.medicine.dosage_unit}`
            : null
        // Quantidade por dose: texto (ex: "1 comprimido") — consistente com dashboard
        const n = p.dosage_per_intake ?? 1
        const intakeLabel = `${n} comprimido${n !== 1 ? 's' : ''}`

        // Próxima dose não-registrada (simplificado — comparar timeSchedule com hora atual)
        const now = getNow()
        const currentHHMM = `${String(now.getHours()).padStart(2, '0')}:${String(
          now.getMinutes()
        ).padStart(2, '0')}`
        const times = Array.isArray(p.time_schedule) ? p.time_schedule : []
        const nextDoseTime = times.find((t) => t > currentHHMM) || null

        return {
          id: p.id,
          medicineId: p.medicine_id,
          medicineName: p.medicine?.name || p.name,
          medicineType: p.medicine?.type || 'medicamento',
          dosageLabel,
          concentrationLabel,
          intakeLabel,
          frequency: p.frequency,
          frequencyLabel: FREQUENCY_LABELS[p.frequency] || p.frequency,
          timeSchedule: times,
          nextDoseTime,
          isRegisteredToday: false,
          stockStatus: getStockStatus(daysRemaining),
          daysRemaining,
          adherenceScore7d: adherenceMap[p.id] ?? 0,
          hasTitration,
          titrationSummary: titSummary,
          notes: p.notes || null,
          treatmentPlanId: p.treatment_plan?.id || null,
          treatmentPlanName: p.treatment_plan?.name || null,
          treatmentPlanEmoji: p.treatment_plan?.emoji || '💊',
          treatmentPlanColor: p.treatment_plan?.color || '#6366f1',
          therapeuticClass: p.medicine?.therapeutic_class || null,
          ...groupInfo,
          active: p.active,
          endDate: p.end_date || null,
          tabStatus,
        }
      })

      setItems(allItems)
    } catch (err) {
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchAll()
  }, [fetchAll])

  // Derived states por tab
  const activeItems = useMemo(() => items.filter((i) => i.tabStatus === 'ativo'), [items])
  const pausedItems = useMemo(() => items.filter((i) => i.tabStatus === 'pausado'), [items])
  const finishedItems = useMemo(() => items.filter((i) => i.tabStatus === 'finalizado'), [items])

  // Helper para computar grupos de qualquer lista de itens
  // Ordena: planos reais primeiro (com lápis de edição), depois classes terapêuticas
  const computeGroups = (itemList) => {
    const map = new Map()
    for (const item of itemList) {
      if (!map.has(item.groupKey)) {
        map.set(item.groupKey, {
          groupKey: item.groupKey,
          groupLabel: item.groupLabel,
          groupEmoji: item.groupEmoji,
          groupColor: item.groupColor,
          items: [],
          hasAlert: false,
          isPlan: item.groupKey.startsWith('plan:'), // S7.5.5: detectar se é plano real
        })
      }
      const g = map.get(item.groupKey)
      g.items.push(item)
      if (item.stockStatus === 'critical' || item.stockStatus === 'low') g.hasAlert = true
    }
    // Separar planos reais (com lápis) vs classes terapêuticas (sem lápis)
    const groups = Array.from(map.values())
    const realPlans = groups.filter((g) => g.isPlan)
    const therapeuticClasses = groups.filter((g) => !g.isPlan)
    // Retornar planos reais primeiro, depois classes terapêuticas
    return [...realPlans, ...therapeuticClasses]
  }

  // Grupos para modo complexo (por tab)
  const activeGroups = useMemo(() => computeGroups(activeItems), [activeItems])
  const pausedGroups = useMemo(() => computeGroups(pausedItems), [pausedItems])
  const finishedGroups = useMemo(() => computeGroups(finishedItems), [finishedItems])

  return {
    items,
    activeItems,
    pausedItems,
    finishedItems,
    activeGroups,
    pausedGroups,
    finishedGroups,
    loading,
    error,
    refetch: fetchAll,
  }
}

import { AnalyzeReminderTimingInputSchema } from '@schemas/reminderOptimizerSchema'
import { getNow, parseISO } from '@utils/dateUtils'

/**
 * Analisa delta entre horário programado e horário real de tomada.
 * Se o paciente consistentemente toma em horário diferente, sugere ajuste.
 *
 * @param {Object} params
 * @param {Object} params.protocol - Protocolo com time_schedule
 * @param {Array} params.logs - Logs de dose para este protocolo
 * @returns {{
 *   shouldSuggest: boolean,
 *   currentTime: string,       // HH:MM programado
 *   suggestedTime: string,     // HH:MM sugerido
 *   avgDeltaMinutes: number,   // Delta médio em minutos
 *   sampleCount: number,       // Quantas amostras usadas
 *   direction: 'later'|'earlier'
 * } | null}
 */
export function analyzeReminderTiming({ protocol, logs }) {
  // Validação obrigatória com Zod
  const validationResult = AnalyzeReminderTimingInputSchema.safeParse({
    protocol,
    logs,
  })

  if (!validationResult.success) {
    // R-087: Structured Logging para debugging
    const issues = validationResult.error.issues
    const fieldErrors = issues.reduce((acc, issue) => {
      const path = issue.path.join('.')
      if (!acc[path]) acc[path] = []
      acc[path].push({ code: issue.code, message: issue.message })
      return acc
    }, {})

    console.error('[reminderOptimizerService] Validation failed:', {
      timestamp: getNow().toISOString(),
      context: 'analyzeReminderTiming',
      protocol_id: protocol?.id,
      logs_count: logs?.length,
      error_by_field: fieldErrors,
      first_log_sample: logs?.[0],
      first_issue_details: issues[0],
    })
    return null
  }

  const { protocol: validProtocol, logs: validLogs } = validationResult.data

  // Guardar clauses: sem time_schedule ou frequency inválida
  if (!validProtocol.time_schedule || validProtocol.time_schedule.length === 0) {
    return null
  }

  if (validProtocol.frequency === 'quando_necessario') {
    return null
  }

  // Otimização: Pré-processa os logs uma única vez para evitar parsing repetido
  const processedLogs = validLogs
    .map((log) => {
      const logDate = parseISO(log.taken_at)
      if (isNaN(logDate.getTime())) return null // Ignora datas inválidas
      return {
        ...log,
        logMinutes: logDate.getHours() * 60 + logDate.getMinutes(),
      }
    })
    .filter(Boolean)

  const suggestions = []

  // Analisar cada horário programado
  for (const scheduledTime of validProtocol.time_schedule) {
    const [scheduledH, scheduledM] = scheduledTime.split(':').map(Number)
    const scheduledMinutes = scheduledH * 60 + scheduledM

    // Filtrar logs relevantes para este horário (dentro de 4h window)
    const relevantLogs = processedLogs.filter((log) => {
      // Apenas logs que correspondem ao ID do protocolo, ou que não têm ID de protocolo mas correspondem ao ID do medicamento.
      const isMatch =
        log.protocol_id === validProtocol.id ||
        (log.protocol_id == null && log.medicine_id === validProtocol.medicine_id)

      if (!isMatch) {
        return false
      }

      const delta = Math.abs(log.logMinutes - scheduledMinutes)
      return delta < 240 // Dentro de 4h do horário programado
    })

    // Amostras insuficientes (< 10)
    if (relevantLogs.length < 10) {
      continue
    }

    // Calcular delta médio
    const deltas = relevantLogs.map((log) => log.logMinutes - scheduledMinutes)

    const avgDelta = deltas.reduce((sum, d) => sum + d, 0) / deltas.length

    // Sugerir apenas se |avgDelta| > 30 minutos
    if (Math.abs(avgDelta) <= 30) {
      continue
    }

    // Arredondar para 15 minutos
    const suggestedMinutes = scheduledMinutes + Math.round(avgDelta / 15) * 15
    const suggestedH = Math.floor(suggestedMinutes / 60) % 24
    const suggestedM = suggestedMinutes % 60
    const suggestedTime = `${String(suggestedH).padStart(2, '0')}:${String(suggestedM).padStart(2, '0')}`

    suggestions.push({
      shouldSuggest: true,
      currentTime: scheduledTime,
      suggestedTime,
      avgDeltaMinutes: Math.round(avgDelta),
      sampleCount: relevantLogs.length,
      direction: avgDelta > 0 ? 'later' : 'earlier',
    })
  }

  return suggestions.length > 0 ? suggestions[0] : null // Uma sugestão por vez
}

/**
 * Verifica se a sugestão já foi dispensada pelo usuário.
 * @param {string} protocolId
 * @returns {boolean}
 */
export function isSuggestionDismissed(protocolId) {
  // Guard clause: ambiente server-side sem window (AP-T03)
  if (typeof window === 'undefined') {
    return true
  }
  // Guard clause: localStorage indisponivel em ambiente de teste/SSR (AP-T03)
  if (typeof localStorage === 'undefined' || typeof localStorage.getItem !== 'function') {
    return false
  }

  const key = `optimizer_dismissed_${protocolId}`
  const dismissed = localStorage.getItem(key)

  if (!dismissed) {
    return false
  }

  try {
    const { timestamp, permanent } = JSON.parse(dismissed)

    if (permanent) {
      return true
    }

    // Dispensado por 30 dias
    const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000
    return getNow().getTime() - timestamp < thirtyDaysMs
  } catch (error) {
    console.error('[reminderOptimizerService] Error parsing dismissed suggestion:', error)
    return true
  }
}

/**
 * Registra dispensa da sugestão.
 * @param {string} protocolId
 * @param {boolean} permanent - Se true, nunca mais sugerir
 */
export function dismissSuggestion(protocolId, permanent = false) {
  // Guard clause: ambiente não-browser ou localStorage indisponivel (AP-T03)
  if (
    typeof window === 'undefined' ||
    typeof localStorage === 'undefined' ||
    typeof localStorage.setItem !== 'function'
  ) {
    console.warn('[reminderOptimizerService] dismissSuggestion called in non-browser environment')
    return
  }

  const key = `optimizer_dismissed_${protocolId}`
  const value = JSON.stringify({
    timestamp: getNow().getTime(),
    permanent,
  })

  try {
    localStorage.setItem(key, value)
    console.log('[reminderOptimizerService] Suggestion dismissed:', {
      protocolId,
      key,
      permanent,
      timestamp: getNow().toISOString(),
      storageSize: Object.keys(localStorage).length,
    })
  } catch (error) {
    console.error('[reminderOptimizerService] Failed to dismiss suggestion:', {
      protocolId,
      key,
      error: error.message,
      timestamp: getNow().toISOString(),
    })
  }
}

/**
 * @fileoverview Componente de geração do resumo clínico em PDF.
 * Usa o pipeline dedicado do Modo Consulta Médica para todos os entrypoints.
 * @module features/reports/components/ReportGenerator
 */

import { useState, useCallback, useEffect, useMemo } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { supabase } from '@shared/utils/supabase'
import { cachedAdherenceService } from '@shared/services/cachedServices'
import { getConsultationData } from '@features/consultation/services/consultationDataService'
import { generateConsultationPDF } from '@/features/reports/services/consultationPdfService.js'
import { shareReport, shareNative, copyToClipboard } from '@/features/reports/services/shareService'
import { analyticsService } from '@dashboard/services/analyticsService'
import Button from '@shared/components/ui/Button'
import { getNow, formatLocalDate } from '@utils/dateUtils.js'
import './ReportGenerator.css'

/**
 * Opções de período para o relatório.
 * @constant {Array<{value: string, label: string}>}
 */
const PERIOD_OPTIONS = [
  { value: '7d', label: 'Últimos 7 dias' },
  { value: '30d', label: 'Últimos 30 dias' },
  { value: '90d', label: 'Últimos 90 dias' },
  { value: 'all', label: 'Todo o período' },
]

function getPeriodLabel(selectedPeriod) {
  return PERIOD_OPTIONS.find((opt) => opt.value === selectedPeriod)?.label || selectedPeriod
}

function buildConsultationReportFilename(selectedPeriod) {
  const periodLabel = getPeriodLabel(selectedPeriod)
  return `dosiq-consulta-medica-${periodLabel.replace(/\s+/g, '-')}-${formatDateForFilename()}.pdf`
}

/**
 * Formata a data atual para o nome do arquivo.
 * @returns {string} Data formatada como YYYY-MM-DD.
 */
function formatDateForFilename() {
  return formatLocalDate(getNow())
}

/**
 * Dispara o download de um Blob como arquivo.
 * @param {Blob} blob - Blob a ser baixado.
 * @param {string} filename - Nome do arquivo.
 */
function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob)
  const link = document.createElement('a')
  link.href = url
  link.download = filename
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
  URL.revokeObjectURL(url)
}

/**
 * Componente de geração de relatórios PDF.
 *
 * @param {Object} props - Propriedades do componente.
 * @returns {JSX.Element} Componente de geração de relatórios.
 *
 * @example
 * // Uso básico
 * <ReportGenerator />
 *
 * // Com callback de fechamento
 * <ReportGenerator onClose={() => setIsModalOpen(false)} />
 */
export default function ReportGenerator() {
  // 1. States (R-010: Hook order)
  const [patientName, setPatientName] = useState('')
  const [patientEmail, setPatientEmail] = useState('')
  const [period, setPeriod] = useState('30d')
  const [isGenerating, setIsGenerating] = useState(false)
  const [error, setError] = useState(null)
  const [pdfBlob, setPdfBlob] = useState(null)

  // Estados para compartilhamento
  const [shareLoading, setShareLoading] = useState(false)
  const [shareUrl, setShareUrl] = useState(null)
  const [shareError, setShareError] = useState(null)
  const [copied, setCopied] = useState(false)

  const { medicines, protocols, logs, stockSummary, stats, dailyAdherence } = useDashboard()

  const resolvePeriodDays = useCallback((selectedPeriod) => {
    const periodMap = {
      '7d': 7,
      '30d': 30,
      '90d': 90,
      all: 90,
    }

    return periodMap[selectedPeriod] || 30
  }, [])

  const dashboardData = useMemo(
    () => ({
      medicines,
      protocols,
      logs,
      stockSummary,
      stats,
      dailyAdherence,
    }),
    [medicines, protocols, logs, stockSummary, stats, dailyAdherence]
  )

  const consultationData = useMemo(
    () => getConsultationData(dashboardData, patientName, null, patientEmail),
    [dashboardData, patientEmail, patientName]
  )

  useEffect(() => {
    let isMounted = true

    const loadPatientProfile = async () => {
      try {
        const {
          data: { user },
        } = await supabase.auth.getUser()

        if (!isMounted) return
        setPatientName(user?.user_metadata?.name || user?.user_metadata?.full_name || '')
        setPatientEmail(user?.email || '')
      } catch (err) {
        console.error('Erro ao carregar perfil para relatório clínico:', err)
      }
    }

    loadPatientProfile()

    return () => {
      isMounted = false
    }
  }, [])

  // 2. Handlers (R-010: States -> Memos -> Effects -> Handlers)
  /**
   * Manipula a geração do relatório PDF.
   * @async
   */
  const handleGenerate = useCallback(async () => {
    setIsGenerating(true)
    setError(null)
    setPdfBlob(null)
    setShareUrl(null)
    setShareError(null)

    try {
      const periodDays = resolvePeriodDays(period)
      const resolvedDailyAdherence =
        periodDays <= 7
          ? dailyAdherence || []
          : await cachedAdherenceService.getDailyAdherenceFromView(periodDays)

      const blob = await generateConsultationPDF({
        consultationData,
        dashboardData: {
          ...dashboardData,
          dailyAdherence: resolvedDailyAdherence,
        },
        period,
        title: 'Dosiq - Consulta Médica',
      })
      setPdfBlob(blob)

      // Track analytics event
      analyticsService.track('report_generated', {
        period,
        fileSize: blob.size,
        fileType: 'pdf',
        reportType: 'consultation_clinical_pdf',
      })
    } catch (err) {
      console.error('Erro ao gerar relatório:', err)
      setError('Erro ao gerar relatório. Tente novamente.')
      analyticsService.track('report_generation_error', {
        period,
        error: err.message,
      })
    } finally {
      setIsGenerating(false)
    }
  }, [consultationData, dailyAdherence, dashboardData, period, resolvePeriodDays])

  /**
   * Manipula o download do PDF gerado.
   */
  const handleDownload = useCallback(() => {
    if (!pdfBlob) return

    const filename = buildConsultationReportFilename(period)

    downloadBlob(pdfBlob, filename)

    analyticsService.track('report_downloaded', {
      period,
      filename,
      fileSize: pdfBlob.size,
      reportType: 'consultation_clinical_pdf',
    })
  }, [pdfBlob, period])

  /**
   * Manipula o compartilhamento do relatório.
   * @async
   */
  const handleShare = useCallback(async () => {
    if (!pdfBlob) return

    setShareLoading(true)
    setShareError(null)
    setShareUrl(null)
    setCopied(false)

    try {
      const filename = buildConsultationReportFilename(period)

      const result = await shareReport(pdfBlob, { filename, expiresInHours: 72 })
      setShareUrl(result.url)

      // Tentar compartilhamento nativo em dispositivos móveis
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
        navigator.userAgent
      )
      if (isMobile) {
        try {
          await shareNative(result.url, 'Resumo Clínico de Consulta')
        } catch {
          // Fallback silencioso - usuário verá o link copiável
        }
      }

      analyticsService.track('report_shared', {
        period,
        filename,
        expiresInHours: 72,
        reportType: 'consultation_clinical_pdf',
      })
    } catch (err) {
      console.error('Erro ao compartilhar relatório:', err)
      setShareError(err.message || 'Erro ao compartilhar relatório. Tente novamente.')
      analyticsService.track('report_share_error', {
        period,
        error: err.message,
      })
    } finally {
      setShareLoading(false)
    }
  }, [pdfBlob, period])

  /**
   * Manipula a cópia do link para a área de transferência.
   * @async
   */
  const handleCopyLink = useCallback(async () => {
    if (!shareUrl) return

    try {
      await copyToClipboard(shareUrl)
      setCopied(true)

      analyticsService.track('report_share_link_copied', { period })

      // Resetar estado de copiado após 3 segundos
      setTimeout(() => setCopied(false), 3000)
    } catch (err) {
      console.error('Erro ao copiar link:', err)
      setShareError('Não foi possível copiar o link. Copie manualmente.')
    }
  }, [shareUrl, period])

  return (
    <div className="report-generator">
      <div className="report-generator__hero">
        <div className="report-generator__hero-copy">
          <p className="report-generator__eyebrow">PDF clínico</p>
          <div className="report-generator__header">
            <h3 className="report-generator__title">Gerar Resumo Clínico</h3>
          </div>
          <p className="report-generator__description">
            Um PDF único, legível em consulta e pronto para compartilhar com o médico.
          </p>
        </div>
        <div className="report-generator__hero-badge">
          <span>Resumo</span>
          <strong>Clínico</strong>
        </div>
      </div>

      <div className="report-generator__content">
        <section className="report-generator__panel">
          <label className="report-generator__label" htmlFor="report-period">
            Período
          </label>
          <select
            id="report-period"
            className="report-generator__select"
            value={period}
            onChange={(e) => setPeriod(e.target.value)}
            disabled={isGenerating}
          >
            {PERIOD_OPTIONS.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
          <p className="report-generator__helper">
            O intervalo define a janela de adesão exibida no resumo principal.
          </p>
        </section>

        <section className="report-generator__panel report-generator__panel--soft">
          <label className="report-generator__label">Inclui no PDF</label>
          <div className="report-generator__chips">
            <span className="report-generator__chip">Tratamentos</span>
            <span className="report-generator__chip">Adesão</span>
            <span className="report-generator__chip">Estoque</span>
            <span className="report-generator__chip">Prescrições</span>
            <span className="report-generator__chip">Titulação</span>
          </div>
          <p className="report-generator__helper">
            O relatório clínico prioriza leitura rápida, com blocos curtos e gráficos legíveis.
          </p>
        </section>
      </div>

      {error && (
        <div className="report-generator__error" role="alert">
          {error}
        </div>
      )}

      {shareError && (
        <div className="report-generator__error" role="alert">
          {shareError}
        </div>
      )}

      <div className="report-generator__actions">
        {!pdfBlob ? (
          <Button
            className="report-generator__button report-generator__button--generate"
            onClick={handleGenerate}
            disabled={isGenerating}
            variant="primary"
          >
            {isGenerating ? (
              <>
                <span className="report-generator__spinner" />
                Gerando...
              </>
            ) : (
              'Gerar PDF Clínico'
            )}
          </Button>
        ) : (
          <div className="report-generator__success">
            <div className="report-generator__success-message">
              Resumo clínico gerado com sucesso!
            </div>
            <div className="report-generator__success-actions">
              <Button
                className="report-generator__button report-generator__button--download"
                onClick={handleDownload}
                variant="primary"
              >
                Baixar PDF
              </Button>
              <Button
                className="report-generator__button report-generator__button--share"
                onClick={handleShare}
                disabled={shareLoading}
                variant="secondary"
              >
                {shareLoading ? (
                  <>
                    <span className="report-generator__spinner" />
                    Enviando...
                  </>
                ) : (
                  'Compartilhar'
                )}
              </Button>
              <Button
                className="report-generator__button report-generator__button--regenerate"
                onClick={handleGenerate}
                disabled={isGenerating}
                variant="outline"
              >
                {isGenerating ? (
                  <>
                    <span className="report-generator__spinner" />
                    Gerando...
                  </>
                ) : (
                  'Gerar Novo'
                )}
              </Button>
            </div>
          </div>
        )}
      </div>

      {/* Seção de link de compartilhamento */}
      {shareUrl && !shareLoading && (
        <div className="report-generator__share-result">
          <div className="report-generator__share-url-container">
            <input
              type="text"
              className="report-generator__share-url-input"
              value={shareUrl}
              readOnly
              aria-label="Link de compartilhamento"
            />
            <Button
              className="report-generator__copy-button"
              onClick={handleCopyLink}
              variant={copied ? 'success' : 'secondary'}
              size="small"
            >
              {copied ? 'Copiado!' : 'Copiar'}
            </Button>
          </div>
          <p className="report-generator__share-expiry">Link válido por 72 horas</p>
        </div>
      )}

      {isGenerating && (
        <div className="report-generator__loading">
          <div className="report-generator__loading-bar">
            <div className="report-generator__loading-progress" />
          </div>
          <p className="report-generator__loading-text">Preparando seu relatório, aguarde...</p>
        </div>
      )}
    </div>
  )
}

/**
 * @fileoverview Monta os dados normalizados do PDF de consulta medica.
 * Converte o estado clinico da app em um modelo editorial pronto para renderizacao.
 * @module features/reports/services/consultationPdfDataBuilder
 */

import { addDays, formatLocalDate, parseLocalDate, parseISO, getNow } from '@utils/dateUtils.js'
import { extractEmailHandle, formatPatientDisplayName } from '@shared/utils/patientUtils'
import { calculateDailyIntake, calculateDosesByDate } from '@utils/adherenceLogic'

/**
 * Formata um numero com fallback legivel.
 * @param {number|string|null|undefined} value - Valor a formatar.
 * @param {string} fallback - Texto exibido quando nao ha valor.
 * @returns {string} Texto formatado.
 */
function safeText(value, fallback = '-') {
  if (value === null || value === undefined || value === '') return fallback
  return String(value)
}

function getTrendLabel(days) {
  if (days >= 90) return '90 dias'
  if (days >= 30) return '30 dias'
  if (days >= 7) return '7 dias'
  return `${days} dias`
}

function summarizeTrend(trend = [], fallbackCurrentStreak = 0) {
  const totals = trend.reduce(
    (accumulator, row) => ({
      taken: accumulator.taken + Number(row.taken ?? 0),
      expected: accumulator.expected + Number(row.expected ?? 0),
    }),
    { taken: 0, expected: 0 }
  )

  const score = totals.expected > 0 ? Math.round((totals.taken / totals.expected) * 100) : 0

  return {
    score,
    taken: totals.taken,
    expected: totals.expected,
    punctuality: score,
    currentStreak: fallbackCurrentStreak,
  }
}

/**
 * Retorna o nome clinico do tratamento.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento associado.
 * @returns {string} Label no formato `[tratamento] - [medicacao]`.
 */
export function formatTreatmentLabel(protocol, medicine) {
  const treatmentName = protocol?.name || protocol?.treatment_name || protocol?.medicine_name
  const medicineName = medicine?.name || protocol?.medicine?.name || protocol?.medicine_name

  if (treatmentName && medicineName) {
    return `${treatmentName} - ${medicineName}`
  }

  return treatmentName || medicineName || 'Tratamento sem nome'
}

/**
 * Formata a apresentacao do medicamento.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto de apresentacao.
 */
export function formatMedicinePresentation(medicine) {
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    return 'Apresentacao nao cadastrada'
  }

  return `${dosagePerPill} ${dosageUnit} por comprimido`
}

/**
 * Formata a dose por tomada.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto da dose por tomada.
 */
export function formatIntakeDose(protocol, medicine) {
  const pillsPerIntake = protocol?.dosage_per_intake ?? 1
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'
  const pillLabel = pillsPerIntake === 1 ? 'comprimido' : 'comprimidos'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    return `${pillsPerIntake} ${pillLabel}`
  }

  const intakeAmount = pillsPerIntake * dosagePerPill
  return `${pillsPerIntake} ${pillLabel} (${intakeAmount} ${dosageUnit})`
}

/**
 * Formata a frequencia em linguagem clinica curta.
 * @param {Object} protocol - Protocolo ativo.
 * @returns {string} Texto da frequencia.
 */
export function formatFrequency(protocol) {
  const schedule = Array.isArray(protocol?.time_schedule) ? protocol.time_schedule : []
  if (schedule.length === 0) return '1x/dia'

  const schedulePreview = schedule.slice(0, 3).join(', ')
  const suffix = schedule.length > 3 ? '...' : ''
  return `${schedule.length}x/dia${schedulePreview ? ` • ${schedulePreview}${suffix}` : ''}`
}

/**
 * Formata a dose diaria total.
 * @param {Object} protocol - Protocolo ativo.
 * @param {Object} medicine - Medicamento cadastrado.
 * @returns {string} Texto da dose diaria.
 */
export function formatDailyDose(protocol, medicine) {
  const pillsPerIntake = protocol?.dosage_per_intake ?? 1
  const timesPerDay =
    Array.isArray(protocol?.time_schedule) && protocol.time_schedule.length > 0
      ? protocol.time_schedule.length
      : 1
  const dosagePerPill = medicine?.dosage_per_pill
  const dosageUnit = medicine?.dosage_unit || 'mg'

  if (dosagePerPill === null || dosagePerPill === undefined) {
    const pillsPerDay = pillsPerIntake * timesPerDay
    const pillLabel = pillsPerDay === 1 ? 'comprimido/dia' : 'comprimidos/dia'
    return `${pillsPerDay} ${pillLabel}`
  }

  const totalDosage = pillsPerIntake * timesPerDay * dosagePerPill
  return `${totalDosage} ${dosageUnit}/dia`
}

/**
 * Calcula a severidade de estoque.
 * @param {Object} stockItem - Resumo de estoque.
 * @returns {string} critical|warning|stable
 */
function getStockSeverity(stockItem) {
  if (!stockItem) return 'stable'
  if (stockItem.isZero || (stockItem.daysRemaining !== null && stockItem.daysRemaining <= 0)) {
    return 'critical'
  }
  if (stockItem.isLow || (stockItem.daysRemaining !== null && stockItem.daysRemaining < 7)) {
    return 'warning'
  }
  return 'stable'
}

/**
 * Gera rows de tratamentos para a tabela principal.
 * @param {Array<Object>} protocols - Protocolos do paciente.
 * @param {Array<Object>} medicines - Medicamentos do paciente.
 * @returns {Array<Object>} Rows prontos para renderizacao.
 */
function buildTreatmentRows(protocols = [], medicines = []) {
  return protocols
    .filter((protocol) => protocol?.active !== false)
    .map((protocol) => {
      const medicine =
        medicines.find((item) => item.id === protocol.medicine_id) || protocol.medicine || {}
      const timesPerDay =
        Array.isArray(protocol.time_schedule) && protocol.time_schedule.length > 0
          ? protocol.time_schedule.length
          : 1
      const dosagePerPill = medicine.dosage_per_pill ?? null
      const dosagePerIntake =
        dosagePerPill === null ? null : (protocol.dosage_per_intake ?? 1) * dosagePerPill

      return {
        id: protocol.id,
        label: formatTreatmentLabel(protocol, medicine),
        presentation: formatMedicinePresentation(medicine),
        dosePerIntake: formatIntakeDose(protocol, medicine),
        frequency: formatFrequency(protocol),
        dailyDose: formatDailyDose(protocol, medicine),
        status: 'Ativo',
        note: protocol.titration_schedule?.length
          ? 'Em titulacao'
          : safeText(medicine.notes, 'Sem observacoes'),
        timesPerDay,
        dosagePerIntake,
      }
    })
    .sort((a, b) => a.label.localeCompare(b.label, 'pt-BR'))
}

/**
 * Gera rows de estoque ordenados por urgencia.
 * @param {Array<Object>} stockSummary - Sumario de estoque vindo do dashboard.
 * @param {Array<Object>} protocols - Protocolos ativos.
 * @param {Array<Object>} medicines - Medicamentos cadastrados.
 * @returns {Array<Object>} Rows do estoque.
 */
function buildStockRows(stockSummary = [], protocols = [], medicines = []) {
  return stockSummary
    .map((stockItem) => {
      const medicine =
        medicines.find((item) => item.id === stockItem?.medicine?.id) || stockItem?.medicine || {}
      const protocol = protocols.find(
        (item) => item.medicine_id === medicine.id && item.active !== false
      )
      const dailyIntake = stockItem?.dailyIntake ?? calculateDailyIntake(medicine.id, protocols)
      const totalQuantity = stockItem?.total ?? 0
      const daysRemaining =
        stockItem?.daysRemaining ??
        (dailyIntake > 0 ? Math.floor(totalQuantity / dailyIntake) : null)
      const severity = getStockSeverity({ ...stockItem, daysRemaining })

      return {
        id: medicine.id || stockItem?.medicine?.id || stockItem?.medicine_id || crypto.randomUUID(),
        label: formatTreatmentLabel(protocol, medicine),
        medicineName: safeText(medicine.name, 'Desconhecido'),
        totalQuantity,
        dailyIntake,
        daysRemaining,
        severity,
        message: stockItem?.isZero
          ? 'Estoque esgotado'
          : stockItem?.isLow
            ? 'Estoque baixo'
            : 'Estoque monitorado',
      }
    })
    .sort((a, b) => {
      const severityOrder = { critical: 0, warning: 1, stable: 2 }
      const severityDiff = severityOrder[a.severity] - severityOrder[b.severity]
      if (severityDiff !== 0) return severityDiff
      const aDays = a.daysRemaining ?? Number.POSITIVE_INFINITY
      const bDays = b.daysRemaining ?? Number.POSITIVE_INFINITY
      return aDays - bDays
    })
}

/**
 * Gera rows de prescricao.
 * @param {Array<Object>} prescriptionStatus - Status das prescricoes.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {Array<Object>} medicines - Medicamentos.
 * @returns {Array<Object>} Rows das prescricoes.
 */
function buildPrescriptionRows(prescriptionStatus = [], protocols = [], medicines = []) {
  return prescriptionStatus.map((prescription) => {
    const protocol = protocols.find((item) => item.id === prescription.protocolId)
    const medicine =
      medicines.find((item) => item.id === protocol?.medicine_id) || protocol?.medicine || {}

    return {
      id: prescription.protocolId,
      label: formatTreatmentLabel(protocol, medicine),
      status: prescription.status,
      statusLabel:
        prescription.status === 'vencida'
          ? 'Vencida'
          : prescription.status === 'vencendo'
            ? 'Vencendo'
            : 'Vigente',
      daysRemaining: prescription.daysRemaining,
      endDate: prescription.endDate || protocol?.end_date || null,
    }
  })
}

/**
 * Gera rows de titulacao.
 * @param {Array<Object>} activeTitrations - Titulacoes ativas.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {Array<Object>} medicines - Medicamentos.
 * @returns {Array<Object>} Rows da titulacao.
 */
function buildTitrationRows(activeTitrations = [], protocols = [], medicines = []) {
  return activeTitrations.map((titration) => {
    const protocol = protocols.find((item) => item.id === titration.protocolId)
    const medicine =
      medicines.find((item) => item.id === titration.medicineId) || protocol?.medicine || {}

    return {
      id: titration.protocolId,
      label: formatTreatmentLabel(protocol, medicine),
      currentStep: titration.currentStep,
      totalSteps: titration.totalSteps,
      currentDosage: titration.currentDosage,
      progressPercent: titration.progressPercent,
      daysRemaining: titration.daysRemaining,
      isTransitionDue: titration.isTransitionDue,
      stageNote: safeText(titration.stageNote, 'Sem observacoes'),
    }
  })
}

/**
 * Gera uma trilha sintetica de adesao dos ultimos dias.
 * @param {Array<Object>} dailyAdherence - Série diária já consolidada pelo dashboard.
 * @param {Array<Object>} logs - Logs de dose.
 * @param {Array<Object>} protocols - Protocolos.
 * @param {number} days - Numero de dias a incluir.
 * @returns {Array<Object>} Rows com a adesao diaria.
 */
function buildAdherenceTrend(dailyAdherence = [], logs = [], protocols = [], days = 7) {
  if (Array.isArray(dailyAdherence) && dailyAdherence.length > 0) {
    return dailyAdherence.slice(-days).map((row) => {
      const taken = Number(row.taken ?? 0)
      const expected = Number(row.expected ?? 0)
      const score = expected > 0 ? Math.round((taken / expected) * 100) : null

      return {
        date: row.date,
        label: row.date
          ? parseLocalDate(row.date).toLocaleDateString('pt-BR', {
              day: '2-digit',
              month: '2-digit',
              timeZone: 'America/Sao_Paulo',
            })
          : row.label || '',
        taken,
        expected,
        score,
        status:
          expected === 0
            ? 'Sem doses'
            : score >= 90
              ? 'Excelente'
              : score >= 70
                ? 'Atenção'
                : 'Critico',
      }
    })
  }

  const activeProtocols = protocols.filter((protocol) => protocol?.active !== false)
  const trend = []

  for (let offset = days - 1; offset >= 0; offset -= 1) {
    const date = addDays(getNow(), -offset)
    const dateStr = formatLocalDate(date)
    const result = calculateDosesByDate(dateStr, logs, activeProtocols)
    const taken = result.takenDoses.length
    const missed = result.missedDoses.length
    const expected = taken + missed
    const score = expected > 0 ? Math.round((taken / expected) * 100) : null

    trend.push({
      date: dateStr,
      label: parseLocalDate(dateStr).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        timeZone: 'America/Sao_Paulo',
      }),
      taken,
      expected,
      score,
      status:
        expected === 0
          ? 'Sem doses'
          : score >= 90
            ? 'Excelente'
            : score >= 70
              ? 'Atenção'
              : 'Critico',
    })
  }

  return trend
}

/**
 * Monta os dados normalizados para renderizacao do PDF.
 * @param {Object} params - Parametros agregados.
 * @param {Object} params.consultationData - Dados consolidados do modo consulta.
 * @param {Object} params.dashboardData - Dados brutos do dashboard.
 * @param {string} [params.period='30d'] - Periodo de cobertura.
 * @param {Date|string} [params.generatedAt=getNow()] - Momento de geracao.
 * @param {string} [params.title] - Titulo do documento.
 * @returns {Object} Modelo editorial pronto para o service de PDF.
 */
export function buildConsultationPdfData({
  consultationData,
  dashboardData = {},
  period = '30d',
  generatedAt = getNow(),
  title = 'Dosiq - Consulta Médica',
  patientEmail = '',
} = {}) {
  const medicines = dashboardData.medicines || []
  const protocols = dashboardData.protocols || []
  const logs = dashboardData.logs || []
  const dailyAdherence = dashboardData.dailyAdherence || []
  const stockSummary = dashboardData.stockSummary || []
  const patientInfo = consultationData?.patientInfo || {}
  const activeMedicines = consultationData?.activeMedicines || []
  const periodDays =
    period === 'all'
      ? Math.max(dailyAdherence.length || 0, 90)
      : Math.max(parseInt(period, 10) || 7, 1)
  const activeTreatments = buildTreatmentRows(protocols, medicines)
  const stockRows = buildStockRows(stockSummary, protocols, medicines)
  const prescriptionRows = buildPrescriptionRows(
    consultationData?.prescriptionStatus || [],
    protocols,
    medicines
  )
  const titrationRows = buildTitrationRows(
    consultationData?.activeTitrations || [],
    protocols,
    medicines
  )
  const adherenceTrend = buildAdherenceTrend(dailyAdherence, logs, protocols, periodDays)

  const adherence30d = consultationData?.adherenceSummary?.last30d || {
    score: 0,
    taken: 0,
    expected: 0,
    punctuality: 0,
  }
  const adherence90d = consultationData?.adherenceSummary?.last90d || {
    score: 0,
    taken: 0,
    expected: 0,
    punctuality: 0,
  }
  const selectedPeriodLabel = getTrendLabel(periodDays)
  const selectedPeriodSummary =
    periodDays === 30
      ? adherence30d
      : periodDays === 90
        ? adherence90d
        : summarizeTrend(
            adherenceTrend,
            consultationData?.adherenceSummary?.currentStreak ?? adherence30d.currentStreak ?? 0
          )

  const criticalStockCount = stockRows.filter((item) => item.severity === 'critical').length
  const warningStockCount = stockRows.filter((item) => item.severity === 'warning').length
  const expiringPrescriptionCount = prescriptionRows.filter(
    (item) => item.status === 'vencendo'
  ).length
  const expiredPrescriptionCount = prescriptionRows.filter(
    (item) => item.status === 'vencida'
  ).length
  const activeTitrationCount = titrationRows.length

  const summaryCards = [
    {
      label: `Adesao ${selectedPeriodLabel}`,
      value: `${selectedPeriodSummary.score ?? 0}%`,
      meta: `${selectedPeriodSummary.taken ?? 0}/${selectedPeriodSummary.expected ?? 0} doses`,
      tone:
        (selectedPeriodSummary.score ?? 0) >= 80
          ? 'success'
          : (selectedPeriodSummary.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Adesao 30d',
      value: `${adherence30d.score ?? 0}%`,
      meta: `${adherence30d.taken ?? 0}/${adherence30d.expected ?? 0} doses`,
      tone:
        (adherence30d.score ?? 0) >= 80
          ? 'success'
          : (adherence30d.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Adesao 90d',
      value: `${adherence90d.score ?? 0}%`,
      meta: `${adherence90d.taken ?? 0}/${adherence90d.expected ?? 0} doses`,
      tone:
        (adherence90d.score ?? 0) >= 80
          ? 'success'
          : (adherence90d.score ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Pontualidade',
      value: `${selectedPeriodSummary.punctuality ?? 0}%`,
      meta: `Janela de tolerancia | ${selectedPeriodLabel}`,
      tone:
        (selectedPeriodSummary.punctuality ?? 0) >= 80
          ? 'success'
          : (selectedPeriodSummary.punctuality ?? 0) >= 50
            ? 'warning'
            : 'danger',
    },
    {
      label: 'Tratamentos ativos',
      value: String(activeTreatments.length),
      meta: `${activeMedicines.length} medicamentos`,
      tone: 'info',
    },
    {
      label: 'Alertas criticos',
      value: String(criticalStockCount + expiredPrescriptionCount),
      meta: `${warningStockCount + expiringPrescriptionCount} em atencao`,
      tone: criticalStockCount + expiredPrescriptionCount > 0 ? 'danger' : 'success',
    },
    {
      label: 'Titulações',
      value: String(activeTitrationCount),
      meta: `${titrationRows.filter((item) => item.isTransitionDue).length} pendentes`,
      tone: activeTitrationCount > 0 ? 'warning' : 'success',
    },
  ]

  const attentionItems = [
    ...stockRows
      .filter((item) => item.severity !== 'stable')
      .slice(0, 4)
      .map((item) => ({
        label: item.label,
        detail:
          item.severity === 'critical'
            ? 'Estoque esgotado'
            : `Estoque baixo: ${item.daysRemaining ?? '-'} dias`,
        tone: item.severity,
      })),
    ...prescriptionRows
      .filter((item) => item.status !== 'vigente')
      .slice(0, 4)
      .map((item) => ({
        label: item.label,
        detail:
          item.status === 'vencida'
            ? 'Prescricao vencida'
            : `${item.daysRemaining ?? '-'} dias para vencer`,
        tone: item.status === 'vencida' ? 'danger' : 'warning',
      })),
    ...titrationRows.slice(0, 3).map((item) => ({
      label: item.label,
      detail: item.isTransitionDue
        ? 'Transicao pendente'
        : `Etapa ${item.currentStep}/${item.totalSteps}`,
      tone: item.isTransitionDue ? 'warning' : 'info',
    })),
  ]

  return {
    title,
    period,
    generatedAt,
    generatedAtLabel: (generatedAt instanceof Date ? generatedAt : parseISO(generatedAt)).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'America/Sao_Paulo',
    }),
    patient: {
      name: formatPatientDisplayName(patientInfo.name, patientEmail),
      age: patientInfo.age ?? null,
      handle: extractEmailHandle(patientEmail) || null,
      emergencyCard: patientInfo.emergencyCard || null,
    },
    summaryCards,
    activeTreatments,
    adherence: {
      selectedPeriod: {
        ...selectedPeriodSummary,
        label: selectedPeriodLabel,
      },
      last30d: adherence30d,
      last90d: adherence90d,
      trend: adherenceTrend,
      trendLabel: selectedPeriodLabel,
      currentStreak:
        consultationData?.adherenceSummary?.currentStreak ?? adherence30d.currentStreak ?? 0,
    },
    stockRows,
    prescriptionRows,
    titrationRows,
    attentionItems,
    clinicalNotes: [
      patientInfo.emergencyCard?.allergies?.length
        ? `Alergias registradas: ${patientInfo.emergencyCard.allergies.join(', ')}`
        : 'Sem alergias registradas no cartao de emergencia',
      patientInfo.emergencyCard?.blood_type
        ? `Tipo sanguineo: ${patientInfo.emergencyCard.blood_type}`
        : 'Tipo sanguineo nao informado',
    ],
  }
}

export default {
  buildConsultationPdfData,
  formatTreatmentLabel,
  formatMedicinePresentation,
  formatIntakeDose,
  formatFrequency,
  formatDailyDose,
}

/**
 * @fileoverview Serviço de geração de relatórios PDF.
 * Gera relatórios completos em formato A4 com gráficos e tabelas.
 * @module features/reports/services/pdfGeneratorService
 */

import { parseLocalDate, formatLocalDate, addDays, getNow } from '@utils/dateUtils.js'

/**
 * Dimensões da página A4 em milímetros.
 * @constant {Object}
 */
const PAGE_DIMENSIONS = {
  width: 210,
  height: 297,
  margin: 10,
  contentWidth: 190, // 210 - 2*10
}

/**
 * Posições Y para elementos do PDF.
 * @constant {Object}
 */
const Y_POSITIONS = {
  headerStart: 20,
  headerTitle: 25,
  headerDate: 35,
  summaryStart: 45,
  chartStart: 80,
  chartHeight: 76, // Proporção 500x200 convertida para 190mm largura
  tableStart: 165,
  stockStart: 250,
  footer: 285,
}

/**
 * Cores do tema para o PDF.
 * @constant {Object}
 */
const PDF_COLORS = {
  primary: [16, 185, 129], // Verde
  warning: [245, 158, 11], // Âmbar
  danger: [239, 68, 68], // Vermelho
  text: [51, 51, 51], // Cinza escuro
  lightGray: [200, 200, 200],
  white: [255, 255, 255],
}

/**
 * Formata uma data para exibição no cabeçalho do relatório.
 * @param {Date} date - Data a ser formatada.
 * @returns {string} Data formatada em português.
 * @private
 */
function formatReportDate(date) {
  const options = {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  }
  return date.toLocaleDateString('pt-BR', options)
}

/**
 * Formata horários de doses para exibição.
 * @param {Array<string>} timeSchedule - Array de horários.
 * @returns {string} Horários formatados.
 * @private
 */
function formatTimeSchedule(timeSchedule) {
  if (!timeSchedule || timeSchedule.length === 0) return '1x/dia'
  return `${timeSchedule.length}x/dia`
}

/**
 * Traduz o status do protocolo para português.
 * @param {boolean} active - Se o protocolo está ativo.
 * @returns {string} Status traduzido.
 * @private
 */
function translateStatus(active) {
  return active ? 'Ativo' : 'Inativo'
}

/**
 * Calcula dias restantes de estoque para um medicamento.
 * @param {Object} stockSummary - Resumo do estoque.
 * @param {Object} protocol - Protocolo associado.
 * @returns {number} Dias restantes estimados.
 * @private
 */
function calculateDaysRemaining(stockSummary, protocol) {
  if (!stockSummary || stockSummary.total_quantity <= 0) return 0

  const dosesPerDay = protocol?.time_schedule?.length || 1
  return Math.floor(stockSummary.total_quantity / dosesPerDay)
}

/**
 * Log estruturado para o serviço de PDF (R-087).
 * @param {string} level - Nível do log (info, warn, error).
 * @param {string} message - Mensagem do log.
 * @param {Object} data - Dados adicionais.
 * @private
 */
function logPDF(level, message, data = {}) {
  const logEntry = {
    timestamp: getNow().toISOString(),
    service: 'pdfGeneratorService',
    level,
    message,
    ...data,
  }
  console.log(JSON.stringify(logEntry))
}

/**
 * Desenha o cabeçalho do relatório.
 * @param {Object} doc - Instância do jsPDF.
 * @param {string} title - Título do relatório.
 * @param {Date} reportDate - Data do relatório.
 * @private
 */
function drawHeader(doc, title, reportDate) {
  // Título principal
  doc.setFontSize(20)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text(title, PAGE_DIMENSIONS.width / 2, Y_POSITIONS.headerTitle, {
    align: 'center',
  })

  // Data do relatório
  doc.setFontSize(10)
  doc.setTextColor(...PDF_COLORS.lightGray)
  doc.text(formatReportDate(reportDate), PAGE_DIMENSIONS.width / 2, Y_POSITIONS.headerDate, {
    align: 'center',
  })

  // Linha separadora
  doc.setDrawColor(...PDF_COLORS.primary)
  doc.setLineWidth(0.5)
  doc.line(
    PAGE_DIMENSIONS.margin,
    Y_POSITIONS.headerDate + 5,
    PAGE_DIMENSIONS.width - PAGE_DIMENSIONS.margin,
    Y_POSITIONS.headerDate + 5
  )
}

/**
 * Desenha o resumo de adesão.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Object} adherenceSummary - Dados de adesão.
 * @private
 */
function drawAdherenceSummary(doc, adherenceSummary) {
  const startY = Y_POSITIONS.summaryStart

  // Título da seção
  doc.setFontSize(14)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Resumo de Adesão', PAGE_DIMENSIONS.margin, startY)

  // Estatísticas em caixas
  const stats = [
    {
      label: 'Score Geral',
      value: `${adherenceSummary.overallScore || 0}%`,
      color:
        adherenceSummary.overallScore >= 80
          ? PDF_COLORS.primary
          : adherenceSummary.overallScore >= 50
            ? PDF_COLORS.warning
            : PDF_COLORS.danger,
    },
    {
      label: 'Doses Tomadas',
      value: String(adherenceSummary.overallTaken || 0),
      color: PDF_COLORS.text,
    },
    {
      label: 'Doses Esperadas',
      value: String(adherenceSummary.overallExpected || 0),
      color: PDF_COLORS.text,
    },
    {
      label: 'Sequência Atual',
      value: `${adherenceSummary.currentStreak || 0} dias`,
      color: PDF_COLORS.primary,
    },
  ]

  const boxWidth = 45
  const boxHeight = 20
  const boxGap = 5
  const startX = PAGE_DIMENSIONS.margin

  stats.forEach((stat, index) => {
    const x = startX + index * (boxWidth + boxGap)

    // Caixa
    doc.setDrawColor(...PDF_COLORS.lightGray)
    doc.setLineWidth(0.2)
    doc.roundedRect(x, startY + 8, boxWidth, boxHeight, 2, 2, 'S')

    // Valor
    doc.setFontSize(14)
    doc.setTextColor(...stat.color)
    doc.text(stat.value, x + boxWidth / 2, startY + 18, { align: 'center' })

    // Label
    doc.setFontSize(8)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text(stat.label, x + boxWidth / 2, startY + 25, { align: 'center' })
  })
}

/**
 * Desenha o gráfico de adesão.
 * @param {Object} doc - Instância do jsPDF.
 * @param {string} chartImage - Imagem do gráfico em base64.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y após o gráfico.
 * @private
 */
function drawAdherenceChart(doc, chartImage, startY) {
  if (!chartImage) {
    // Mensagem de dados não disponíveis
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text(
      'Dados de adesão não disponíveis para o período',
      PAGE_DIMENSIONS.width / 2,
      startY + Y_POSITIONS.chartHeight / 2,
      { align: 'center' }
    )
    return startY + Y_POSITIONS.chartHeight + 10
  }

  // Título do gráfico
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Tendência de Adesão (30 dias)', PAGE_DIMENSIONS.margin, startY)

  // Adiciona imagem do gráfico
  doc.addImage(
    chartImage,
    'PNG',
    PAGE_DIMENSIONS.margin,
    startY + 5,
    PAGE_DIMENSIONS.contentWidth,
    Y_POSITIONS.chartHeight
  )

  return startY + Y_POSITIONS.chartHeight + 15
}

/**
 * Desenha a tabela de protocolos.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} protocols - Lista de protocolos.
 * @param {Function} autoTable - Função autoTable do jspdf-autotable.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y final após a tabela.
 * @private
 */
function drawProtocolsTable(doc, protocols, autoTable, startY) {
  if (!protocols || protocols.length === 0) {
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text('Nenhum protocolo cadastrado', PAGE_DIMENSIONS.margin, startY + 10)
    return startY + 20
  }

  // Prepara dados da tabela
  const tableData = protocols.map((protocol) => [
    protocol.medicine?.name || protocol.name || 'Medicamento',
    `${protocol.dosage || ''} ${protocol.dosage_unit || 'comprimido(s)'}`,
    formatTimeSchedule(protocol.time_schedule),
    translateStatus(protocol.active),
  ])

  // Usa autoTable para criar tabela formatada
  autoTable(doc, {
    startY: startY,
    head: [['Medicamento', 'Dosagem', 'Frequência', 'Status']],
    body: tableData,
    theme: 'striped',
    headStyles: {
      fillColor: PDF_COLORS.primary,
      textColor: PDF_COLORS.white,
      fontSize: 10,
      fontStyle: 'bold',
    },
    bodyStyles: {
      fontSize: 9,
      textColor: PDF_COLORS.text,
    },
    alternateRowStyles: {
      fillColor: [245, 245, 245],
    },
    margin: {
      left: PAGE_DIMENSIONS.margin,
      right: PAGE_DIMENSIONS.margin,
    },
    columnStyles: {
      0: { cellWidth: 60 },
      1: { cellWidth: 40 },
      2: { cellWidth: 40 },
      3: { cellWidth: 30 },
    },
  })

  // Retorna a posição Y final da tabela
  return doc.lastAutoTable.finalY + 10
}

/**
 * Desenha o resumo de estoque com gráfico.
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} stockData - Dados de estoque.
 * @param {string} stockChartImage - Imagem do gráfico de estoque.
 * @param {number} startY - Posição Y inicial.
 * @private
 */
function drawStockSummary(doc, stockData, stockChartImage, startY) {
  // Verifica se precisa de nova página
  if (startY > 240) {
    doc.addPage()
    startY = 20
  }

  // Título da seção
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Resumo de Estoque', PAGE_DIMENSIONS.margin, startY)

  if (!stockData || stockData.length === 0) {
    doc.setFontSize(10)
    doc.setTextColor(...PDF_COLORS.lightGray)
    doc.text('Nenhum dado de estoque disponível', PAGE_DIMENSIONS.margin, startY + 10)
    return
  }

  // Alertas de estoque baixo
  const lowStock = stockData.filter((item) => item.daysRemaining < 7)
  if (lowStock.length > 0) {
    doc.setFontSize(9)
    doc.setTextColor(...PDF_COLORS.danger)
    doc.text(
      `Atenção: ${lowStock.length} medicamento(s) com estoque baixo`,
      PAGE_DIMENSIONS.margin,
      startY + 8
    )
  }

  // Gráfico de estoque
  if (stockChartImage) {
    doc.addImage(
      stockChartImage,
      'PNG',
      PAGE_DIMENSIONS.margin,
      startY + 12,
      PAGE_DIMENSIONS.contentWidth,
      50
    )
  }
}

/**
 * Cores RGB para nivel de risco (sem CSS vars — jsPDF usa RGB).
 * @constant {Object}
 */
const RISK_RGB_COLORS = {
  stable: [34, 197, 94], // #22c55e verde
  attention: [245, 158, 11], // #f59e0b amarelo
  critical: [239, 68, 68], // #ef4444 vermelho
}

/**
 * Desenha a tabela de risco por protocolo.
 * Só renderiza se houver protocolos com dados suficientes (hasEnoughData === true).
 * @param {Object} doc - Instância do jsPDF.
 * @param {Array} risks - Array retornado por calculateAllProtocolRisks.
 * @param {Array} protocols - Lista de protocolos (para buscar nome do medicamento).
 * @param {Function} autoTable - Função autoTable do jspdf-autotable.
 * @param {number} startY - Posição Y inicial.
 * @returns {number} Posição Y após a tabela.
 * @private
 */
function drawRiskTable(doc, risks, protocols, autoTable, startY) {
  const risksWithData = risks.filter((r) => r.hasEnoughData)
  if (risksWithData.length === 0) return startY

  // Verifica se precisa de nova página
  if (startY > 220) {
    doc.addPage()
    startY = 20
  }

  // Título da seção
  doc.setFontSize(12)
  doc.setTextColor(...PDF_COLORS.text)
  doc.text('Risco por Protocolo', PAGE_DIMENSIONS.margin, startY)

  const tableData = risksWithData.map((risk) => {
    const protocol = protocols.find((p) => p.id === risk.protocolId)
    const name = protocol?.medicine?.name || protocol?.name || 'Protocolo'
    const adherence = `${risk.adherence14d}%`
    const trend = risk.trend7d > 0 ? `+${risk.trend7d}%` : `${risk.trend7d}%`
    return [name, adherence, trend, risk.riskLabel]
  })

  autoTable(doc, {
    startY: startY + 5,
    head: [['Protocolo', 'Adesão 14d', 'Tendência', 'Classificação']],
    body: tableData,
    theme: 'striped',
    headStyles: {
      fillColor: PDF_COLORS.primary,
      textColor: PDF_COLORS.white,
      fontSize: 10,
      fontStyle: 'bold',
    },
    bodyStyles: {
      fontSize: 9,
      textColor: PDF_COLORS.text,
    },
    alternateRowStyles: {
      fillColor: [245, 245, 245],
    },
    margin: {
      left: PAGE_DIMENSIONS.margin,
      right: PAGE_DIMENSIONS.margin,
    },
    columnStyles: {
      0: { cellWidth: 70 },
      1: { cellWidth: 35 },
      2: { cellWidth: 35 },
      3: { cellWidth: 40 },
    },
    // Colorir células da coluna "Classificação" conforme nível de risco
    didParseCell(data) {
      if (data.section === 'body' && data.column.index === 3) {
        const risk = risksWithData[data.row.index]
        if (risk) {
          data.cell.styles.textColor = RISK_RGB_COLORS[risk.riskLevel] || PDF_COLORS.text
          data.cell.styles.fontStyle = 'bold'
        }
      }
    },
  })

  return doc.lastAutoTable.finalY + 10
}

/**
 * Desenha o rodapé do relatório.
 * @param {Object} doc - Instância do jsPDF.
 * @private
 */
function drawFooter(doc) {
  // Linha separadora
  doc.setDrawColor(...PDF_COLORS.lightGray)
  doc.setLineWidth(0.2)
  doc.line(
    PAGE_DIMENSIONS.margin,
    Y_POSITIONS.footer - 5,
    PAGE_DIMENSIONS.width - PAGE_DIMENSIONS.margin,
    Y_POSITIONS.footer - 5
  )

  // Disclaimer
  doc.setFontSize(8)
  doc.setTextColor(...PDF_COLORS.lightGray)
  doc.text(
    'Este relatório é apenas informativo e não substitui orientação médica. Consulte seu médico para decisões sobre tratamento.',
    PAGE_DIMENSIONS.width / 2,
    Y_POSITIONS.footer,
    { align: 'center', maxWidth: PAGE_DIMENSIONS.contentWidth }
  )
}

/**
 * Prepara dados de adesão para o gráfico.
 * @param {Array} dailyAdherence - Dados diários de adesão.
 * @returns {Object} Dados formatados para renderAdherenceChart.
 * @private
 */
function prepareAdherenceChartData(dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length === 0) {
    return null
  }

  return {
    labels: dailyAdherence.map((day) => {
      // Formata data para DD/MM
      const date = parseLocalDate(day.date)
      return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
    }),
    values: dailyAdherence.map((day) => day.adherence || 0),
    expected: dailyAdherence.map((day) => day.expected || 0),
    taken: dailyAdherence.map((day) => day.taken || 0),
  }
}

/**
 * Prepara dados de estoque para o gráfico.
 * @param {Array} protocols - Lista de protocolos.
 * @param {Array} stockSummaries - Resumos de estoque.
 * @returns {Array} Dados formatados para renderStockChart.
 * @private
 */
function prepareStockChartData(protocols, stockSummaries) {
  if (!protocols || protocols.length === 0) {
    return []
  }

  return protocols
    .filter((protocol) => protocol.active && protocol.medicine)
    .map((protocol) => {
      const stock = stockSummaries.find((s) => s.medicine_id === protocol.medicine_id)
      return {
        name: protocol.medicine?.name || protocol.name,
        daysRemaining: stock ? calculateDaysRemaining(stock, protocol) : 0,
      }
    })
    .filter((item) => item.daysRemaining > 0)
    .sort((a, b) => a.daysRemaining - b.daysRemaining)
    .slice(0, 10) // Limita a 10 medicamentos
}

/**
 * Gera um relatório PDF completo.
 *
 * @param {Object} options - Opções de geração do relatório.
 * @param {string} [options.title='Dosiq - Relatório'] - Título do relatório.
 * @param {string} [options.period='30d'] - Período do relatório ('7d', '30d', '90d').
 * @param {boolean} [options.includeCharts=true] - Se deve incluir gráficos.
 * @param {boolean} [options.includeProtocols=true] - Se deve incluir tabela de protocolos.
 * @param {boolean} [options.includeStock=true] - Se deve incluir resumo de estoque.
 * @param {boolean} [options.includeRiskTable=true] - Se deve incluir tabela de risco por protocolo.
 * @returns {Promise<Blob>} Blob do PDF gerado.
 *
 * @example
 * // Geração básica
 * const pdfBlob = await generatePDF()
 *
 * // Com opções personalizadas
 * const pdfBlob = await generatePDF({
 *   title: 'Relatório Mensal',
 *   period: '30d',
 *   includeCharts: true
 * })
 *
 * // Download do PDF
 * const url = URL.createObjectURL(pdfBlob)
 * const a = document.createElement('a')
 * a.href = url
 * a.download = 'relatorio-medicamentos.pdf'
 * a.click()
 * URL.revokeObjectURL(url)
 */
export async function generatePDF(options = {}) {
  const startTime = getNow().getTime()
  const {
    title = 'Dosiq - Relatório',
    period = '30d',
    includeCharts = true,
    includeProtocols = true,
    includeStock = true,
    includeRiskTable = true,
  } = options

  logPDF('info', 'Iniciando geração do PDF', { title, period, options })

  try {
    // Lazy load TODOS os módulos pesados (jsPDF, services, chartRenderer)
    // Isso evita que o main bundle inclua vendor-pdf (589KB), feature-stock (139KB), etc.
    const [
      { jsPDF },
      { default: autoTable },
      { renderAdherenceChart, renderStockChart },
      { adherenceService },
      { protocolService },
      stockModule,
      riskModule,
      logModule,
    ] = await Promise.all([
      import('jspdf'),
      import('jspdf-autotable'),
      import('./chartRenderer.js'),
      import('@services/api/adherenceService.js'),
      import('@features/protocols/services/protocolService.js'),
      includeStock ? import('@features/stock/services/stockService.js') : Promise.resolve(null),
      includeRiskTable
        ? import('@adherence/services/protocolRiskService.js')
        : Promise.resolve(null),
      includeRiskTable ? import('@shared/services/api/logService.js') : Promise.resolve(null),
    ])

    const stockService = stockModule?.stockService
    const calculateAllProtocolRisks = riskModule?.calculateAllProtocolRisks
    const logService = logModule?.logService

    logPDF('info', 'Módulos carregados sob demanda', { library: 'jspdf + services + charts' })

    // Busca dados em paralelo
    const dataFetchStart = getNow().getTime()
    const today = getNow()
    const thirtyDaysAgo = addDays(today, -30)
    const startDateStr = formatLocalDate(thirtyDaysAgo)
    const endDateStr = formatLocalDate(today)

    const [adherenceSummary, dailyAdherence, protocols, lowStock, recentLogs] = await Promise.all([
      adherenceService.getAdherenceSummary(period),
      adherenceService.getDailyAdherence(30),
      includeProtocols ? protocolService.getAll() : Promise.resolve([]),
      includeStock && stockService ? stockService.getLowStockMedicines(100) : Promise.resolve([]),
      includeRiskTable && logService
        ? logService.getByDateRange(startDateStr, endDateStr, 500).then((r) => r.data ?? [])
        : Promise.resolve([]),
    ])

    logPDF('info', 'Dados buscados', {
      duration: `${getNow().getTime() - dataFetchStart}ms`,
      adherenceScore: adherenceSummary.overallScore,
      protocolsCount: protocols.length,
      lowStockCount: lowStock.length,
    })

    // Busca resumos de estoque para cada medicamento
    let stockSummaries = []
    if (includeStock && stockService && protocols.length > 0) {
      const medicineIds = [...new Set(protocols.map((p) => p.medicine_id).filter(Boolean))]
      stockSummaries = await Promise.all(medicineIds.map((id) => stockService.getStockSummary(id)))
    }

    // Cria documento PDF
    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
    })

    // Desenha cabeçalho
    drawHeader(doc, title, getNow())

    // Desenha resumo de adesão
    drawAdherenceSummary(doc, adherenceSummary)

    // Prepara e desenha gráfico de adesão
    let currentY = Y_POSITIONS.chartStart
    if (includeCharts) {
      const chartData = prepareAdherenceChartData(dailyAdherence)
      const chartImage = chartData ? renderAdherenceChart(chartData, 500, 200) : null
      currentY = drawAdherenceChart(doc, chartImage, currentY)
    }

    // Desenha tabela de protocolos
    if (includeProtocols) {
      currentY = drawProtocolsTable(doc, protocols, autoTable, currentY)
    }

    // Desenha tabela de risco por protocolo
    if (includeRiskTable && calculateAllProtocolRisks && protocols.length > 0) {
      const risks = calculateAllProtocolRisks({ protocols, logs: recentLogs })
      currentY = drawRiskTable(doc, risks, protocols, autoTable, currentY)
      logPDF('info', 'Tabela de risco adicionada', {
        protocolsWithData: risks.filter((r) => r.hasEnoughData).length,
        totalProtocols: risks.length,
      })
    }

    // Desenha resumo de estoque
    if (includeStock) {
      const stockChartData = prepareStockChartData(protocols, stockSummaries)
      const stockChartImage =
        stockChartData.length > 0 ? renderStockChart(stockChartData, 500, 150) : null
      drawStockSummary(doc, stockChartData, stockChartImage, currentY)
    }

    // Desenha rodapé
    drawFooter(doc)

    // Gera Blob
    const pdfBlob = doc.output('blob')

    const totalDuration = getNow().getTime() - startTime
    logPDF('info', 'PDF gerado com sucesso', {
      duration: `${totalDuration}ms`,
      blobSize: `${(pdfBlob.size / 1024).toFixed(2)}KB`,
      blobSizeMB: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
    })

    // Verifica tamanho do arquivo (<2MB)
    if (pdfBlob.size > 2 * 1024 * 1024) {
      logPDF('warn', 'PDF excede 2MB', {
        size: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
      })
    }

    return pdfBlob
  } catch (error) {
    logPDF('error', 'Erro ao gerar PDF', {
      error: error.message,
      stack: error.stack,
    })
    throw new Error(`Falha ao gerar relatório PDF: ${error.message}`)
  }
}

/**
 * Exporta todas as funções do módulo.
 */
export default {
  generatePDF,
}

/**
 * Service para compartilhamento de relatórios
 *
 * Fornece funções para upload de PDFs para compartilhamento temporário
 * e integração com Web Share API e Clipboard API.
 *
 * @module src/features/reports/services/shareService
 * @version 1.0.0
 */

import { supabase } from '@shared/utils/supabase'
import { getNow } from '@utils/dateUtils'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

const API_ENDPOINT = '/api/share'

/**
 * Níveis de log disponíveis
 * @readonly
 */
const LOG_LEVELS = {
  DEBUG: 'debug',
  INFO: 'info',
  WARN: 'warn',
  ERROR: 'error',
}

// ============================================================================
// LOGGER ESTRUTURADO (R-087)
// ============================================================================

/**
 * Log estruturado com timestamp e contexto
 * @param {string} level - Nível do log (debug, info, warn, error)
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais para o log
 */
function log(level, message, data = {}) {
  const timestamp = getNow().toISOString()
  const logEntry = {
    timestamp,
    service: 'shareService',
    level,
    message,
    ...data,
  }

  const formattedMessage = `[shareService] ${message}`

  if (level === LOG_LEVELS.ERROR) {
    console.error(formattedMessage, logEntry)
  } else if (level === LOG_LEVELS.WARN) {
    console.warn(formattedMessage, logEntry)
  } else {
    console.log(formattedMessage, logEntry)
  }
}

/**
 * Log de informação
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logInfo(message, data = {}) {
  log(LOG_LEVELS.INFO, message, data)
}

/**
 * Log de erro
 * @param {string} message - Mensagem descritiva
 * @param {Error|Object} error - Erro ocorrido
 * @param {Object} additionalData - Dados adicionais de contexto
 */
function logError(message, error, additionalData = {}) {
  const errorDetails =
    error instanceof Error
      ? { name: error.name, message: error.message, stack: error.stack }
      : { error: String(error) }

  log(LOG_LEVELS.ERROR, message, { ...errorDetails, ...additionalData })
}

/**
 * Log de warning
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logWarn(message, data = {}) {
  log(LOG_LEVELS.WARN, message, data)
}

// ============================================================================
// FUNÇÕES PÚBLICAS
// ============================================================================

/**
 * Obtém o token de acesso JWT do Supabase
 * @returns {Promise<string|null>} Token JWT ou null se não autenticado
 */
async function getAuthToken() {
  try {
    const {
      data: { session },
    } = await supabase.auth.getSession()
    return session?.access_token || null
  } catch (error) {
    logError('Erro ao obter token de autenticação', error)
    return null
  }
}

/**
 * Faz upload de um relatório PDF para compartilhamento temporário
 *
 * @param {Blob} blob - Arquivo PDF em formato Blob
 * @param {Object} options - Opções de compartilhamento
 * @param {string} options.filename - Nome do arquivo (deve terminar com .pdf)
 * @param {number} [options.expiresInHours=72] - Tempo de expiração em horas (1-168)
 * @returns {Promise<Object>} Resultado com { url, expiresAt }
 * @throws {Error} Se o upload falhar ou usuário não estiver autenticado
 *
 * @example
 * const pdfBlob = await generatePDF()
 * const { url, expiresAt } = await shareReport(pdfBlob, {
 *   filename: 'relatorio-medicamentos.pdf',
 *   expiresInHours: 48
 * })
 */
export async function shareReport(blob, options) {
  const { filename, expiresInHours = 72 } = options

  logInfo('Iniciando compartilhamento de relatório', { filename, size: blob.size, expiresInHours })

  // Validar parâmetros
  if (!blob || !(blob instanceof Blob)) {
    throw new Error('Arquivo inválido. Envie um Blob válido.')
  }

  if (!filename || !filename.endsWith('.pdf')) {
    throw new Error('Nome do arquivo deve terminar com .pdf')
  }

  if (expiresInHours < 1 || expiresInHours > 168) {
    throw new Error('Tempo de expiração deve estar entre 1 e 168 horas')
  }

  // Verificar tamanho máximo (5MB)
  const maxSize = 5 * 1024 * 1024
  if (blob.size > maxSize) {
    throw new Error('Arquivo muito grande. Máximo de 5MB.')
  }

  // Obter token de autenticação
  const token = await getAuthToken()
  if (!token) {
    throw new Error('Usuário não autenticado. Faça login para compartilhar.')
  }

  // Converter Blob para base64
  let base64Data
  try {
    base64Data = await blobToBase64(blob)
    logInfo('Blob convertido para base64', { size: base64Data.length })
  } catch (error) {
    logError('Erro ao converter blob para base64', error)
    throw new Error('Erro ao processar arquivo')
  }

  // Fazer requisição para API
  try {
    const response = await fetch(API_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        blob: base64Data,
        filename,
        expiresInHours,
      }),
    })

    const result = await response.json()

    if (!response.ok || !result.success) {
      const errorMessage = result.error || 'Erro ao compartilhar relatório'
      logWarn('Falha no compartilhamento', { status: response.status, error: errorMessage })
      throw new Error(errorMessage)
    }

    logInfo('Relatório compartilhado com sucesso', { url: result.data?.url?.split('?')[0] })

    return {
      url: result.data.url,
      expiresAt: result.data.expiresAt,
    }
  } catch (error) {
    if (error.message === 'Failed to fetch') {
      logError('Erro de conexão com servidor', error)
      throw new Error('Erro de conexão. Verifique sua internet.')
    }
    throw error
  }
}

/**
 * Compartilha uma URL usando Web Share API nativa
 * Fallback para clipboard se não suportado
 *
 * @param {string} url - URL a ser compartilhada
 * @param {string} [title='Relatório'] - Título do compartilhamento
 * @returns {Promise<boolean>} true se compartilhado com sucesso
 *
 * @example
 * const success = await shareNative(url, 'Meu Relatório de Medicamentos')
 * if (!success) {
 *   // Usuário cancelou ou não suportado
 * }
 */
export async function shareNative(url, title = 'Relatório') {
  logInfo('Tentando compartilhamento nativo', { url: url.split('?')[0], title })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Verificar se Web Share API é suportada
  if (navigator.share) {
    try {
      await navigator.share({
        title,
        text: `Confira meu ${title.toLowerCase()}`,
        url,
      })
      logInfo('Compartilhamento nativo bem-sucedido')
      return true
    } catch (error) {
      // Usuário cancelou ou erro
      if (error.name === 'AbortError') {
        logInfo('Usuário cancelou compartilhamento')
        return false
      }
      logWarn('Erro no compartilhamento nativo', { error: error.message })
      // Continuar para fallback
    }
  }

  // Fallback para clipboard
  logInfo('Usando fallback para clipboard')
  try {
    await copyToClipboard(url)
    return true
  } catch (error) {
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível compartilhar. Copie a URL manualmente.')
  }
}

/**
 * Copia uma URL para o clipboard
 * Usa Clipboard API moderna com fallback para método legacy
 *
 * @param {string} url - URL a ser copiada
 * @returns {Promise<void>}
 * @throws {Error} Se não conseguir copiar
 *
 * @example
 * await copyToClipboard('https://example.com/relatorio.pdf')
 * // Mostrar toast: "Link copiado para a área de transferência!"
 */
export async function copyToClipboard(url) {
  logInfo('Copiando para clipboard', { url: url.split('?')[0] })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Tentar Clipboard API moderna
  if (navigator.clipboard && window.isSecureContext) {
    try {
      await navigator.clipboard.writeText(url)
      logInfo('URL copiada com Clipboard API')
      return
    } catch (error) {
      logWarn('Clipboard API falhou, tentando fallback', { error: error.message })
    }
  }

  // Fallback para método legacy
  const textArea = document.createElement('textarea')
  textArea.value = url
  textArea.style.position = 'fixed'
  textArea.style.left = '-999999px'
  textArea.style.top = '-999999px'
  document.body.appendChild(textArea)

  try {
    textArea.focus()
    textArea.select()

    const successful = document.execCommand('copy')
    document.body.removeChild(textArea)

    if (successful) {
      logInfo('URL copiada com método legacy')
    } else {
      throw new Error('execCommand retornou false')
    }
  } catch (error) {
    document.body.removeChild(textArea)
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível copiar o link. Copie manualmente.')
  }
}

