/**
 * useStockData — Hook compartilhado de dados para views de Estoque
 * Reutilizado por Stock.jsx (legado) e StockRedesign.jsx (redesign).
 *
 * Fonte: extração de Stock.jsx linhas 30-228.
 * Implementa: getStockStatus(), getBarPercentage(), lastPurchase computado.
 */

import { useState, useEffect, useMemo } from 'react'
import { medicineService, stockService, protocolService } from '@shared/services'
import { purchaseService } from '@stock/services/purchaseService'
import { parseLocalDate } from '@utils/dateUtils'

// ─── Status Helpers (Exportados para testes) ─────────────────────────────────

/**
 * Calcula o status de urgência de estoque.
 * Baseado em: quantidade total == 0 OU dias restantes.
 *
 * @param {number} totalQuantity — quantidade total em estoque
 * @param {number} daysRemaining — dias de estoque (Infinity se sem protocolo ativo)
 * @returns {'urgente' | 'atencao' | 'seguro' | 'alto'}
 */
export function getStockStatus(totalQuantity, daysRemaining) {
  if (totalQuantity === 0) return 'urgente'
  if (!isFinite(daysRemaining) || daysRemaining >= 30) return 'alto'
  if (daysRemaining <= 7) return 'urgente'
  if (daysRemaining <= 14) return 'atencao'
  return 'seguro'
}

/**
 * Calcula percentual da barra de progresso (0–100).
 * Baseado em dias: 30 dias = 100%, 0 dias = 0%.
 *
 * @param {number} totalQuantity
 * @param {number} daysRemaining
 * @returns {number} Percentual 0–100
 */
export function getBarPercentage(totalQuantity, daysRemaining) {
  if (totalQuantity === 0) return 0
  if (!isFinite(daysRemaining) || daysRemaining >= 30) return 100
  return Math.round((daysRemaining / 30) * 100)
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

/**
 * Hook de dados para a view de Estoque.
 * Compartilhado por Stock.jsx (legado) e StockRedesign.jsx (redesign).
 *
 * @returns {Object} Dados processados de estoque + estado + handlers
 */
export function useStockData() {
  // 1. States
  const [medicines, setMedicines] = useState([])
  const [protocols, setProtocols] = useState([])
  const [stockMap, setStockMap] = useState({})
  const [purchaseHistoryMap, setPurchaseHistoryMap] = useState({})
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)

  // 2. Memos — Computar items, sub-listas por urgência
  const items = useMemo(() => {
    if (medicines.length === 0) return []

    const activeMedicineIds = new Set(protocols.map((p) => p.medicine_id))

    // Mapa: medicineId → protocolo primário (primeiro ativo)
    const primaryProtocolMap = {}
    protocols
      .filter((p) => p.active !== false)
      .forEach((p) => {
        if (!primaryProtocolMap[p.medicine_id]) {
          primaryProtocolMap[p.medicine_id] = {
            name: p.name,
            time_schedule: p.time_schedule || [],
            dosage_per_intake: p.dosage_per_intake || 0,
          }
        }
      })

    // Calcular consumo diário por medicamento
    const dailyIntakeMap = {}
    protocols
      .filter((p) => p.active !== false)
      .forEach((p) => {
        const daily = (p.dosage_per_intake || 0) * (p.time_schedule?.length || 0)
        dailyIntakeMap[p.medicine_id] = (dailyIntakeMap[p.medicine_id] || 0) + daily
      })

    return medicines.map((medicine) => {
      const stock = stockMap[medicine.id] || {
        entries: [],
        total: 0,
      }
      const purchases = purchaseHistoryMap[medicine.id] || []
      const dailyIntake = dailyIntakeMap[medicine.id] || 0
      const daysRemaining = dailyIntake > 0 ? stock.total / dailyIntake : Infinity
      const stockStatus = getStockStatus(stock.total, daysRemaining)
      const barPercentage = getBarPercentage(stock.total, daysRemaining)

      const purchaseEntries = [...purchases].sort(
        (a, b) => parseLocalDate(b.purchase_date) - parseLocalDate(a.purchase_date)
      )
      const latestEntry = purchaseEntries[0] || null
      const lastPurchase = latestEntry
        ? {
            date: latestEntry.purchase_date,
            unitPrice: latestEntry.unit_price ?? null,
            quantity: latestEntry.quantity_bought,
            pharmacy: latestEntry.pharmacy ?? null,
            laboratory: latestEntry.laboratory ?? null,
          }
        : null

      return {
        medicine: {
          id: medicine.id,
          name: medicine.name,
          dosage_per_pill: medicine.dosage_per_pill,
          dosage_unit: medicine.dosage_unit || 'mg',
          type: medicine.type || 'medicamento',
        },
        entries: stock.entries,
        purchases: purchaseEntries,
        totalQuantity: stock.total,
        dailyIntake,
        daysRemaining,
        stockStatus,
        hasActiveProtocol: activeMedicineIds.has(medicine.id),
        primaryProtocol: primaryProtocolMap[medicine.id] || null,
        barPercentage,
        lastPurchase,
      }
    })
  }, [medicines, protocols, purchaseHistoryMap, stockMap])

  // Sub-listas por urgência — ordenadas por criticidade (menor dias primeiro)

  // Medicamentos órfãos: sem protocolo ativo, mas com estoque > 0
  const orphanItems = useMemo(
    () => items.filter((i) => !i.hasActiveProtocol && i.totalQuantity > 0),
    [items]
  )

  // Critical items: urgente MAS excluir (estoque 0 E sem protocolo ativo)
  // Racional: não fazem sentido como "críticos" se não há protocolo para reabastecimento
  const criticalItems = useMemo(
    () =>
      items
        .filter((i) => i.stockStatus === 'urgente')
        .filter((i) => !(i.totalQuantity === 0 && !i.hasActiveProtocol))
        .sort((a, b) => a.daysRemaining - b.daysRemaining),
    [items]
  )
  const warningItems = useMemo(
    () =>
      items
        .filter((i) => i.stockStatus === 'atencao')
        .sort((a, b) => a.daysRemaining - b.daysRemaining),
    [items]
  )
  const okItems = useMemo(
    () =>
      items
        .filter((i) => i.stockStatus === 'seguro')
        .sort((a, b) => a.daysRemaining - b.daysRemaining),
    [items]
  )
  const highItems = useMemo(() => items.filter((i) => i.stockStatus === 'alto'), [items])

  // 3. Effects
  const loadData = async () => {
    try {
      setIsLoading(true)
      setError(null)

      const [medicinesData, protocolsData] = await Promise.all([
        medicineService.getAll(),
        protocolService.getActive(),
      ])

      setMedicines(medicinesData)
      setProtocols(protocolsData)

      // Fetch estoque em paralelo para todos os medicamentos
      const stockResults = await Promise.all(
        medicinesData.map(async (medicine) => {
          const entries = await stockService.getByMedicine(medicine.id)
          const total = entries.reduce((sum, e) => sum + e.quantity, 0)
          return { medicineId: medicine.id, entries, total }
        })
      )

      const map = {}
      stockResults.forEach(({ medicineId, entries, total }) => {
        map[medicineId] = { entries, total }
      })
      setStockMap(map)

      const purchaseHistory = await purchaseService.getHistoryByMedicineIds(
        medicinesData.map((medicine) => medicine.id)
      )
      setPurchaseHistoryMap(purchaseHistory)
    } catch (err) {
      setError('Erro ao carregar estoque: ' + err.message)
      console.error('[useStockData] Erro:', err)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    loadData()
  }, [])

  return {
    items,
    criticalItems,
    warningItems,
    okItems,
    highItems,
    orphanItems,
    medicines,
    protocols,
    isLoading,
    error,
    reload: loadData,
  }
}

import { z } from 'zod'
import { supabase, getUserId } from '@shared/utils/supabase'
import { isProtocolActiveOnDate, parseLocalDate, formatLocalDate, getNow, parseISO, addDays, getTodayLocal, getYesterdayLocal, getSaoPauloTime, cloneDate, parseTimestamp } from '@utils/dateUtils.js'

// Schema para validação de parâmetros
const GetDailyAdherenceFromViewSchema = z.object({
  days: z.number().int().positive().max(365, 'Máximo 365 dias').default(30),
})

const DAY_NAMES = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']
const PERIOD_NAMES = ['Madrugada', 'Manhã', 'Tarde', 'Noite']

/**
 * Extrai intervalo de datas baseado em um período string
 * @param {string} period - Período: '7d', '30d', '90d'
 * @returns {{days: number, endDate: Date, startDate: Date}}
 */
function _getDateRangeForPeriod(period) {
  const days = parseInt(period)
  const endDate = getNow()
  const startDate = addDays(endDate, -days)
  return { startDate, endDate, days }
}

/**
 * Inicializa e preenche o grid de adesão 7×4 com os dados fornecidos
 * @param {Array} data - Dados brutos da view de heatmap
 * @returns {Array<Array<Object>>} O grid de adesão 7×4
 */
function buildAdherenceGrid(data) {
  const grid = Array.from({ length: 7 }, () =>
    Array.from({ length: 4 }, () => ({ taken: 0, expected: 0, adherence: null }))
  )

  ;(data || []).forEach((row) => {
    grid[row.day_of_week][row.period_index] = {
      taken: row.taken_doses,
      expected: row.expected_doses,
      adherence: row.adherence_percentage,
    }
  })

  return grid
}

/**
 * Encontra pior célula e gera narrativa para heatmap
 * @param {Array} data - Dados do heatmap
 * @param {boolean} hasEnoughData - Se tem dados suficientes
 * @returns {object} {worstCell, narrative}
 */
function buildHeatmapNarrative(data, hasEnoughData) {
  let worstCell = null

  if (hasEnoughData) {
    let worstAdherence = 100
    let worstDayIndex = null
    let worstPeriodIndex = null

    ;(data || []).forEach((row) => {
      if (
        row.expected_doses >= 3 &&
        row.adherence_percentage !== null &&
        row.adherence_percentage < worstAdherence
      ) {
        worstAdherence = row.adherence_percentage
        worstDayIndex = row.day_of_week
        worstPeriodIndex = row.period_index
      }
    })

    if (worstDayIndex !== null && worstPeriodIndex !== null) {
      worstCell = {
        dayIndex: worstDayIndex,
        periodIndex: worstPeriodIndex,
        adherence: worstAdherence,
        dayName: DAY_NAMES[worstDayIndex],
        periodName: PERIOD_NAMES[worstPeriodIndex],
      }
    }
  }

  const narrative =
    hasEnoughData && worstCell
      ? `Seu pior horário é ${worstCell.dayName} à ${worstCell.periodName.toLowerCase()}`
      : !hasEnoughData
        ? `Dados insuficientes. Registre pelo menos 21 dias de doses para análise completa.`
        : 'Sua adesão está excelente em todos os períodos!'

  return { worstCell, narrative }
}

/**
 * Adherence Service - Cálculo de adesão ao tratamento
 *
 * CÁLCULOS PRINCIPAIS:
 * - Adesão = (Doses Registradas / Doses Esperadas) × 100
 * - Doses Esperadas = Soma das frequências dos protocolos no período
 * - Doses Registradas = Logs confirmados no período
 * - Streak = Dias seguidos com adesão >= 80%
 *
 * @module adherenceService
 */
export const adherenceService = {
  /**
   * Calcula o score de adesão geral do usuário
   * @param {string} period - Período: '7d', '30d', '90d'
   * @param {string} [userId] - ID do usuário (opcional, evita chamadas redundantes ao getUser)
   * @returns {Promise<{score: number, taken: number, expected: number, period: string}>}
   */
  async calculateAdherence(period = '30d', userId = null) {
    const { startDate, endDate, days } = _getDateRangeForPeriod(period)

    // Usa userId fornecido ou busca do Supabase
    const resolvedUserId = userId || (await getUserId())

    // Buscar protocolos ativos no período
    const { data: protocols, error: protocolError } = await supabase
      .from('protocols')
      .select('*')
      .eq('user_id', resolvedUserId)
      .eq('active', true)

    if (protocolError) throw protocolError

    // M7.2: HEAD request — apenas count, sem dados (zero bytes transferidos)
    const { count, error: logError } = await supabase
      .from('medicine_logs')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', resolvedUserId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())

    if (logError) throw logError

    // Calcular doses esperadas (passar endDate para consistência)
    const expectedDoses = calculateExpectedDoses(protocols, days, endDate)

    // Contar doses registradas
    const takenDoses = count || 0

    // Calcular score (0-100)
    const score = expectedDoses > 0 ? Math.round((takenDoses / expectedDoses) * 100) : 0

    return {
      score: Math.min(score, 100), // Cap at 100%
      taken: takenDoses,
      expected: expectedDoses,
      period,
      startDate: startDate.toISOString(),
      endDate: endDate.toISOString(),
    }
  },

  /**
   * Calcula adesão por protocolo específico
   * @param {string} protocolId - ID do protocolo
   * @param {string} period - Período: '7d', '30d', '90d'
   * @param {string} [userId] - ID do usuário (opcional, evita chamadas redundantes ao getUser)
   * @returns {Promise<{protocolId: string, name: string, score: number, taken: number, expected: number}>}
   */
  async calculateProtocolAdherence(protocolId, period = '30d', userId = null) {
    const days = parseInt(period)
    const endDate = getNow()
    const startDate = addDays(endDate, -days)

    // Usa userId fornecido ou busca do Supabase
    const resolvedUserId = userId || (await getUserId())

    // Buscar protocolo específico
    const { data: protocol, error: protocolError } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(*)')
      .eq('id', protocolId)
      .eq('user_id', resolvedUserId)
      .single()

    if (protocolError) throw protocolError

    // Buscar logs do protocolo no período
    const { data: logs, error: logError } = await supabase
      .from('medicine_logs')
      .select('*')
      .eq('protocol_id', protocolId)
      .eq('user_id', resolvedUserId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())

    if (logError) throw logError

    // Calcular doses esperadas para este protocolo
    const expectedDoses = calculateExpectedDoses([protocol], days)
    const takenDoses = logs?.length || 0

    const score = expectedDoses > 0 ? Math.round((takenDoses / expectedDoses) * 100) : 0

    return {
      protocolId,
      name: protocol.name,
      medicineName: protocol.medicine?.name,
      score: Math.min(score, 100),
      taken: takenDoses,
      expected: expectedDoses,
    }
  },

  /**
   * Calcula adesão para todos os protocolos ativos
   * @param {string} period - Período: '7d', '30d', '90d'
   * @param {string} [userId] - ID do usuário (opcional, evita chamadas redundantes ao getUser)
   * @returns {Promise<Array<{protocolId: string, name: string, score: number}>>}
   */
  async calculateAllProtocolsAdherence(period = '30d', userId = null) {
    const { startDate, endDate, days } = _getDateRangeForPeriod(period)

    // Usa userId fornecido ou busca do Supabase
    const resolvedUserId = userId || (await getUserId())

    // Query 1: Buscar todos os protocolos ativos
    const { data: protocols, error } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(*)')
      .eq('user_id', resolvedUserId)
      .eq('active', true)

    if (error) throw error

    if (!protocols || protocols.length === 0) return []

    // M7.1: Query 2 (batch): Buscar APENAS protocol_id — não select('*')
    // Transfere ~50 bytes por log ao invés de ~500 bytes (select '*')
    const { data: allLogs, error: logError } = await supabase
      .from('medicine_logs')
      .select('protocol_id')
      .eq('user_id', resolvedUserId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())

    if (logError) throw logError

    // M7.1: Agrupar por protocol_id client-side — O(M) uma vez
    // Em vez de O(M) × N separado (N = número de protocolos)
    const takenByProtocol = new Map()
    ;(allLogs || []).forEach((log) => {
      if (log.protocol_id) {
        takenByProtocol.set(log.protocol_id, (takenByProtocol.get(log.protocol_id) || 0) + 1)
      }
    })

    // Calcular scores sem mais queries
    return protocols.map((protocol) => {
      const expected = calculateExpectedDoses([protocol], days, endDate)
      const taken = takenByProtocol.get(protocol.id) || 0
      const score = expected > 0 ? Math.min(Math.round((taken / expected) * 100), 100) : 0
      return {
        protocolId: protocol.id,
        name: protocol.name,
        medicineName: protocol.medicine?.name,
        score,
        taken,
        expected,
        error: false,
      }
    })
  },

  /**
   * Calcula o streak atual (dias seguidos com adesão >= 80%)
   * @param {string} [userId] - ID do usuário (opcional, evita chamadas redundantes ao getUser)
   * @returns {Promise<{currentStreak: number, longestStreak: number}>}
   */
  async getCurrentStreak(userId = null) {
    // Usa userId fornecido ou busca do Supabase
    const resolvedUserId = userId || (await getUserId())

    // Buscar logs dos últimos 90 dias
    const endDate = getNow()
    const startDate = addDays(endDate, -90)

    const { data: logs, error } = await supabase
      .from('medicine_logs')
      .select('taken_at')
      .eq('user_id', resolvedUserId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())
      .order('taken_at', { ascending: false })

    if (error) throw error

    // Buscar protocolos ativos para calcular doses esperadas por dia
    const { data: protocols, error: protocolError } = await supabase
      .from('protocols')
      .select('*')
      .eq('user_id', resolvedUserId)
      .eq('active', true)

    if (protocolError) throw protocolError

    // Verificar se há protocolos ativos
    if (!protocols || protocols.length === 0 || !logs || logs.length === 0) {
      return { currentStreak: 0, longestStreak: 0 }
    }

    // Agrupar logs por dia
    const logsByDay = groupLogsByDay(logs)

    // Calcular streaks (passa protocols para calcular expected por dia)
    const { currentStreak, longestStreak } = calculateStreaks(logsByDay, protocols)

    return { currentStreak, longestStreak }
  },

  /**
   * Calcula o maior streak histórico
   * @returns {Promise<number>}
   */
  async getLongestStreak() {
    const { longestStreak } = await this.getCurrentStreak()
    return longestStreak
  },

  /**
   * Retorna resumo completo de adesão para o Dashboard
   * @param {string} period - Período: '7d', '30d', '90d'
   * @returns {Promise<Object>}
   */
  async getAdherenceSummary(period = '30d') {
    const userId = await getUserId()

    // Buscar protocols UMA VEZ — evita 3 queries idênticas nas sub-funções
    const { data: protocols, error: protocolError } = await supabase
      .from('protocols')
      .select('*, medicine:medicines(*)')
      .eq('user_id', userId)
      .eq('active', true)

    if (protocolError) throw protocolError

    // Passa protocols pré-carregados para todas as sub-funções
    const results = await Promise.allSettled([
      this._calculateAdherenceWithProtocols(period, userId, protocols),
      this._calculateAllProtocolsAdherenceWithProtocols(period, userId, protocols),
      this._getCurrentStreakWithProtocols(userId, protocols),
    ])

    const overall =
      results[0].status === 'fulfilled' ? results[0].value : { score: 0, taken: 0, expected: 0 }
    const protocolScores = results[1].status === 'fulfilled' ? results[1].value : []
    const streaks =
      results[2].status === 'fulfilled' ? results[2].value : { currentStreak: 0, longestStreak: 0 }

    return {
      overallScore: overall.score,
      overallTaken: overall.taken,
      overallExpected: overall.expected,
      period,
      protocolScores,
      currentStreak: streaks.currentStreak,
      longestStreak: streaks.longestStreak,
    }
  },

  /**
   * Retorna dados de adesão por dia para sparkline
   * @param {number} days - Número de dias (padrão: 7)
   * @returns {Promise<Array<{date: string, adherence: number, taken: number, expected: number}>>}
   */
  async getDailyAdherence(days = 7) {
    const userId = await getUserId()

    const endDate = getNow()
    const startDate = addDays(endDate, -days)

    // Buscar protocolos ativos
    const { data: protocols, error: protocolError } = await supabase
      .from('protocols')
      .select('*')
      .eq('user_id', userId)
      .eq('active', true)

    if (protocolError) throw protocolError

    // Expandir range de busca para compensar fuso horário
    // Doses tomadas em GMT-3 podem aparecer no dia seguinte em UTC
    const adjustedStartDate = addDays(startDate, -1)
    const adjustedEndDate = addDays(endDate, 1)

    // Buscar logs no período (com range expandido para timezone)
    const { data: logs, error: logError } = await supabase
      .from('medicine_logs')
      .select('taken_at')
      .eq('user_id', userId)
      .gte('taken_at', adjustedStartDate.toISOString())
      .lte('taken_at', adjustedEndDate.toISOString())

    if (logError) throw logError

    // Agrupar logs por dia
    const logsByDay = groupLogsByDay(logs)

    // Gerar array com dados para cada dia (usando data local)
    const dailyData = []
    for (let i = days - 1; i >= 0; i--) {
      const date = addDays(endDate, -i)
      const dateKey = formatLocalDate(date)

      // Calcular doses esperadas para este dia específico (filtra por start_date/end_date)
      const dayExpected = calculateDailyExpectedDoses(protocols, dateKey)

      const taken = logsByDay.get(dateKey) || 0
      const adherence = dayExpected > 0 ? Math.round((taken / dayExpected) * 100) : 0

      dailyData.push({
        date: dateKey,
        taken,
        expected: Math.round(dayExpected),
        adherence: Math.min(adherence, 100),
      })
    }

    return dailyData
  },

  /**
   * Retorna dados de adesão diária DIRETAMENTE DA VIEW (M3 — sem processamento client)
   * @param {number} days - Número de dias (padrão: 30)
   * @returns {Promise<Array<{date: string, adherence: number, taken: number, expected: number}>>}
   */
  async getDailyAdherenceFromView(days = 30) {
    // Validar input com Zod
    const validation = GetDailyAdherenceFromViewSchema.safeParse({ days })
    if (!validation.success) {
      console.error(
        '[adherenceService] Erro validação getDailyAdherenceFromView:',
        validation.error.format()
      )
      return []
    }

    const { days: validDays } = validation.data
    const endDate = getNow()
    const startDate = addDays(endDate, -validDays)

    const startDateStr = formatLocalDate(startDate)
    const endDateStr = formatLocalDate(endDate)

    const { data, error } = await supabase
      .from('v_daily_adherence')
      .select('log_date, expected_doses, taken_doses, adherence_percentage')
      .gte('log_date', startDateStr)
      .lte('log_date', endDateStr)
      .order('log_date', { ascending: true })

    if (error) {
      console.error('[adherenceService] getDailyAdherenceFromView erro:', error)
      throw error
    }

    // Adaptar nomes das colunas para match com SparklineAdesao
    return (data || []).map((row) => ({
      date: row.log_date,
      taken: row.taken_doses,
      expected: row.expected_doses,
      adherence: row.adherence_percentage ?? 0, // NULL → 0% se sem protocolo
    }))
  },

  /**
   * Retorna padrões de adesão HEATMAP DIRETAMENTE DA VIEW (M3 — sem processamento client)
   * Transforma array de linhas (28 = 7×4) em grid 7×4
   * @returns {Promise<{grid: Array, worstCell: Object|null, narrative: string, hasEnoughData: boolean, dayOccurrences: Array}>}
   */
  async getAdherencePatternFromView() {
    const { data, error } = await supabase
      .from('v_adherence_heatmap')
      .select('day_of_week, period_index, expected_doses, taken_doses, adherence_percentage')
      .order('day_of_week')
      .order('period_index')

    if (error) {
      console.error('[adherenceService] getAdherencePatternFromView erro:', error)
      throw error
    }

    // Inicializar e preencher grid de adesão 7×4
    const grid = buildAdherenceGrid(data)

    // Calcular hasEnoughData: pelo menos 7 células com expected_doses > 0
    // (1 período por dia × 7 dias da semana — usuários com só manhã+noite têm 14 células max)
    const filledCells = (data || []).filter((row) => row.expected_doses > 0).length
    const hasEnoughData = filledCells >= 7

    // Encontrar pior célula e gerar narrativa
    const { worstCell, narrative } = buildHeatmapNarrative(data, hasEnoughData)

    return {
      grid,
      worstCell: hasEnoughData ? worstCell : null,
      narrative,
      hasEnoughData,
      dayOccurrences: [0, 0, 0, 0, 0, 0, 0], // Compatibilidade com analyzeAdherencePatterns
    }
  },

  /**
   * @private Variante de calculateAdherence que recebe protocols pré-carregados
   */
  async _calculateAdherenceWithProtocols(period, userId, protocols) {
    const { startDate, endDate, days } = _getDateRangeForPeriod(period)

    // HEAD request — apenas count, zero dados transferidos
    const { count, error: logError } = await supabase
      .from('medicine_logs')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', userId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())

    if (logError) throw logError

    const expectedDoses = calculateExpectedDoses(protocols, days, endDate)
    const takenDoses = count || 0
    const score =
      expectedDoses > 0 ? Math.min(Math.round((takenDoses / expectedDoses) * 100), 100) : 0

    return {
      score,
      taken: takenDoses,
      expected: expectedDoses,
      period,
      startDate: startDate.toISOString(),
      endDate: endDate.toISOString(),
    }
  },

  /**
   * @private Variante de calculateAllProtocolsAdherence que recebe protocols pré-carregados
   */
  async _calculateAllProtocolsAdherenceWithProtocols(period, userId, protocols) {
    const { startDate, endDate, days } = _getDateRangeForPeriod(period)

    if (!protocols || protocols.length === 0) return []

    // Batch: APENAS protocol_id — ~50 bytes por log ao invés de ~500
    const { data: allLogs, error: logError } = await supabase
      .from('medicine_logs')
      .select('protocol_id')
      .eq('user_id', userId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())

    if (logError) throw logError

    // Agrupar por protocol_id client-side: O(M) uma vez
    const takenByProtocol = new Map()
    ;(allLogs || []).forEach((log) => {
      if (log.protocol_id) {
        takenByProtocol.set(log.protocol_id, (takenByProtocol.get(log.protocol_id) || 0) + 1)
      }
    })

    return protocols.map((protocol) => {
      const expected = calculateExpectedDoses([protocol], days, endDate)
      const taken = takenByProtocol.get(protocol.id) || 0
      const score = expected > 0 ? Math.min(Math.round((taken / expected) * 100), 100) : 0
      return {
        protocolId: protocol.id,
        name: protocol.name,
        medicineName: protocol.medicine?.name,
        score,
        taken,
        expected,
        error: false,
      }
    })
  },

  /**
   * @private Variante de getCurrentStreak que recebe protocols pré-carregados
   */
  async _getCurrentStreakWithProtocols(userId, protocols) {
    if (!protocols || protocols.length === 0) {
      return { currentStreak: 0, longestStreak: 0 }
    }

    const endDate = getNow()
    const startDate = addDays(endDate, -90)

    const { data: logs, error } = await supabase
      .from('medicine_logs')
      .select('taken_at')
      .eq('user_id', userId)
      .gte('taken_at', startDate.toISOString())
      .lte('taken_at', endDate.toISOString())
      .order('taken_at', { ascending: false })

    if (error) throw error

    if (!logs || logs.length === 0) {
      return { currentStreak: 0, longestStreak: 0 }
    }

    const logsByDay = groupLogsByDay(logs)
    const { currentStreak, longestStreak } = calculateStreaks(logsByDay, protocols)

    return { currentStreak, longestStreak }
  },
}

/**
 * Calcula doses esperadas para um conjunto de protocolos.
 * Considera start_date e end_date para calcular dias efetivos de cada protocolo.
 *
 * @param {Array} protocols - Array de protocolos
 * @param {number} days - Número de dias do período de análise
 * @param {Date} endDate - Data final do período (padrão: hoje)
 * @returns {number}
 */
function calculateExpectedDoses(protocols, days, endDate = getNow()) {
  if (!protocols || protocols.length === 0) return 0

  // M9.0: Normalizar endDate para fuso de Brasília para evitar day-drift em servidores UTC
  const normalizedEndDate = getSaoPauloTime(endDate)

  // Calcular data de início do período de análise
  const periodStart = addDays(normalizedEndDate, -days + 1)
  periodStart.setHours(0, 0, 0, 0)

  const periodEnd = cloneDate(normalizedEndDate)
  periodEnd.setHours(23, 59, 59, 999)

  return protocols.reduce((total, protocol) => {
    const timesPerDay = protocol.time_schedule?.length || 1
    const frequency = protocol.frequency || 'daily'

    // Calcular frequência real baseada na configuração
    let dailyDoses = timesPerDay

    // Ajustar baseado na frequência
    switch (frequency.toLowerCase()) {
      case 'daily':
      case 'diariamente':
      case 'diário':
        dailyDoses = timesPerDay
        break
      case 'weekly':
      case 'semanal':
      case 'semanalmente':
        dailyDoses = timesPerDay / 7
        break
      case 'every_other_day':
      case 'dia_sim_dia_nao':
      case 'dia sim, dia não':
        dailyDoses = timesPerDay / 2
        break
      default:
        dailyDoses = timesPerDay
    }

    // Calcular dias efetivos do protocolo dentro do período de análise
    let effectiveDays = 0

    // Se não tiver start_date, assume que o protocolo estava ativo desde o início do período
    const protocolStartDate = protocol.start_date
      ? parseLocalDate(protocol.start_date)
      : periodStart

    // Se não tiver end_date, assume que o protocolo continua ativo
    const protocolEndDate = protocol.end_date
      ? parseISO(protocol.end_date + 'T23:59:59')
      : periodEnd

    // Calcular interseção entre período do protocolo e período de análise
    const effectiveStart = parseTimestamp(Math.max(protocolStartDate.getTime(), periodStart.getTime()))
    const effectiveEnd = parseTimestamp(Math.min(protocolEndDate.getTime(), periodEnd.getTime()))

    // Calcular número de dias efetivos (inclusive)
    if (effectiveEnd >= effectiveStart) {
      const diffTime = effectiveEnd.getTime() - effectiveStart.getTime()
      effectiveDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
    }

    return total + dailyDoses * Math.max(effectiveDays, 0)
  }, 0)
}

/**
 * Calcula doses esperadas por dia para uma data específica.
 * Filtra protocolos que estavam ativos na data.
 *
 * @param {Array} protocols - Array de protocolos
 * @param {string} dateStr - Data no formato YYYY-MM-DD (opcional, padrão: hoje)
 * @returns {number}
 */
function calculateDailyExpectedDoses(protocols, dateStr = null) {
  if (!protocols || protocols.length === 0) return 0

  // Se não houver data, usar hoje
  const targetDate = dateStr || getTodayLocal()

  return protocols.reduce((total, protocol) => {
    // Verificar se o protocolo estava ativo nesta data
    if (!isProtocolActiveOnDate(protocol, targetDate)) return total

    const timesPerDay = protocol.time_schedule?.length || 1
    return total + timesPerDay
  }, 0)
}

/**
 * Agrupa logs por dia usando fuso horário local do usuário
 * @param {Array} logs - Array de logs
 * @returns {Map<string, number>}
 */
function groupLogsByDay(logs) {
  const days = new Map()

  logs.forEach((log) => {
    const dayKey = formatLocalDate(parseISO(log.taken_at))
    days.set(dayKey, (days.get(dayKey) || 0) + 1)
  })

  return days
}

/**
 * Verifica se protocolo estava ativo numa data usando comparação de strings.
 * Strings YYYY-MM-DD são lexicograficamente ordenáveis — sem criar Date objects.
 * @param {string} dateStr - Data YYYY-MM-DD
 * @param {string|null} startStr - start_date do protocolo (ou null)
 * @param {string|null} endStr - end_date do protocolo (ou null)
 * @returns {boolean}
 */
function isActiveOnDateFast(dateStr, startStr, endStr) {
  if (startStr && dateStr < startStr) return false
  if (endStr && dateStr > endStr) return false
  return true
}

/**
 * Calcula doses esperadas por dia usando dados pré-parseados (zero Date objects).
 * @param {Array<{timesPerDay: number, startStr: string|null, endStr: string|null}>} parsed
 * @param {string} dateStr - Data YYYY-MM-DD
 * @returns {number}
 */
function dailyExpectedFast(parsed, dateStr) {
  let total = 0
  for (let i = 0; i < parsed.length; i++) {
    const p = parsed[i]
    if (isActiveOnDateFast(dateStr, p.startStr, p.endStr)) {
      total += p.timesPerDay
    }
  }
  return total
}

/**
 * Calcula streaks (atual e maior)
 * Considera start_date e end_date dos protocolos para calcular expected por dia.
 * Otimizado: pré-parseia datas dos protocolos e usa comparação de strings (R-128).
 *
 * @param {Map} logsByDay - Logs agrupados por dia
 * @param {Array} protocols - Array de protocolos ativos
 * @returns {{currentStreak: number, longestStreak: number}}
 */
function calculateStreaks(logsByDay, protocols) {
  // Criar array de datas ordenadas (mais recente primeiro)
  const dates = Array.from(logsByDay.keys()).sort().reverse()

  if (dates.length === 0 || !protocols || protocols.length === 0) {
    return { currentStreak: 0, longestStreak: 0 }
  }

  // Pré-parsear protocolos UMA VEZ (evita ~2700 parseISO() no loop)
  const parsed = protocols.map((p) => ({
    timesPerDay: p.time_schedule?.length || 1,
    startStr: p.start_date || null,
    endStr: p.end_date || null,
  }))

  let currentStreak = 0
  let longestStreak = 0
  let tempStreak = 0
  let isCurrent = true
  const minAdherenceRate = 0.8 // 80% de adesão para contar o dia

  // Usar funções utilitárias para today/yesterday (timezone local)
  const today = getTodayLocal()
  const yesterdayKey = getYesterdayLocal()

  // Calcular expected para hoje e ontem (com funções otimizadas)
  const todayExpected = dailyExpectedFast(parsed, today)
  const yesterdayExpected = dailyExpectedFast(parsed, yesterdayKey)

  // Verificar se o streak ainda está ativo
  const lastLogDate = dates[0]
  const hasTakenToday =
    lastLogDate === today &&
    todayExpected > 0 &&
    (logsByDay.get(today) || 0) >= todayExpected * minAdherenceRate
  const hasTakenYesterday =
    lastLogDate === yesterdayKey ||
    (dates.includes(yesterdayKey) &&
      yesterdayExpected > 0 &&
      (logsByDay.get(yesterdayKey) || 0) >= yesterdayExpected * minAdherenceRate)

  if (!hasTakenToday && !hasTakenYesterday) {
    isCurrent = false
  }

  // Calcular streak: itera dia a dia para trás (max 91 iterações)
  const MAX_ITERATIONS = 91
  let checkDate = getNow()
  for (let iter = 0; iter < MAX_ITERATIONS; iter++) {
    const dateKey = formatLocalDate(checkDate)

    const dayExpected = dailyExpectedFast(parsed, dateKey)
    const taken = logsByDay.get(dateKey) || 0
    const adherenceRate = dayExpected > 0 ? taken / dayExpected : 0

    // Se não há doses esperadas neste dia, não conta nem quebra o streak
    if (dayExpected === 0) {
      // Continua para o próximo dia sem afetar o streak
    } else if (adherenceRate >= minAdherenceRate) {
      if (isCurrent) currentStreak++
      tempStreak++
    } else {
      if (isCurrent) {
        // Verificar se é hoje (ainda pode tomar)
        if (dateKey !== today) {
          isCurrent = false
        }
      }
      longestStreak = Math.max(longestStreak, tempStreak)
      tempStreak = 0
    }

    // Ir para o dia anterior
    checkDate.setDate(checkDate.getDate() - 1)

    // Parar se passou de 90 dias e streak quebrou
    if (tempStreak === 0 && !isCurrent) {
      break
    }
  }

  longestStreak = Math.max(longestStreak, tempStreak)

  return { currentStreak, longestStreak }
}

export default adherenceService

import { useState } from 'react'
import { supabase } from '@shared/utils/supabase'
import Button from './ui/Button'
import Card from './ui/Card'

export default function TestConnection() {
  const [status, setStatus] = useState('idle')
  const [message, setMessage] = useState('')

  const testConnection = async () => {
    setStatus('loading')
    setMessage('Testando conexão...')

    try {
      // Tenta buscar medicamentos (deve retornar array vazio se não houver dados)
      const { data, error } = await supabase.from('medicines').select('*').limit(1)

      if (error) throw error

      setStatus('success')
      setMessage(
        `✅ Conexão OK! ${data.length === 0 ? 'Banco vazio (normal)' : `${data.length} medicamento(s) encontrado(s)`}`
      )
    } catch (error) {
      setStatus('error')
      setMessage(`❌ Erro: ${error.message}`)
      console.error('Erro de conexão:', error)
    }
  }

  return (
    <Card>
      <h3>🔌 Teste de Conexão Supabase</h3>
      <p
        style={{
          color: 'var(--text-secondary)',
          fontSize: 'var(--font-size-sm)',
          marginBottom: 'var(--space-4)',
        }}
      >
        Clique para verificar se o banco de dados está conectado
      </p>

      <Button variant="primary" onClick={testConnection} disabled={status === 'loading'}>
        {status === 'loading' ? 'Testando...' : 'Testar Conexão'}
      </Button>

      {message && (
        <div
          style={{
            marginTop: 'var(--space-4)',
            padding: 'var(--space-4)',
            borderRadius: 'var(--radius-md)',
            backgroundColor:
              status === 'error' ? 'rgba(255, 0, 110, 0.1)' : 'rgba(0, 255, 136, 0.1)',
            border: `1px solid ${status === 'error' ? 'var(--color-error)' : 'var(--color-success)'}`,
            color: status === 'error' ? 'var(--color-error)' : 'var(--color-success)',
          }}
        >
          {message}
        </div>
      )}
    </Card>
  )
}

import { useState, useEffect } from 'react'
import { Pill, Folders } from 'lucide-react'
import Button from '@shared/components/ui/Button'
import ProtocolChecklistItem from '@protocols/components/ProtocolChecklistItem'
import { getNow, parseISO, parseLocalDatetime } from '@utils/dateUtils.js'
import './LogForm.css'

export default function LogForm({
  protocols,
  treatmentPlans = [],
  initialValues,
  onSave,
  onCancel,
}) {
  // Helper to format date to local ISO string (YYYY-MM-DDTHH:mm) for datetime-local input
  const toLocalISO = (dateStr) => {
    const date = dateStr ? parseISO(dateStr) : getNow()
    const year = date.getFullYear()
    const month = String(date.getMonth() + 1).padStart(2, '0')
    const day = String(date.getDate()).padStart(2, '0')
    const hours = String(date.getHours()).padStart(2, '0')
    const mins = String(date.getMinutes()).padStart(2, '0')
    return `${year}-${month}-${day}T${hours}:${mins}`
  }

  const [formData, setFormData] = useState({
    type:
      initialValues?.type ||
      (initialValues?.protocol_id
        ? 'protocol'
        : initialValues?.treatment_plan_id
          ? 'plan'
          : 'protocol'),
    id: initialValues?.id || null, // For editing
    protocol_id: initialValues?.protocol_id || '',
    treatment_plan_id: initialValues?.treatment_plan_id || '',
    taken_at: toLocalISO(initialValues?.taken_at),
    quantity_taken: initialValues?.quantity_taken || '',
    notes: initialValues?.notes || '',
  })

  const [selectedPlanProtocols, setSelectedPlanProtocols] = useState([])
  const [errors, setErrors] = useState({})
  const [isSubmitting, setIsSubmitting] = useState(false)

  const selectedProtocol = protocols.find((p) => p.id === formData.protocol_id)
  const selectedPlan = treatmentPlans.find((p) => p.id === formData.treatment_plan_id)

  // Atualizar formData quando initialValues mudar (Deep Linking Interno)
  useEffect(() => {
    if (initialValues) {
      setFormData((prev) => ({
        ...prev,
        type:
          initialValues.type ||
          (initialValues.protocol_id
            ? 'protocol'
            : initialValues.treatment_plan_id
              ? 'plan'
              : 'protocol'),
        protocol_id: initialValues.protocol_id || '',
        treatment_plan_id: initialValues.treatment_plan_id || '',
        taken_at: toLocalISO(initialValues.taken_at),
        quantity_taken: initialValues.quantity_taken || '',
        notes: initialValues.notes || '',
      }))
    }
  }, [initialValues])

  // Auto-select all protocols when a plan is selected
  useEffect(() => {
    if (formData.type === 'plan' && formData.treatment_plan_id) {
      const plan = treatmentPlans.find((p) => p.id === formData.treatment_plan_id)
      if (plan) {
        const activeIds = plan.protocols?.filter((p) => p.active).map((p) => p.id) || []
        setSelectedPlanProtocols(activeIds)
      }
    } else {
      setSelectedPlanProtocols([])
    }
  }, [formData.treatment_plan_id, formData.type, treatmentPlans])

  const handleChange = (e) => {
    const { name, value } = e.target
    setFormData((prev) => ({ ...prev, [name]: value }))
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }))
    }
  }

  const toggleProtocol = (protocolId) => {
    setSelectedPlanProtocols((prev) => {
      if (prev.includes(protocolId)) {
        return prev.filter((id) => id !== protocolId)
      } else {
        return [...prev, protocolId]
      }
    })

    // Clear error if selection becomes valid
    if (errors.submit && selectedPlanProtocols.length === 0) {
      // logic inverted because state update is async, but simple check is enough
      setErrors((prev) => ({ ...prev, submit: '' }))
    }
  }

  const validate = () => {
    const newErrors = {}

    if (formData.type === 'protocol' && !formData.protocol_id) {
      newErrors.protocol_id = 'Selecione um protocolo'
    }

    if (formData.type === 'plan') {
      if (!formData.treatment_plan_id) {
        newErrors.treatment_plan_id = 'Selecione um plano'
      } else if (selectedPlanProtocols.length === 0) {
        newErrors.submit = 'Selecione pelo menos um medicamento para registrar'
      }
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleSubmit = async (e) => {
    e.preventDefault()

    if (!validate()) return

    setIsSubmitting(true)

    try {
      if (formData.type === 'protocol') {
        const protocol = protocols.find((p) => p.id === formData.protocol_id)
        if (!protocol) {
          throw new Error('Protocolo não encontrado')
        }

        const dataToSave = {
          protocol_id: formData.protocol_id,
          medicine_id: protocol.medicine_id,
          quantity_taken: formData.quantity_taken
            ? parseFloat(String(formData.quantity_taken).replace(',', '.'))
            : protocol.dosage_per_intake,
          taken_at: parseLocalDatetime(formData.taken_at).toISOString(),
          notes: formData.notes.trim() || null,
        }

        if (formData.id) {
          await onSave({ ...dataToSave, id: formData.id })
        } else {
          await onSave(dataToSave)
        }
      } else {
        // Plan bulk log
        const plan = treatmentPlans.find((p) => p.id === formData.treatment_plan_id)
        if (!plan) {
          throw new Error('Plano não encontrado')
        }

        // Filter only selected protocols
        const protocolsToLog =
          plan.protocols?.filter((p) => p.active && selectedPlanProtocols.includes(p.id)) || []

        if (protocolsToLog.length === 0) {
          throw new Error('Nenhum protocolo selecionado')
        }

        const logsToSave = protocolsToLog.map((p) => ({
          protocol_id: p.id,
          medicine_id: p.medicine_id,
          quantity_taken: p.dosage_per_intake,
          taken_at: parseLocalDatetime(formData.taken_at).toISOString(),
          notes: formData.notes.trim()
            ? `[Plano: ${plan.name}] ${formData.notes.trim()}`
            : `[Plano: ${plan.name}]`,
        }))

        await onSave(logsToSave)
      }
    } catch (error) {
      console.error('Erro ao registrar medicamento:', error)
      const errorMessage = error?.message || 'Erro desconhecido ao registrar medicamento'
      setErrors({ submit: errorMessage })
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <form className="log-form" onSubmit={handleSubmit}>
      <h3>Registrar Medicamento Tomado</h3>

      <div className="log-type-toggle">
        <button
          type="button"
          className={formData.type === 'protocol' ? 'active' : ''}
          onClick={() => setFormData((prev) => ({ ...prev, type: 'protocol' }))}
        >
          <Pill size={18} /> Único Remédio
        </button>
        <button
          type="button"
          className={formData.type === 'plan' ? 'active' : ''}
          onClick={() => setFormData((prev) => ({ ...prev, type: 'plan' }))}
          disabled={treatmentPlans.length === 0 || formData.id}
        >
          <Folders size={18} /> Plano Completo
        </button>
      </div>

      <div className="form-group">
        <label htmlFor="taken_at">
          Data e Hora do Registro <span className="required">*</span>
        </label>
        <input
          type="datetime-local"
          id="taken_at"
          name="taken_at"
          value={formData.taken_at}
          onChange={handleChange}
          required
        />
      </div>

      {formData.type === 'protocol' ? (
        <div className="form-group">
          <label htmlFor="protocol_id">
            Protocolo <span className="required">*</span>
          </label>
          <select
            id="protocol_id"
            name="protocol_id"
            value={formData.protocol_id}
            onChange={handleChange}
            className={errors.protocol_id ? 'error' : ''}
          >
            <option value="">Selecione um protocolo</option>
            {protocols.map((protocol) => (
              <option key={protocol.id} value={protocol.id}>
                {protocol.name} - {protocol.medicine?.name}
              </option>
            ))}
          </select>
          {errors.protocol_id && <span className="error-message">{errors.protocol_id}</span>}
        </div>
      ) : (
        <div className="form-group">
          <label htmlFor="treatment_plan_id">
            Plano de Tratamento <span className="required">*</span>
          </label>
          <select
            id="treatment_plan_id"
            name="treatment_plan_id"
            value={formData.treatment_plan_id}
            onChange={handleChange}
            className={errors.treatment_plan_id ? 'error' : ''}
          >
            <option value="">Selecione um plano</option>
            {treatmentPlans.map((plan) => (
              <option key={plan.id} value={plan.id}>
                {plan.name} ({plan.protocols?.filter((p) => p.active).length || 0} remédios)
              </option>
            ))}
          </select>
          {errors.treatment_plan_id && (
            <span className="error-message">{errors.treatment_plan_id}</span>
          )}
        </div>
      )}

      {selectedProtocol && formData.type === 'protocol' && (
        <div className="protocol-info">
          <div className="form-group">
            <label htmlFor="quantity_taken">Quantidade Tomada</label>
            <input
              type="text"
              inputMode="decimal"
              pattern="[0-9]*[.,]?[0-9]*"
              id="quantity_taken"
              name="quantity_taken"
              value={
                formData.quantity_taken ||
                (selectedProtocol ? selectedProtocol.dosage_per_intake : '')
              }
              onChange={handleChange}
              required
            />
          </div>
          <div className="info-item" style={{ marginTop: 'var(--space-2)' }}>
            <span className="info-label">💊 Medicamento:</span>
            <span className="info-value">{selectedProtocol.medicine?.name}</span>
          </div>
        </div>
      )}

      {selectedPlan && formData.type === 'plan' && (
        <div className="protocol-info">
          <p className="plan-summary-title">Selecione os medicamentos tomados:</p>
          <div className="plan-medicines-list">
            {selectedPlan.protocols
              ?.filter((p) => p.active)
              .map((p) => (
                <ProtocolChecklistItem
                  key={p.id}
                  protocol={p}
                  isSelected={selectedPlanProtocols.includes(p.id)}
                  onToggle={toggleProtocol}
                />
              ))}
          </div>
          <div
            style={{
              marginTop: '8px',
              fontSize: '11px',
              color: 'var(--text-tertiary)',
              textAlign: 'right',
            }}
          >
            {selectedPlanProtocols.length} selecionados
          </div>
        </div>
      )}

      <div className="form-group">
        <label htmlFor="notes">Observações (opcional)</label>
        <textarea
          id="notes"
          name="notes"
          value={formData.notes}
          onChange={handleChange}
          placeholder="Ex: Tomei com água, após café da manhã..."
          rows="3"
        />
      </div>

      {errors.submit && <div className="error-banner">❌ {errors.submit}</div>}

      <div className="form-actions">
        <Button type="button" variant="ghost" onClick={onCancel} disabled={isSubmitting}>
          Cancelar
        </Button>
        <Button
          type="submit"
          variant="primary"
          disabled={
            isSubmitting ||
            (formData.type === 'protocol'
              ? !formData.protocol_id
              : !formData.treatment_plan_id || selectedPlanProtocols.length === 0)
          }
        >
          {isSubmitting
            ? 'Salvando...'
            : formData.id
              ? 'Atualizar Registro'
              : formData.type === 'plan' && selectedPlanProtocols.length > 0
                ? `Registrar (${selectedPlanProtocols.length})`
                : 'Registrar Dose'}
        </Button>
      </div>
    </form>
  )
}

import { useState, useCallback } from 'react'
import { z } from 'zod'
import { useOnboarding } from './useOnboarding'
import { cachedStockService } from '@shared/services/cachedServices'
import { formatLocalDate, getNow } from '@utils/dateUtils'
import Button from '@shared/components/ui/Button'
import './StockStep.css'

const stockFormSchema = z.object({
  quantity: z.coerce
    .number({ invalid_type_error: 'Quantidade é obrigatória.' })
    .positive('Quantidade deve ser maior que 0.'),
  unitPrice: z.coerce.number().nonnegative('Preço não pode ser negativo.').optional().nullable(),
})

// Referência para o cálculo de duração do estoque (ex: 2 meses se 1 comprimido/dia)
const PREVIEW_MAX_QUANTITY = 60

export default function StockStep() {
  // 1. States
  const [quantity, setQuantity] = useState('')
  const [unitPrice, setUnitPrice] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)

  // 2. Context
  const { onboardingData, nextStep } = useOnboarding()
  const medicine = onboardingData.medicine

  // 3. Handlers
  const handleSaveStock = useCallback(async () => {
    setError(null)

    // Validação com Zod
    const result = stockFormSchema.safeParse({ quantity, unitPrice })
    if (!result.success) {
      setError(result.error.errors[0]?.message || 'Erro na validação')
      return
    }

    setIsLoading(true)

    try {
      const validatedData = result.data
      await cachedStockService.add({
        medicine_id: medicine.id,
        quantity: validatedData.quantity,
        unit_price: validatedData.unitPrice,
        purchase_date: formatLocalDate(getNow()),
      })

      // Avança para próximo step após sucesso
      nextStep()
    } catch (err) {
      console.error('Erro ao salvar estoque:', err)
      setError(err.message || 'Erro ao salvar estoque. Tente novamente.')
    } finally {
      setIsLoading(false)
    }
  }, [medicine, quantity, unitPrice, nextStep])

  const handleSkip = useCallback(() => {
    nextStep()
  }, [nextStep])

  // Guard clause
  if (!medicine) return null

  return (
    <div className="stock-step">
      <div className="stock-header">
        <h2>Adicionar Estoque Inicial</h2>
        <p>
          Quanto do medicamento <strong>{medicine.name}</strong> você tem agora?
        </p>
      </div>

      <div className="stock-form">
        <div className="form-group">
          <label htmlFor="quantity">Quantidade *</label>
          <input
            id="quantity"
            type="number"
            min="1"
            value={quantity}
            onChange={(e) => setQuantity(e.target.value)}
            placeholder="Ex: 30 comprimidos"
            disabled={isLoading}
          />
          <small>Unidade: comprimidos</small>
        </div>

        <div className="form-group">
          <label htmlFor="unitPrice">Preço unitário (opcional)</label>
          <input
            id="unitPrice"
            type="number"
            min="0"
            step="0.01"
            value={unitPrice}
            onChange={(e) => setUnitPrice(e.target.value)}
            placeholder="Ex: 2.50"
            disabled={isLoading}
          />
          <small>Preço por comprimido em R$</small>
        </div>

        {error && <div className="error-message">{error}</div>}
      </div>

      <div className="stock-preview">
        <div className="preview-label">Previsão de estoque</div>
        <div className="stock-bar">
          <div
            className="stock-fill"
            style={{
              width: quantity
                ? Math.min((Number(quantity) / PREVIEW_MAX_QUANTITY) * 100, 100) + '%'
                : '0%',
            }}
          />
        </div>
        <div className="preview-text">
          {quantity ? `${quantity} comprimidos` : 'Digite a quantidade'}
        </div>
      </div>

      <div className="stock-navigation">
        <Button
          variant="primary"
          onClick={handleSaveStock}
          disabled={isLoading || !quantity}
          className="btn-save"
        >
          {isLoading ? 'Salvando...' : 'Salvar Estoque'}
        </Button>
        <button onClick={handleSkip} disabled={isLoading} className="btn-skip-stock">
          Pular esta etapa
        </button>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Download, X } from 'lucide-react'
import './InstallPrompt.css'
import {
  isStandalone,
  isIOSSafari,
  isChromeAndroid,
  isDesktopChrome,
  canShowNativePrompt,
  wasPromptDismissed,
  dismissPrompt,
  isDismissalExpired,
  getInstallInstructions,
  isPushPermissionGranted,
  supportsWebPush
} from './pwaUtils'
import { webpushService } from '@/shared/services/webpushService'

/**
 * Componente de Prompt de Instalação PWA
 *
 * Exibe um prompt de instalação para usuários em plataformas suportadas.
 * - iOS Safari: Mostra instruções customizadas para "Adicionar à Tela de Início"
 * - Chrome/Android e Desktop: Mostra botão de instalação nativo ou instruções customizadas
 * - Dispensável com persistência via localStorage
 * - Oculto quando o app já está instalado (modo standalone)
 */
export default function InstallPrompt() {
  const [isVisible, setIsVisible] = useState(false)
  const [deferredPrompt, setDeferredPrompt] = useState(null)
  const [showIOSInstructions, setShowIOSInstructions] = useState(false)
  const [platformInfo, setPlatformInfo] = useState({
    isIOSSafari: false,
    isChromeAndroid: false,
    isDesktopChrome: false,
    canShowNativePrompt: false,
  })

  // Detecta plataforma e verifica se o prompt deve ser exibido
  useEffect(() => {
    const checkVisibility = () => {
      // Não exibir se já estiver em modo standalone E já tem permissões (ou não suporta Push)
      if (isStandalone() && (!supportsWebPush() || isPushPermissionGranted())) {
        setIsVisible(false)
        return
      }

      // Não exibir se o usuário dispensou recentemente
      if (wasPromptDismissed() && !isDismissalExpired()) {
        setIsVisible(false)
        return
      }

      // Detecta plataforma
      const isIOS = isIOSSafari()
      const isAndroid = isChromeAndroid()
      const isDesktop = isDesktopChrome()

      setPlatformInfo({
        isIOSSafari: isIOS,
        isChromeAndroid: isAndroid,
        isDesktopChrome: isDesktop,
        canShowNativePrompt: canShowNativePrompt(),
        isStandalone: isStandalone(),
      })

      // Exibe o prompt para plataformas suportadas, ou se já está standalone e falta permissão Push
      const needsPush = isStandalone() && supportsWebPush() && !isPushPermissionGranted()
      const shouldShow = (!isStandalone() && (isIOS || isAndroid || isDesktop)) || needsPush
      setIsVisible(shouldShow)
    }

    checkVisibility()
  }, [])

  // Escuta o evento beforeinstallprompt (Chrome/Edge)
  useEffect(() => {
    const handleBeforeInstallPrompt = (event) => {
      // Previne o prompt padrão do navegador
      event.preventDefault()
      // Armazena o evento para uso posterior
      setDeferredPrompt(event)
    }

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt)

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt)
    }
  }, [])

  // Trata a ação de dispensar o prompt
  const handleDismiss = useCallback(() => {
    setIsVisible(false)
    dismissPrompt(30) // Lembra da dispensa por 30 dias
  }, [])

  // Trata o clique no botão de instalação
  const handleInstall = useCallback(async () => {
    // iOS Safari - exibe instruções
    if (platformInfo.isIOSSafari) {
      setShowIOSInstructions(true)
      return
    }

    // Chrome/Edge com prompt adiado disponível
    if (deferredPrompt) {
      try {
        // Exibe o prompt nativo de instalação
        deferredPrompt.prompt()

        // Aguarda a escolha do usuário
        const { outcome } = await deferredPrompt.userChoice

        if (outcome === 'accepted') {
          setIsVisible(false)
        }

        // Limpa o prompt adiado
        setDeferredPrompt(null)
      } catch (error) {
        console.error('[PWA Install] Erro ao exibir prompt:', error)
      }
      return
    }

    // Se já é standalone e suporta Web Push, mas não concedeu ainda, tentar assinar
    if (platformInfo.isStandalone && supportsWebPush() && !isPushPermissionGranted()) {
      try {
        await webpushService.subscribe()
        setIsVisible(false)
      } catch (error) {
        console.error('Falha ao assinar Web Push:', error)
      }
      return
    }

    // Chrome Android sem prompt adiado - exibe instruções manuais
    if (platformInfo.isChromeAndroid) {
      setShowIOSInstructions(true) // Reutiliza o modal de instruções
      return
    }

    // Desktop Chrome/Edge sem prompt adiado (comum em dev/localhost)
    // Exibe instruções em vez de não fazer nada
    if (platformInfo.isDesktopChrome) {
      setShowIOSInstructions(true)
      return
    }
  }, [deferredPrompt, platformInfo])

  // Fecha o modal de instruções
  const handleCloseInstructions = useCallback(() => {
    setShowIOSInstructions(false)
    setIsVisible(false)
    dismissPrompt(30)
  }, [])

  // Retorna texto adequado conforme a plataforma
  const getPromptText = () => {
    if (platformInfo.isStandalone) {
      return {
        title: 'Habilitar Notificações',
        description: 'Receba lembretes importantes do seu tratamento no seu dispositivo',
        buttonText: 'Habilitar',
      }
    }

    if (platformInfo.isIOSSafari) {
      return {
        title: 'Adicione à Tela de Início',
        description: 'Acesse o Dosiq rapidamente como um app instalado',
        buttonText: 'Ver Como Instalar',
      }
    }

    if (platformInfo.isChromeAndroid) {
      return {
        title: 'Instale o Dosiq',
        description: 'Acesse rapidamente como um app instalado no seu Android',
        buttonText: 'Instalar Agora',
      }
    }

    return {
      title: 'Instale o Dosiq',
      description: 'Acesse rapidamente como um app nativo no seu computador',
      buttonText: 'Instalar Agora',
    }
  }

  const promptText = getPromptText()
  const instructions = getInstallInstructions()

  return (
    <>
      {/* Banner principal de instalação */}
      <AnimatePresence>
        {isVisible && !showIOSInstructions && (
          <motion.div
            className="install-prompt"
            initial={{ y: -100, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -100, opacity: 0 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            role="dialog"
            aria-label="Prompt de instalação do app"
          >
            <div className="install-prompt__content">
              {/* Ícone do app */}
              <div className="install-prompt__icon" aria-hidden="true">
                <Download size={24} />
              </div>

              {/* Conteúdo textual */}
              <div className="install-prompt__text">
                <h3 className="install-prompt__title">{promptText.title}</h3>
                <p className="install-prompt__description">{promptText.description}</p>
              </div>

              {/* Ações */}
              <div className="install-prompt__actions">
                <button
                  className="install-prompt__install-btn"
                  onClick={handleInstall}
                  type="button"
                >
                  {promptText.buttonText}
                </button>
                <button
                  className="install-prompt__dismiss-btn"
                  onClick={handleDismiss}
                  type="button"
                  aria-label="Fechar prompt de instalação"
                >
                  <X size={16} aria-hidden="true" />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Modal de instruções iOS/Android */}
      <AnimatePresence>
        {showIOSInstructions && (
          <motion.div
            className="install-prompt__modal-overlay"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={handleCloseInstructions}
            role="dialog"
            aria-modal="true"
            aria-labelledby="install-instructions-title"
          >
            <motion.div
              className="install-prompt__modal"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
            >
              <div className="install-prompt__modal-header">
                <span className="install-prompt__modal-icon" role="img" aria-label="Ícone">
                  {instructions.icon}
                </span>
                <h3 id="install-instructions-title" className="install-prompt__modal-title">
                  {instructions.title}
                </h3>
                <button
                  className="install-prompt__modal-close"
                  onClick={handleCloseInstructions}
                  type="button"
                  aria-label="Fechar instruções"
                >
                  <X size={16} aria-hidden="true" />
                </button>
              </div>

              <div className="install-prompt__modal-content">
                <ol className="install-prompt__steps">
                  {instructions.steps.map((step, index) => (
                    <li key={index} className="install-prompt__step">
                      <span className="install-prompt__step-number">{index + 1}</span>
                      <span className="install-prompt__step-text">{step}</span>
                    </li>
                  ))}
                </ol>

                {platformInfo.isIOSSafari && (
                  <div className="install-prompt__ios-hint">
                    <span role="img" aria-label="Dica">
                      💡
                    </span>
                    <span>
                      Procure o botão
                      <svg
                        className="install-prompt__share-icon"
                        viewBox="0 0 24 24"
                        fill="currentColor"
                        aria-hidden="true"
                      >
                        <path d="M16 5l-1.42-1.42-4.58 4.59V0h-2v8.17L3.42 3.58 2 5l7 7 7-7zm7 6v8c0 1.1-.9 2-2 2H5c-1.1 0-2-.9-2-2v-8H0v8c0 2.76 2.24 5 5 5h14c2.76 0 5-2.24 5-5v-8h-2z" />
                      </svg>{' '}
                      na barra do Safari
                    </span>
                  </div>
                )}
              </div>

              <div className="install-prompt__modal-footer">
                <button
                  className="install-prompt__modal-btn"
                  onClick={handleCloseInstructions}
                  type="button"
                >
                  Entendi
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}

import { useState, useEffect } from 'react'
import { ChevronLeft, ChevronRight } from 'lucide-react'
import { getNow, addDays, getTodayLocal, parseLocalDate, getSaoPauloTime, cloneDate, addMonths } from '@utils/dateUtils.js'
import './Calendar.css'

/**
 * Retorna cor de fundo para o dia baseado na adesão (heat map).
 * @param {{adherence: number, taken: number, expected: number}|undefined} data
 * @returns {string} Cor CSS ou 'transparent'
 */
function getDayColor(data) {
  if (!data) return 'transparent'
  if (data.expected === 0) return 'transparent'
  if (data.adherence === 100) return 'var(--color-success)'
  if (data.adherence > 0) return 'var(--color-warning)'
  return 'var(--color-error)'
}

/**
 * Calendar - Componente de calendario reutilizavel com features opcionais
 *
 * @typedef {Object} CalendarProps
 * @property {Array<string>} [markedDates=[]] - Datas com marcacao
 * @property {Date} [selectedDate] - Data selecionada
 * @property {Function} [onDayClick] - Callback ao clicar em dia
 * @property {boolean} [enableLazyLoad=false] - Habilitar lazy loading de meses
 * @property {Function} [onLoadMonth] - Callback para carregar dados do mes
 * @property {boolean} [enableSwipe=false] - Habilitar navegacao por swipe
 * @property {boolean} [enableMonthPicker=false] - Habilitar seletor de mes
 * @property {Object} [monthPickerRange] - Range do seletor {start, end} em meses
 * @property {Object<string, {adherence: number, taken: number, expected: number}>} [adherenceData={}]
 *   Dados de adesão por dia (YYYY-MM-DD → dados). Quando presente, sobrescreve as cores dos dias.
 */
export default function Calendar({
  markedDates = [],
  selectedDate,
  onDayClick,
  enableLazyLoad = false,
  onLoadMonth,
  enableSwipe = false,
  enableMonthPicker = false,
  monthPickerRange = { start: -12, end: 3 },
  adherenceData = {},
}) {
  const [viewDate, setViewDate] = useState(getSaoPauloTime())
  const [isLoading, setIsLoading] = useState(false)
  const [touchStart, setTouchStart] = useState(null)
  const [touchEnd, setTouchEnd] = useState(null)

  // Lazy loading effect - carrega dados do mes quando viewDate muda
  useEffect(() => {
    if (!enableLazyLoad || !onLoadMonth) return

    const year = viewDate.getFullYear()
    const month = viewDate.getMonth()

    let isCancelled = false

    // Setar loading sincronamente evita race condition com microtasks
    // (rAF anterior causava: finally() rodava antes do rAF → stuck loading)
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setIsLoading(true)

    onLoadMonth(year, month)
      .catch((err) => {
        if (!isCancelled) {
          console.error('Error in onLoadMonth:', err)
        }
      })
      .finally(() => {
        if (!isCancelled) {
          setIsLoading(false)
        }
      })

    return () => {
      isCancelled = true
    }
  }, [viewDate, enableLazyLoad, onLoadMonth])

  // Navigation handlers
  const handlePreviousMonth = () => {
    setViewDate((prevDate) => {
      const newDate = cloneDate(prevDate)
      newDate.setMonth(newDate.getMonth() - 1)
      return newDate
    })
  }

  const handleNextMonth = () => {
    setViewDate((prevDate) => {
      const newDate = cloneDate(prevDate)
      newDate.setMonth(newDate.getMonth() + 1)
      return newDate
    })
  }

  // Month picker handler
  const handleMonthSelect = (e) => {
    const [selectedYear, selectedMonth] = e.target.value.split('-').map(Number)
    const newDate = parseLocalDate(`${selectedYear}-${String(selectedMonth + 1).padStart(2, '0')}-01`)
    setViewDate(newDate)
  }

  // Touch handlers (apenas se enableSwipe)
  const handleTouchStart = (e) => {
    if (!enableSwipe) return
    setTouchEnd(null)
    setTouchStart(e.targetTouches[0].clientX)
  }

  const handleTouchMove = (e) => {
    if (!enableSwipe) return
    setTouchEnd(e.targetTouches[0].clientX)
  }

  const handleTouchEnd = () => {
    if (!enableSwipe || !touchStart || !touchEnd || isLoading) return

    const distance = touchStart - touchEnd
    const isLeftSwipe = distance > 50
    const isRightSwipe = distance < -50

    if (isLeftSwipe) {
      handleNextMonth()
    } else if (isRightSwipe) {
      handlePreviousMonth()
    }
  }

  // Generate month options for picker - defined inline para evitar issues de memoization
  const generateMonthOptions = () => {
    if (!enableMonthPicker) return []

    const monthNamesLocal = [
      'Janeiro',
      'Fevereiro',
      'Marco',
      'Abril',
      'Maio',
      'Junho',
      'Julho',
      'Agosto',
      'Setembro',
      'Outubro',
      'Novembro',
      'Dezembro',
    ]

    const options = []
    const todayNow = getSaoPauloTime()

    // Calcular data inicial baseada no range (setando dia 1 via addMonths para evitar overflow de meses curtos)
    const startDate = addMonths(todayNow, monthPickerRange.start)

    // Calcular data final baseada no range
    const endDate = addMonths(todayNow, monthPickerRange.end)

    let current = cloneDate(startDate)
    while (current <= endDate) {
      options.push({
        value: `${current.getFullYear()}-${current.getMonth()}`,
        label: `${monthNamesLocal[current.getMonth()]} ${current.getFullYear()}`,
      })
      current = cloneDate(current)
      current.setMonth(current.getMonth() + 1)
    }

    return options.reverse()
  }

  // Calendar calculations
  // Calendar calculations - Usando parseLocalDate para garantir integridade do grid
  const daysInMonth = (y, m) => {
    const d = parseLocalDate(`${y}-${String(m + 2).padStart(2, '0')}-01`)
    d.setDate(0)
    return d.getDate()
  }
  const firstDayOfMonth = (y, m) => parseLocalDate(`${y}-${String(m + 1).padStart(2, '0')}-01`).getDay()

  const year = viewDate.getFullYear()
  const month = viewDate.getMonth()

  const monthNames = [
    'Janeiro',
    'Fevereiro',
    'Marco',
    'Abril',
    'Maio',
    'Junho',
    'Julho',
    'Agosto',
    'Setembro',
    'Outubro',
    'Novembro',
    'Dezembro',
  ]

  // Build calendar days
  const days = []
  const totalDays = daysInMonth(year, month)
  const firstDay = firstDayOfMonth(year, month)

  // Preencher dias vazios no inicio
  for (let i = 0; i < firstDay; i++) {
    days.push(
      <div key={`empty-${i}`} className="calendar-day empty" role="gridcell" aria-hidden="true" />
    )
  }

  const todayKey = getTodayLocal() // 'YYYY-MM-DD' em fuso Brasilia (R-020)

  // Preencher dias do mes
  for (let d = 1; d <= totalDays; d++) {
    const dateKey = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`
    const dayDate = parseLocalDate(dateKey)

    const isToday = dateKey === todayKey
    const isSelected =
      selectedDate &&
      (typeof selectedDate === 'string'
        ? dateKey === selectedDate
        : dayDate.getFullYear() === selectedDate.getFullYear() &&
          dayDate.getMonth() === selectedDate.getMonth() &&
          dayDate.getDate() === selectedDate.getDate())

    // Verificar se ha doses registradas neste dia
    // CORRECAO: Usar parsing manual de YYYY-MM-DD para evitar bugs de timezone (R-020)
    // As datas em markedDates estao em formato YYYY-MM-DD (local Brasilia GMT-3)
    const hasLog = markedDates.some((dateStr) => dateStr === dateKey)

    // Heat map de adesão: aplica cor quando adherenceData tem dados para o dia
    const adherenceDayData = adherenceData[dateKey]
    const heatColor = getDayColor(adherenceDayData)
    const hasHeatColor = heatColor !== 'transparent'
    const ariaLabelParts = [
      `${d} de ${monthNames[month]} de ${year}`,
      isToday ? 'Hoje' : null,
      isSelected ? 'Selecionado' : null,
      hasHeatColor
        ? `Adesão ${adherenceDayData?.adherence ?? 0} por cento, ${adherenceDayData?.taken ?? 0} de ${adherenceDayData?.expected ?? 0} doses`
        : hasLog
          ? 'Com registro de dose'
          : 'Sem registros',
    ].filter(Boolean)

    days.push(
      <div
        key={d}
        className={`calendar-day ${isToday ? 'today' : ''} ${isSelected ? 'selected' : ''} ${hasLog ? 'has-log' : ''} ${hasHeatColor ? 'has-adherence' : ''}`}
        style={hasHeatColor ? { '--heat-color': heatColor } : undefined}
        role="gridcell"
        aria-selected={isSelected}
        aria-label={ariaLabelParts.join('. ')}
        onClick={() => onDayClick && onDayClick(dayDate)}
      >
        <span className="day-number">{d}</span>
        {hasLog && !hasHeatColor && <div className="log-dot"></div>}
      </div>
    )
  }

  // Render controls baseado nas features
  const renderControls = () => {
    if (enableMonthPicker) {
      return (
        <div className="calendar-controls">
          <button
            onClick={handlePreviousMonth}
            disabled={isLoading}
            className="calendar-nav-btn"
            aria-label="Mês anterior"
            type="button"
          >
            <ChevronLeft size={20} aria-hidden="true" />
          </button>
          <select
            className="month-picker"
            value={`${year}-${month}`}
            onChange={handleMonthSelect}
            disabled={isLoading}
            aria-label="Selecionar mes"
          >
            {generateMonthOptions().map((opt) => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
          <button
            onClick={handleNextMonth}
            disabled={isLoading}
            className="calendar-nav-btn"
            aria-label="Próximo mês"
            type="button"
          >
            <ChevronRight size={20} aria-hidden="true" />
          </button>
        </div>
      )
    }

    // Controles simples (default)
    return (
      <div className="calendar-controls">
        <button
          onClick={handlePreviousMonth}
          disabled={isLoading}
          className="calendar-nav-btn"
          aria-label="Mês anterior"
          type="button"
        >
          <ChevronLeft size={20} aria-hidden="true" />
        </button>
        <div className="current-month">
          {monthNames[month]} {year}
        </div>
        <button
          onClick={handleNextMonth}
          disabled={isLoading}
          className="calendar-nav-btn"
          aria-label="Próximo mês"
          type="button"
        >
          <ChevronRight size={20} aria-hidden="true" />
        </button>
      </div>
    )
  }

  return (
    <div className="calendar-widget">
      {renderControls()}
      <div className="calendar-weekdays" aria-hidden="true">
        <div>Dom</div>
        <div>Seg</div>
        <div>Ter</div>
        <div>Qua</div>
        <div>Qui</div>
        <div>Sex</div>
        <div>Sab</div>
      </div>
      <div
        className="calendar-grid"
        role="grid"
        aria-label={`Calendário de ${monthNames[month]} de ${year}`}
        onTouchStart={enableSwipe ? handleTouchStart : undefined}
        onTouchMove={enableSwipe ? handleTouchMove : undefined}
        onTouchEnd={enableSwipe ? handleTouchEnd : undefined}
      >
        {isLoading && enableLazyLoad ? (
          <div className="calendar-skeleton">
            {Array(35)
              .fill(0)
              .map((_, i) => (
                <div key={i} className="skeleton-day"></div>
              ))}
          </div>
        ) : (
          (() => {
            const rows = []
            for (let i = 0; i < days.length; i += 7) {
              rows.push(
                <div key={`row-${i / 7}`} className="calendar-grid-row" role="row">
                  {days.slice(i, i + 7)}
                </div>
              )
            }
            return rows
          })()
        )}
      </div>
    </div>
  )
}

