/**
 * useCachedQuery - Hook React para uso do cache SWR
 *
 * Fornece uma interface React-friendly para o queryCache com:
 * - Estados de loading/error/data
 * - Revalidação automática
 * - Refetch manual
 * - Integração com ciclo de vida do componente
 *
 * @module useCachedQuery
 */

import { useState, useEffect, useCallback, useRef } from 'react'
import { webQueryCache } from '@shared/platform/query-cache/webQueryCache'

// Aliases locais para a engine — mantem chamadas internas compactas
const cachedQuery = (key, fetcher, opts) => webQueryCache.cachedQuery(key, fetcher, opts)
const invalidateCache = (pattern) => webQueryCache.invalidate(pattern)

/**
 * Hook para executar queries com cache SWR
 *
 * @param {string} key - Chave única da query (ou null para desabilitar)
 * @param {Function} fetcher - Função que retorna Promise com os dados
 * @param {Object} options - Opções do hook
 * @param {boolean} options.enabled - Se a query está habilitada (padrão: true)
 * @param {number} options.staleTime - Tempo de stale em ms
 * @param {*} options.initialData - Dados iniciais para SSR/hidratação
 * @param {Function} options.onSuccess - Callback quando dados são carregados
 * @param {Function} options.onError - Callback quando ocorre erro
 * @returns {Object} Estado e controles da query
 */
export function useCachedQuery(key, fetcher, options = {}) {
  const { enabled = true, staleTime, initialData, onSuccess, onError } = options

  const [data, setData] = useState(initialData)
  const [isLoading, setIsLoading] = useState(false)
  const [isFetching, setIsFetching] = useState(false)
  const [error, setError] = useState(null)

  // Refs para controle de cancelamento e duplicação
  const isMounted = useRef(true)
  const fetchCount = useRef(0)

  // Função principal de fetch
  const executeQuery = useCallback(
    async (options = {}) => {
      const { force = false, background = false } = options

      if (!key || !enabled || !fetcher) return

      const currentFetch = ++fetchCount.current

      try {
        if (!background) {
          setIsLoading(true)
        }
        setIsFetching(true)
        setError(null)

        // Se force=true, invalida o cache primeiro
        if (force) {
          invalidateCache(key)
        }

        const result = await cachedQuery(key, fetcher, { staleTime })

        // Só atualiza se for a fetch mais recente e componente montado
        if (isMounted.current && currentFetch === fetchCount.current) {
          setData(result)
          setIsLoading(false)
          setIsFetching(false)
          onSuccess?.(result)
        }

        return result
      } catch (err) {
        if (isMounted.current && currentFetch === fetchCount.current) {
          setError(err)
          setIsLoading(false)
          setIsFetching(false)
          onError?.(err)
        }
        throw err
      }
    },
    [key, fetcher, enabled, staleTime, onSuccess, onError]
  )

  // Fetch inicial
  useEffect(() => {
    isMounted.current = true

    if (enabled && key) {
      // Catch rejection to prevent unhandled promise warning
      // (error is already handled in executeQuery catch block and set in state)
      // eslint-disable-next-line react-hooks/set-state-in-effect
      executeQuery().catch(() => {})
    }

    return () => {
      isMounted.current = false
    }
  }, [key, enabled, executeQuery])

  // Refetch manual
  const refetch = useCallback(async () => {
    return executeQuery({ force: true })
  }, [executeQuery])

  // Refetch em background (silencioso)
  const refresh = useCallback(async () => {
    return executeQuery({ background: true })
  }, [executeQuery])

  return {
    data,
    isLoading,
    isFetching,
    error,
    refetch,
    refresh,
  }
}

/**
 * Utilitário para executar múltiplas queries em paralelo
 * Extraído para evitar duplicação entre fetchAll e refetchAll
 */
async function executeParallelQueries(queries) {
  const promises = queries.map(async (query, index) => {
    const { key, fetcher, options = {} } = query
    const { enabled = true, staleTime } = options

    if (!enabled || !key || !fetcher) {
      return { index, data: undefined, error: null }
    }

    try {
      const data = await cachedQuery(key, fetcher, { staleTime })
      return { index, data, error: null }
    } catch (error) {
      return { index, data: undefined, error }
    }
  })

  return Promise.all(promises)
}

/**
 * Hook para múltiplas queries em paralelo com cache SWR
 *
 * @param {Array} queries - Array de { key, fetcher, options }
 * @returns {Object} Estado combinado das queries
 */
export function useCachedQueries(queries) {
  const [results, setResults] = useState(() =>
    queries.map(() => ({
      data: undefined,
      isLoading: false,
      isFetching: false,
      error: null,
    }))
  )

  // Chave estável derivada das query keys (não muda com rerenders desnecessários)
  const queriesKey = queries.map((q) => q.key ?? 'null').join('|')

  // Ref para acessar queries atualizadas dentro do effect sem re-disparar o effect
  // (evita render loop causado por [queries] como dependência)
  const queriesRef = useRef(queries)

  const isMounted = useRef(true)

  // Note: Using [queriesKey] instead of [queries] to prevent infinite render loops.
  // We manually update queriesRef.current inside effect to access fresh query values.
  // This is intentional — queriesKey is a stable string derived from query keys.
  useEffect(() => {
    isMounted.current = true
    queriesRef.current = queries // Update ref inside effect (safe)

    const fetchAll = async () => {
      setResults((prev) => prev.map((r) => ({ ...r, isLoading: true })))

      const settled = await executeParallelQueries(queriesRef.current)

      if (isMounted.current) {
        setResults((prev) => {
          const next = [...prev]
          settled.forEach(({ index, data, error }) => {
            next[index] = {
              data,
              error,
              isLoading: false,
              isFetching: false,
            }
          })
          return next
        })
      }
    }

    fetchAll()

    return () => {
      isMounted.current = false
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [queriesKey]) // Estável: só muda quando as query keys mudam

  // Estados combinados
  const isLoading = results.some((r) => r.isLoading)
  const isFetching = results.some((r) => r.isFetching)
  const hasError = results.some((r) => r.error)
  const errors = results.map((r) => r.error).filter(Boolean)

  // Refetch todas as queries com invalidação
  const refetchAll = useCallback(async () => {
    queriesRef.current.forEach((query) => {
      const { key } = query
      if (key) invalidateCache(key)
    })

    setResults((prev) => prev.map((r) => ({ ...r, isLoading: true })))

    const settled = await executeParallelQueries(queriesRef.current)

    if (isMounted.current) {
      setResults((prev) => {
        const next = [...prev]
        settled.forEach(({ index, data, error }) => {
          next[index] = {
            data,
            error,
            isLoading: false,
            isFetching: false,
          }
        })
        return next
      })
    }
  }, []) // Sem dependências: sempre usa queriesRef.current (stale-safe)

  return {
    results,
    isLoading,
    isFetching,
    hasError,
    errors,
    refetchAll,
  }
}

/**
 * Hook para mutações que invalidam cache após sucesso
 *
 * @param {Function} mutationFn - Função de mutação
 * @param {Object} options - Opções
 * @param {string|Array} options.invalidateKeys - Chaves a invalidar após sucesso
 * @param {Function} options.onSuccess - Callback de sucesso
 * @param {Function} options.onError - Callback de erro
 * @returns {Object} Estado e função de mutação
 */
export function useCachedMutation(mutationFn, options = {}) {
  const { invalidateKeys = [], onSuccess, onError } = options

  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)
  const [data, setData] = useState(null)

  const mutate = useCallback(
    async (variables) => {
      setIsLoading(true)
      setError(null)

      try {
        const result = await mutationFn(variables)
        setData(result)

        // Invalida as chaves especificadas
        const keysToInvalidate = Array.isArray(invalidateKeys) ? invalidateKeys : [invalidateKeys]

        keysToInvalidate.forEach((key) => {
          if (key) {
            invalidateCache(key)
            console.log(`[useCachedMutation] Cache invalidado: ${key}`)
          }
        })

        onSuccess?.(result)
        return result
      } catch (err) {
        setError(err)
        onError?.(err)
        throw err
      } finally {
        setIsLoading(false)
      }
    },
    [mutationFn, invalidateKeys, onSuccess, onError]
  )

  const reset = useCallback(() => {
    setData(null)
    setError(null)
    setIsLoading(false)
  }, [])

  return {
    mutate,
    reset,
    data,
    isLoading,
    error,
    isError: !!error,
  }
}

// Re-exporta funções úteis do query cache (via pacote centralizado — evita duplicação)
export { generateCacheKey } from '@dosiq/shared-data'

export { invalidateCache }

export function prefetchCache(key, data) {
  webQueryCache.prefetch(key, data)
}

export function getCacheStats() {
  return webQueryCache.getStats()
}

export function clearCache() {
  webQueryCache.clear()
}

export function cancelGarbageCollection() {
  webQueryCache.cancelGC()
}

export function restartGarbageCollection() {
  webQueryCache.restartGC()
}

/**
 * useHapticFeedback.js - Hook para feedback tátil (vibração)
 *
 * Funcionalidades:
 * - Vibration API para Android Chrome
 * - Fallback silencioso em iOS/desktop
 * - Tipos de haptic: success, warning, error, selection, impact
 * - Suporte a prefers-reduced-motion
 */

import { useCallback } from 'react'

/**
 * Tipos de feedback háptico pré-definidos
 */
const HAPTIC_PATTERNS = {
  // Feedback positivo (sucesso)
  success: {
    duration: 50,
    pattern: null,
  },
  // Feedback de atenção (aviso)
  warning: {
    duration: 100,
    pattern: null,
  },
  // Feedback negativo (erro)
  error: {
    duration: 200,
    pattern: null,
  },
  // Feedback de seleção
  selection: {
    duration: 10,
    pattern: null,
  },
  // Feedback de impacto leve
  impact: {
    duration: 20,
    pattern: null,
  },
  // Confete/celebração
  celebration: {
    duration: 15,
    pattern: [15, 10, 15, 10, 15, 10, 50],
  },
  // Pulso (para registro de dose)
  pulse: {
    duration: 30,
    pattern: null,
  },
  // Shake (erro de validação)
  shake: {
    duration: 500,
    pattern: [50, 30, 50, 30, 50],
  },
}

/**
 * Hook useHapticFeedback
 *
 * @returns {Object} { trigger, isSupported, vibrate }
 *
 * @example
 * const { trigger, vibrate } = useHapticFeedback()
 *
 * // Usar tipo pré-definido
 * trigger('success')
 *
 * // Vibração customizada
 * vibrate(100)
 */
export function useHapticFeedback() {
  // Verificar se Vibration API é suportada
  const isSupported =
    typeof navigator !== 'undefined' &&
    typeof navigator.vibrate === 'function' &&
    !navigator.userAgent.match(/iPhone|iPad|iPod/i)

  // Verificar prefers-reduced-motion
  const prefersReducedMotion =
    typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches

  /**
   * Função principal de haptic feedback
   * @param {string} type - Tipo de haptic ('success', 'warning', 'error', 'selection', 'impact', 'celebration', 'pulse', 'shake')
   * @param {Object} options - Opções adicionais
   */
  const trigger = useCallback(
    (type, options = {}) => {
      // Se reduced-motion está ativo, não vibrate
      if (prefersReducedMotion) {
        return
      }

      // Se API não é suportada, retorna silenciosamente
      if (!isSupported) {
        return
      }

      const pattern = HAPTIC_PATTERNS[type] || HAPTIC_PATTERNS.selection

      // Se há pattern customizado via options, usa ele
      const patternToUse = options.pattern || pattern.pattern
      const duration = options.duration || pattern.duration

      try {
        if (patternToUse) {
          // Usar pattern de vibração
          navigator.vibrate(patternToUse)
        } else {
          // Usar duração simples
          navigator.vibrate(duration)
        }
      } catch (err) {
        // Silenciosamente ignora erros de vibration API
        console.debug('Haptic feedback error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  /**
   * Função de vibração direta
   * @param {number|number[]} duration - Duração em ms ou array de pattern
   */
  const vibrate = useCallback(
    (duration) => {
      if (prefersReducedMotion || !isSupported) {
        return
      }

      try {
        navigator.vibrate(duration)
      } catch (err) {
        console.debug('Haptic vibration error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  return {
    trigger,
    vibrate,
    isSupported,
  }
}

// Exportar padrões para uso externo se necessário
export { HAPTIC_PATTERNS }

export default useHapticFeedback

/**
 * webQueryCache — Instancia do query cache para a plataforma web
 *
 * Criado via factory do shared-data com:
 * - webStorageAdapter: persistencia via localStorage (via contrato H3.1)
 * - logger: console do browser
 * - configuracoes padrao do projeto
 *
 * IMPORTANTE: init() e chamado aqui para hidratar o cache no bootstrap da web.
 * Em outras plataformas (mobile), o bootstrap chama init() explicitamente.
 *
 * Estrategia de coexistencia (H3.3):
 * - Este modulo cria a nova instancia de cache
 * - useCachedQuery.js importa daqui (nao mais de queryCache.js legado)
 * - queryCache.js legado removido apos validacao bem-sucedida
 */
import { createQueryCache } from '@dosiq/shared-data'
import { webStorageAdapter } from '@shared/platform/storage/webStorageAdapter'

const logger = {
  log: (msg) => {
    if (import.meta.env.DEV) console.debug(msg)
  },
  warn: (msg) => console.warn(msg),
  error: (msg) => console.error(msg),
}

export const webQueryCache = createQueryCache({
  storage: webStorageAdapter,
  logger,
  staleTime: 30_000,
  maxEntries: 200,
  persistKey: 'dosiq_query_cache',
})

// Hidratacao automatica no bootstrap web.
// init() e idempotente — chamadas multiplas sao seguras.
webQueryCache.init().catch((err) => {
  console.warn('[webQueryCache] Falha na inicializacao:', err)
})

/**
 * Logger com suporte a development mode
 * Reduz poluição de console em produção
 *
 * @module logger
 */

const isDev = typeof window !== 'undefined' && process.env.NODE_ENV === 'development'

/**
 * Log de debug (só em development)
 * @param {string} tag - Prefixo [tag] do log
 * @param {string} message - Mensagem principal
 * @param {...*} args - Dados adicionais (opcionais)
 */
export function debugLog(tag, message, ...args) {
  if (isDev) {
    console.log(`[${tag}] ${message}`, ...args)
  }
}

/**
 * Log de erro/warning (sempre, mas formatado)
 * @param {string} tag - Prefixo [tag]
 * @param {string} message - Mensagem
 * @param {...*} args - Erro opcional e outros dados
 */
export function errorLog(tag, message, ...args) {
  console.error(`[${tag}] ${message}`, ...args)
}

/**
 * Log condicional (quando expressão é true)
 * @param {boolean} condition - Condição
 * @param {string} tag - Prefixo
 * @param {string} message - Mensagem
 * @param {...*} args - Dados
 */
export function conditionalLog(condition, tag, message, ...args) {
  if (condition) {
    debugLog(tag, message, ...args)
  }
}

import { useState } from 'react'
import { X } from 'lucide-react'
import { signIn, signUp } from '@shared/utils/supabase'
import './Auth.css'

export default function Auth({ onAuthSuccess, onClose }) {
  const [isLogin, setIsLogin] = useState(true)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)
  const [message, setMessage] = useState(null)

  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)
    setMessage(null)

    try {
      if (isLogin) {
        await signIn(email, password)
        if (onAuthSuccess) onAuthSuccess()
      } else {
        await signUp(email, password)
        setMessage('Conta criada! Verifique seu email para confirmar o cadastro.')
        setIsLogin(true)
      }
    } catch (err) {
      console.error(err)
      let msg = 'Ocorreu um erro.'
      if (err.message.includes('Invalid login credentials')) {
        msg = 'Email ou senha incorretos.'
      } else if (err.message.includes('User already registered')) {
        msg = 'Usuário já cadastrado.'
      } else if (err.message.includes('Password should be at least')) {
        msg = 'A senha deve ter pelo menos 6 caracteres.'
      }
      setError(msg)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="auth-container">
      <div className="auth-card">
        {onClose && (
          <button className="auth-close-btn" onClick={onClose} aria-label="Fechar">
            <X size={20} />
          </button>
        )}
        <div className="auth-header">
          <div className="logo-container">
            <img src="/logo-new.svg" alt="Dosiq" className="auth-logo" />
          </div>
          <h1>{isLogin ? 'Bem-vindo de volta' : 'Crie sua conta'}</h1>
          <p className="auth-subtitle">
            {isLogin ? 'Acesse sua agenda de medicamentos' : 'Comece a gerenciar sua saúde hoje'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="seu@email.com"
              required
              className="auth-input"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Senha</label>
            <input
              id="password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              required
              minLength={6}
              className="auth-input"
            />
          </div>

          {error && <div className="auth-error">{error}</div>}
          {message && <div className="auth-message">{message}</div>}

          <button type="submit" className="auth-submit-btn" disabled={isLoading}>
            {isLoading ? 'Carregando...' : isLogin ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="auth-footer">
          <p>
            {isLogin ? 'Não tem uma conta?' : 'Já tem uma conta?'}
            <button
              className="toggle-auth-btn"
              onClick={() => {
                setIsLogin(!isLogin)
                setError(null)
                setMessage(null)
              }}
            >
              {isLogin ? 'Cadastre-se' : 'Entrar'}
            </button>
          </p>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { medicineService, protocolService, stockService } from '@shared/services' // Import protocolService and stockService
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import EmptyState from '@shared/components/ui/EmptyState'
import MedicineForm from '@medications/components/MedicineForm'
import MedicineCard from '@medications/components/MedicineCard'
import './Medicines.css'

export default function Medicines({ onNavigateToProtocol }) {
  const [medicines, setMedicines] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingMedicine, setEditingMedicine] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [filterType, setFilterType] = useState('all') // 'all', 'medicamento', 'suplemento'
  const [medicineDependencies, setMedicineDependencies] = useState({}) // { medicineId: { hasProtocols: boolean, hasStock: boolean } }

  const loadDependencies = useCallback(async (medicines) => {
    const dependencies = {}
    for (const medicine of medicines) {
      const [protocols, stock] = await Promise.all([
        protocolService.getByMedicineId(medicine.id),
        stockService.getByMedicine(medicine.id),
      ])
      dependencies[medicine.id] = {
        hasProtocols: protocols.length > 0,
        hasStock: stock.length > 0,
      }
    }
    setMedicineDependencies(dependencies)
  }, [])

  const loadMedicines = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const data = await medicineService.getAll()
      setMedicines(data)

      // Load dependencies
      await loadDependencies(data)
    } catch (err) {
      setError('Erro ao carregar medicamentos: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [loadDependencies])

  useEffect(() => {
    loadMedicines()
  }, [loadMedicines])

  const handleAdd = () => {
    setEditingMedicine(null)
    setIsModalOpen(true)
  }

  const handleEdit = (medicine) => {
    setEditingMedicine(medicine)
    setIsModalOpen(true)
  }

  const handleSave = async (medicineData) => {
    try {
      if (editingMedicine) {
        await medicineService.update(editingMedicine.id, medicineData)
        showSuccess('Medicamento atualizado com sucesso!')
      } else {
        const newMedicine = await medicineService.create(medicineData)
        showSuccess('Medicamento cadastrado com sucesso!')

        // UX: Offer to create a protocol immediately
        if (
          window.confirm('✨ Medicamento criado! Deseja criar um protocolo de uso para ele agora?')
        ) {
          if (onNavigateToProtocol) {
            onNavigateToProtocol(newMedicine.id)
            return // Exit early to avoid closing/reloading the current screen unnecessarily
          }
        }
      }

      setIsModalOpen(false)
      setEditingMedicine(null)
      await loadMedicines()
    } catch (err) {
      throw new Error('Erro ao salvar medicamento: ' + err.message)
    }
  }

  const handleDelete = async (medicine) => {
    const hasDependencies =
      medicineDependencies[medicine.id]?.hasProtocols || medicineDependencies[medicine.id]?.hasStock

    if (hasDependencies) {
      const confirmation = window.confirm(
        `Este medicamento possui${medicineDependencies[medicine.id].hasProtocols ? 'protocolos e' : ''} ${medicineDependencies[medicine.id].hasStock ? 'estoque' : ''} associado(s).\nTem certeza que deseja excluí-lo?`
      )
      if (!confirmation) {
        return
      }
    }
    if (!window.confirm(`Tem certeza que deseja excluir "${medicine.name}"?`)) {
      return
    }

    try {
      await medicineService.delete(medicine.id)
      showSuccess('Medicamento excluído com sucesso!')
      await loadMedicines()
    } catch (err) {
      setError('Erro ao excluir medicamento: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  if (isLoading) {
    return (
      <div className="medicines-view">
        <Loading text="Carregando medicamentos..." />
      </div>
    )
  }

  return (
    <div className="medicines-view">
      <div className="medicines-header">
        <div>
          <h2>💊 Medicamentos e Suplementos</h2>
          <p className="medicines-subtitle">Gerencie seus medicamentos cadastrados</p>
        </div>
        <Button variant="primary" onClick={handleAdd}>
          ➕ Adicionar
        </Button>
      </div>

      <div className="filter-tabs" style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <Button
          variant={filterType === 'all' ? 'primary' : 'outline'}
          onClick={() => setFilterType('all')}
          size="sm"
        >
          Todos
        </Button>
        <Button
          variant={filterType === 'medicamento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('medicamento')}
          size="sm"
        >
          Medicamentos
        </Button>
        <Button
          variant={filterType === 'suplemento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('suplemento')}
          size="sm"
        >
          Suplementos
        </Button>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <EmptyState
          illustration="protocols"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar sua saúde"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={handleAdd}
        />
      ) : (
        <div className="medicines-grid">
          {medicines
            .filter((m) => filterType === 'all' || m.type === filterType)
            .map((medicine) => {
              const hasDependencies =
                medicineDependencies[medicine.id]?.hasProtocols ||
                medicineDependencies[medicine.id]?.hasStock
              return (
                <MedicineCard
                  key={medicine.id}
                  medicine={medicine}
                  onEdit={handleEdit}
                  onDelete={handleDelete}
                  hasDependencies={hasDependencies} // Pass this prop to MedicineCard
                />
              )
            })}
        </div>
      )}

      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingMedicine(null)
        }}
      >
        <MedicineForm
          medicine={editingMedicine}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingMedicine(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { medicineService, protocolService, treatmentPlanService } from '@shared/services'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import ProtocolForm from '@protocols/components/ProtocolForm'
import ProtocolCard from '@protocols/components/ProtocolCard'
import TreatmentPlanForm from '@protocols/components/TreatmentPlanForm'
import Card from '@shared/components/ui/Card'
import { calculateTitrationData } from '@utils/titrationUtils'
import './Protocols.css'

export default function Protocols({ initialParams, onClearParams, onNavigateToStock }) {
  const [medicines, setMedicines] = useState([])
  const [protocols, setProtocols] = useState([])
  const [treatmentPlans, setTreatmentPlans] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [isPlanModalOpen, setIsPlanModalOpen] = useState(false)
  const [editingProtocol, setEditingProtocol] = useState(null)
  const [editingPlan, setEditingPlan] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')

  const loadData = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)

      const [medicinesData, protocolsData, plansData] = await Promise.all([
        medicineService.getAll(),
        protocolService.getAll(),
        treatmentPlanService.getAll(),
      ])

      // Enrich protocols with titration data
      const enrichedProtocols = protocolsData.map((p) => ({
        ...p,
        titration_scheduler_data: calculateTitrationData(p),
      }))

      setMedicines(medicinesData)
      setProtocols(enrichedProtocols)
      setTreatmentPlans(plansData)
    } catch (err) {
      setError('Erro ao carregar dados: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [])

  useEffect(() => {
    loadData()
  }, [loadData])

  useEffect(() => {
    if (initialParams?.medicineId && medicines.length > 0) {
      setIsModalOpen(true)
      setEditingProtocol(null)
    }
  }, [initialParams, medicines])

  const handleAdd = () => {
    if (medicines.length === 0) {
      setError('Cadastre um medicamento antes de criar protocolos')
      return
    }
    setEditingProtocol(null)
    setIsModalOpen(true)
  }

  const handleAddPlan = () => {
    setEditingPlan(null)
    setIsPlanModalOpen(true)
  }

  const handleEdit = (protocol) => {
    setEditingProtocol(protocol)
    setIsModalOpen(true)
  }

  const handleEditPlan = (plan) => {
    setEditingPlan(plan)
    setIsPlanModalOpen(true)
  }

  const handleSave = async (protocolData) => {
    try {
      if (editingProtocol) {
        await protocolService.update(editingProtocol.id, protocolData)
        showSuccess('Protocolo atualizado com sucesso!')
      } else {
        await protocolService.create(protocolData)
        showSuccess('Protocolo criado com sucesso!')

        if (
          window.confirm(
            'Protocolo criado! Deseja adicionar o estoque inicial deste medicamento agora?'
          )
        ) {
          onNavigateToStock(protocolData.medicine_id)
        }
      }

      setIsModalOpen(false)
      setEditingProtocol(null)
      if (onClearParams) onClearParams()
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar protocolo: ' + err.message)
    }
  }

  const handleSavePlan = async (planData) => {
    try {
      if (editingPlan) {
        await treatmentPlanService.update(editingPlan.id, planData)
        showSuccess('Plano de tratamento atualizado!')
      } else {
        await treatmentPlanService.create(planData)
        showSuccess('Plano de tratamento criado!')
      }

      setIsPlanModalOpen(false)
      setEditingPlan(null)
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar plano: ' + err.message)
    }
  }

  const handleToggleActive = async (protocol) => {
    try {
      await protocolService.update(protocol.id, { active: !protocol.active })
      showSuccess(`Protocolo ${!protocol.active ? 'ativado' : 'pausado'} com sucesso!`)
      await loadData()
    } catch (err) {
      setError('Erro ao atualizar protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDelete = async (protocol) => {
    if (!window.confirm(`Tem certeza que deseja excluir o protocolo "${protocol.name}"?`)) {
      return
    }

    try {
      await protocolService.delete(protocol.id)
      showSuccess('Protocolo excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDeletePlan = async (plan) => {
    if (
      !window.confirm(
        `Tem certeza que deseja excluir o plano "${plan.name}" e desvincular seus remédios?`
      )
    ) {
      return
    }

    try {
      await treatmentPlanService.delete(plan.id)
      showSuccess('Plano excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir plano: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  // Separar protocolos ativos e inativos
  const activeProtocols = protocols.filter((p) => p.active)
  const inactiveProtocols = protocols.filter((p) => !p.active)

  if (isLoading) {
    return (
      <div className="protocols-view">
        <Loading text="Carregando tratamentos..." />
      </div>
    )
  }

  return (
    <div className="protocols-view">
      <div className="protocols-header">
        <div>
          <h2>📋 Protocolos</h2>
          <p className="protocols-subtitle">
            Gerencie seus protocolos e planos de tratamento agrupados
          </p>
        </div>
        <div style={{ display: 'flex', gap: 'var(--space-2)' }}>
          <Button variant="outline" onClick={handleAddPlan}>
            📁 Novo Plano (Grupo)
          </Button>
          <Button variant="primary" onClick={handleAdd}>
            ➕ Criar Protocolo
          </Button>
        </div>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📋</div>
          <h3>Nenhum medicamento cadastrado</h3>
          <p>Cadastre medicamentos primeiro para criar protocolos</p>
        </div>
      ) : (
        <div className="protocols-content">
          {/* Planos de Tratamentos */}
          {treatmentPlans.length > 0 && (
            <div className="treatment-plans-section">
              <h3 className="section-title plans">📁 Planos de Tratamento</h3>
              <div className="plans-grid">
                {treatmentPlans.map((plan) => (
                  <Card key={plan.id} className="treatment-plan-card">
                    <div className="plan-header">
                      <div>
                        <h4>{plan.name}</h4>
                        <p className="plan-objective">{plan.objective}</p>
                      </div>
                      <div className="plan-actions">
                        <Button variant="ghost" size="sm" onClick={() => handleEditPlan(plan)}>
                          ✏️
                        </Button>
                        <Button variant="ghost" size="sm" onClick={() => handleDeletePlan(plan)}>
                          🗑️
                        </Button>
                      </div>
                    </div>
                    {plan.description && <p className="plan-desc">{plan.description}</p>}

                    <div className="plan-protocols-list">
                      {plan.protocols && plan.protocols.length > 0 ? (
                        plan.protocols.map((p) => (
                          <div key={p.id} className="plan-protocol-row">
                            <span>💊 {p.name}</span>
                            <span className={`titration-status-mini ${p.titration_status}`}>
                              {p.titration_status === 'titulando' ? '📈 Titulando' : '✅'}
                            </span>
                          </div>
                        ))
                      ) : (
                        <p className="empty-plan">Nenhum remédio vinculado ainda.</p>
                      )}
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Protocolos ativos */}
          {activeProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title active">
                {treatmentPlans.length > 0
                  ? '🔍 Todos os Protocolos Ativos'
                  : '✅ Protocolos Ativos'}{' '}
                ({activeProtocols.length})
              </h3>
              <div className="protocols-grid">
                {activeProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Protocolos inativos */}
          {inactiveProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title inactive">
                ⏸️ Protocolos Pausados ({inactiveProtocols.length})
              </h3>
              <div className="protocols-grid">
                {inactiveProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Modal para Protocolos */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingProtocol(null)
          if (onClearParams) onClearParams()
        }}
      >
        <ProtocolForm
          medicines={medicines}
          treatmentPlans={treatmentPlans}
          protocol={editingProtocol}
          initialValues={initialParams ? { medicine_id: initialParams.medicineId } : null}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingProtocol(null)
            if (onClearParams) onClearParams()
          }}
        />
      </Modal>

      {/* Modal para Planos de Tratamento */}
      <Modal
        isOpen={isPlanModalOpen}
        onClose={() => {
          setIsPlanModalOpen(false)
          setEditingPlan(null)
        }}
      >
        <TreatmentPlanForm
          plan={editingPlan}
          onSave={handleSavePlan}
          onCancel={() => {
            setIsPlanModalOpen(false)
            setEditingPlan(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { supabase, signOut, updatePassword } from '@shared/utils/supabase'
import { getNow } from '@utils/dateUtils'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import ExportDialog from '@features/export/components/ExportDialog'
import ReportGenerator from '@features/reports/components/ReportGenerator'
import './Settings.css'

export default function Settings({ onNavigate }) {
  const [user, setUser] = useState(null)
  const [settings, setSettings] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [telegramToken, setTelegramToken] = useState(null)
  const [newPassword, setNewPassword] = useState('')
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(null)
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false)
  const [isReportModalOpen, setIsReportModalOpen] = useState(false)

  useEffect(() => {
    loadProfile()
  }, [])

  const loadProfile = async () => {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      setUser(user)

      const { data, error } = await supabase
        .from('user_settings')
        .select('*')
        .eq('user_id', user.id)
        .single() // Might fail if no settings exist yet

      if (!error && data) {
        setSettings(data)
      } else if (error && error.code !== 'PGRST116') {
        // Ignore "not found"
        console.error(error)
      }
    } catch (err) {
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }

  const handleLogout = async () => {
    try {
      await signOut()
      // App.jsx will handle redirect due to auth state change
    } catch (err) {
      console.error(err)
    }
  }

  const handleUpdatePassword = async (e) => {
    e.preventDefault()
    if (newPassword.length < 6) {
      setError('Senha deve ter no mínimo 6 caracteres')
      return
    }

    try {
      await updatePassword(newPassword)
      setMessage('Senha atualizada com sucesso!')
      setNewPassword('')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      setError('Erro ao atualizar senha: ' + err.message)
    }
  }

  const generateTelegramToken = async () => {
    const token = Math.random().toString(36).substring(2, 8).toUpperCase()

    try {
      const { error } = await supabase.from('user_settings').upsert(
        {
          user_id: user.id,
          verification_token: token,
          updated_at: getNow(),
        },
        { onConflict: 'user_id' }
      )

      if (error) throw error

      setTelegramToken(token)
    } catch (err) {
      console.error(err)
      setError('Erro ao gerar token. Tente novamente.')
    }
  }

  const handleDisconnectTelegram = async () => {
    if (
      !window.confirm(
        'Deseja realmente desconectar o Telegram? Você parará de receber notificações.'
      )
    )
      return

    try {
      const { error } = await supabase
        .from('user_settings')
        .update({
          telegram_chat_id: null,
          verification_token: null,
          updated_at: getNow(),
        })
        .eq('user_id', user.id)

      if (error) throw error

      setSettings((prev) => ({ ...prev, telegram_chat_id: null }))
      setTelegramToken(null)
      setMessage('Telegram desconectado com sucesso!')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      console.error(err)
      setError('Erro ao desconectar Telegram.')
    }
  }

  if (isLoading) return <Loading />

  return (
    <div className="settings-container">
      <h2 className="page-title">Configurações</h2>

      <div className="settings-section">
        <h3>Minha Conta</h3>
        <div className="profile-info">
          <div className="info-row">
            <span className="label">Email</span>
            <span className="value">{user?.email}</span>
          </div>
          <div className="info-row">
            <span className="label">ID</span>
            <span className="value mono">{user?.id?.slice(0, 8)}...</span>
          </div>
        </div>

        <form onSubmit={handleUpdatePassword} className="password-form">
          <h4>Alterar Senha</h4>
          <div className="input-group">
            <input
              type="password"
              placeholder="Nova senha"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="settings-input"
            />
            <Button type="submit" disabled={!newPassword}>
              Atualizar
            </Button>
          </div>
        </form>
      </div>

      <div className="settings-section">
        <h3>Integração Telegram</h3>
        <p className="section-desc">Receba notificações e gerencie seus remédios pelo Telegram.</p>

        <div className="telegram-status">
          Status:
          <span
            className={`status-badge ${settings?.telegram_chat_id ? 'connected' : 'disconnected'}`}
          >
            {settings?.telegram_chat_id ? 'Conectado' : 'Não Conectado'}
          </span>
        </div>

        {settings?.telegram_chat_id ? (
          <div className="connected-actions">
            <p className="section-desc success-text">Bot vinculado com sucesso!</p>
            <Button variant="outline" className="btn-disconnect" onClick={handleDisconnectTelegram}>
              Desconectar Telegram
            </Button>
          </div>
        ) : (
          <div className="connect-telegram">
            {!telegramToken ? (
              <Button onClick={generateTelegramToken}>Gerar Código de Vínculo</Button>
            ) : (
              <div className="token-display">
                <p>Envie este comando para o bot:</p>
                <div className="code-box">/start {telegramToken}</div>
                <a
                  href={`https://t.me/dosiq_bot?start=${telegramToken}`}
                  target="_blank"
                  rel="noreferrer"
                  className="telegram-link"
                >
                  Abrir Bot no Telegram
                </a>
                <Button
                  variant="ghost"
                  className="btn-cancel-token"
                  onClick={() => setTelegramToken(null)}
                >
                  Cancelar
                </Button>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="settings-section">
        <h3>Saúde e Emergência</h3>
        <p className="section-desc">Informações médicas críticas para situações de emergência.</p>

        <div className="emergency-actions">
          <Button variant="outline" onClick={() => onNavigate('emergency')}>
            Cartão de Emergência
          </Button>
          <Button
            variant="outline"
            onClick={() => onNavigate('consultation')}
          >
            Modo Consulta Médica
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Exportar Dados</h3>
        <p className="section-desc">
          Exporte seus dados em formato CSV ou JSON para backup ou análise.
        </p>

        <div className="export-actions">
          <Button variant="outline" onClick={() => setIsExportDialogOpen(true)}>
            Exportar Dados
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Relatórios</h3>
        <p className="section-desc">
          Gere relatórios em PDF com seu histórico de medicamentos e adesão.
        </p>

        <div className="report-actions">
          <Button variant="outline" onClick={() => setIsReportModalOpen(true)}>
            Gerar Relatório PDF
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Administração</h3>
        <p className="section-desc">Ferramentas administrativas do sistema.</p>

        <div className="admin-actions">
          <Button variant="outline" onClick={() => onNavigate('admin-dlq')}>
            Gerenciar Notificações Falhadas (DLQ)
          </Button>
        </div>
      </div>

      {message && <div className="settings-message success">{message}</div>}
      {error && <div className="settings-message error">{error}</div>}

      <div className="logout-section">
        <Button variant="outline" className="logout-btn" onClick={handleLogout}>
          Sair da Conta
        </Button>
      </div>

      <ExportDialog isOpen={isExportDialogOpen} onClose={() => setIsExportDialogOpen(false)} />

      {/* Modal de Geração de Relatórios */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)}>
        <ReportGenerator onClose={() => setIsReportModalOpen(false)} />
      </Modal>
    </div>
  )
}

// src/views/admin/DLQAdmin.jsx
// Dead Letter Queue Admin Interface
import { useState, useEffect, useCallback } from 'react'
import { dlqService } from '@services/api/dlqService'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import './DLQAdmin.css'

// Constantes de formatação
const USER_ID_TRUNCATE_LENGTH = 8
const ERROR_MESSAGE_TRUNCATE_LENGTH = 50

/**
 * DLQAdmin - Interface de administração da Dead Letter Queue
 *
 * Funcionalidades:
 * - Lista notificações falhadas com paginação
 * - Filtra por status
 * - Permite retentar ou descartar notificações
 * - Exibe detalhes de cada notificação
 */
export default function DLQAdmin() {
  // Estados principais
  const [entries, setEntries] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)

  // Estados de paginação
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [pageSize] = useState(20)
  const [totalPages, setTotalPages] = useState(0)

  // Estados de filtro
  const [statusFilter, setStatusFilter] = useState('')

  // Estados de ação
  const [selectedEntry, setSelectedEntry] = useState(null)
  const [showDetails, setShowDetails] = useState(false)
  const [actionLoading, setActionLoading] = useState(null)
  const [actionMessage, setActionMessage] = useState(null)

  // Estados de confirmação
  const [confirmAction, setConfirmAction] = useState(null)
  const [showConfirmModal, setShowConfirmModal] = useState(false)

  // Carregar dados
  const loadEntries = useCallback(async () => {
    setIsLoading(true)
    setError(null)

    try {
      const offset = (page - 1) * pageSize
      const result = await dlqService.getAll({
        limit: pageSize,
        offset,
        status: statusFilter || null,
      })

      setEntries(result.data)
      setTotal(result.total)
      setTotalPages(result.totalPages)
    } catch (err) {
      console.error('[DLQAdmin] Erro ao carregar:', err)
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }, [page, pageSize, statusFilter])

  useEffect(() => {
    loadEntries()
  }, [loadEntries])

  // Handlers de ação com Modal de confirmação
  const handleRetry = async (id) => {
    setConfirmAction({
      type: 'retry',
      id,
      message: 'Deseja retentar esta notificação?',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.retry(id)
          setActionMessage({
            type: 'success',
            text: result.message || 'Notificação reenviada com sucesso!',
          })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  const handleDiscard = async (id) => {
    setConfirmAction({
      type: 'discard',
      id,
      message: 'Deseja descartar esta notificação? Esta ação não pode ser desfeita.',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.discard(id)
          setActionMessage({ type: 'success', text: result.message || 'Notificação descartada.' })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  // Handler de confirmação
  const handleConfirmAction = async () => {
    if (confirmAction?.onConfirm) {
      await confirmAction.onConfirm()
    }
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleCancelConfirm = () => {
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleViewDetails = (entry) => {
    setSelectedEntry(entry)
    setShowDetails(true)
  }

  // Handlers de paginação
  const handlePrevPage = () => {
    if (page > 1) setPage(page - 1)
  }

  const handleNextPage = () => {
    if (page < totalPages) setPage(page + 1)
  }

  // Handler de filtro
  const handleStatusChange = (e) => {
    setStatusFilter(e.target.value)
    setPage(1) // Resetar para primeira página
  }

  // Limpar mensagem após 5 segundos
  useEffect(() => {
    if (actionMessage) {
      const timer = setTimeout(() => setActionMessage(null), 5000)
      return () => clearTimeout(timer)
    }
  }, [actionMessage])

  return (
    <div className="dlq-admin">
      <header className="dlq-admin__header">
        <h1>Dead Letter Queue</h1>
        <p className="dlq-admin__subtitle">Gerenciamento de notificações falhadas</p>
      </header>

      {/* Filtros e estatísticas */}
      <div className="dlq-admin__controls">
        <div className="dlq-admin__filter">
          <label htmlFor="status-filter">Filtrar por status:</label>
          <select
            id="status-filter"
            value={statusFilter}
            onChange={handleStatusChange}
            className="dlq-admin__select"
          >
            <option value="">Todos</option>
            <option value="pending">Pendente</option>
            <option value="retrying">Retentando</option>
            <option value="resolved">Resolvido</option>
            <option value="discarded">Descartado</option>
          </select>
        </div>

        <div className="dlq-admin__stats">
          <span className="dlq-admin__stat">
            <strong>{total}</strong> notificações
          </span>
        </div>
      </div>

      {/* Mensagem de ação */}
      {actionMessage && (
        <div className={`dlq-admin__message dlq-admin__message--${actionMessage.type}`}>
          {actionMessage.text}
        </div>
      )}

      {/* Erro */}
      {error && (
        <div className="dlq-admin__error">
          <p>Erro ao carregar dados: {error}</p>
          <Button onClick={loadEntries} variant="secondary">
            Tentar novamente
          </Button>
        </div>
      )}

      {/* Loading */}
      {isLoading && (
        <div className="dlq-admin__loading">
          <Loading text="Carregando notificações..." />
        </div>
      )}

      {/* Tabela */}
      {!isLoading && !error && (
        <>
          <div className="dlq-admin__table-container">
            <table className="dlq-admin__table">
              <thead>
                <tr>
                  <th>Data/Hora</th>
                  <th>Usuário</th>
                  <th>Tipo</th>
                  <th>Status</th>
                  <th>Erro</th>
                  <th>Tentativas</th>
                  <th>Ações</th>
                </tr>
              </thead>
              <tbody>
                {entries.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="dlq-admin__empty">
                      Nenhuma notificação encontrada
                    </td>
                  </tr>
                ) : (
                  entries.map((entry) => (
                    <tr key={entry.id} className="dlq-admin__row">
                      <td className="dlq-admin__cell dlq-admin__cell--date">
                        {dlqService.formatDate(entry.created_at)}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--user">
                        <span className="dlq-admin__user-id">
                          {entry.user_id
                            ? entry.user_id.substring(0, USER_ID_TRUNCATE_LENGTH) + '...'
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell">
                        {dlqService.formatNotificationType(entry.notification_type)}
                      </td>
                      <td className="dlq-admin__cell">
                        <span
                          className="dlq-admin__status"
                          style={{ color: dlqService.getStatusColor(entry.status) }}
                        >
                          {dlqService.formatStatus(entry.status)}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--error">
                        <span className="dlq-admin__error-text" title={entry.error_message}>
                          {entry.error_message
                            ? entry.error_message.length > ERROR_MESSAGE_TRUNCATE_LENGTH
                              ? entry.error_message.substring(0, ERROR_MESSAGE_TRUNCATE_LENGTH) +
                                '...'
                              : entry.error_message
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--attempts">
                        {entry.retry_count || 0}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--actions">
                        <div className="dlq-admin__actions">
                          <button
                            className="dlq-admin__action-btn dlq-admin__action-btn--view"
                            onClick={() => handleViewDetails(entry)}
                            title="Ver detalhes"
                          >
                            Ver
                          </button>
                          {(entry.status === 'pending' || entry.status === 'retrying') && (
                            <>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--retry"
                                onClick={() => handleRetry(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Retentar"
                              >
                                {actionLoading === entry.id ? '...' : 'Retentar'}
                              </button>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--discard"
                                onClick={() => handleDiscard(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Descartar"
                              >
                                Descartar
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Paginação */}
          {totalPages > 1 && (
            <div className="dlq-admin__pagination">
              <button
                className="dlq-admin__page-btn"
                onClick={handlePrevPage}
                disabled={page === 1}
              >
                Anterior
              </button>
              <span className="dlq-admin__page-info">
                Página {page} de {totalPages}
              </span>
              <button
                className="dlq-admin__page-btn"
                onClick={handleNextPage}
                disabled={page === totalPages}
              >
                Próxima
              </button>
            </div>
          )}
        </>
      )}

      {/* Modal de detalhes */}
      {showDetails && selectedEntry && (
        <Modal isOpen={showDetails} onClose={() => setShowDetails(false)}>
          <div className="dlq-admin__details">
            <h2>Detalhes da Notificação</h2>

            <div className="dlq-admin__detail-grid">
              <div className="dlq-admin__detail-item">
                <label>ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.id}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Correlation ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.correlation_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>User ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.user_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Protocol ID:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--mono">
                  {selectedEntry.protocol_id || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Tipo:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatNotificationType(selectedEntry.notification_type)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Status:</label>
                <span
                  className="dlq-admin__detail-value"
                  style={{ color: dlqService.getStatusColor(selectedEntry.status) }}
                >
                  {dlqService.formatStatus(selectedEntry.status)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Categoria de Erro:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatErrorCategory(selectedEntry.error_category)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Código de Erro:</label>
                <span className="dlq-admin__detail-value">{selectedEntry.error_code || '-'}</span>
              </div>

              <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                <label>Mensagem de Erro:</label>
                <span className="dlq-admin__detail-value dlq-admin__detail-value--error">
                  {selectedEntry.error_message || '-'}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Tentativas:</label>
                <span className="dlq-admin__detail-value">{selectedEntry.retry_count || 0}</span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Criado em:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatDate(selectedEntry.created_at)}
                </span>
              </div>

              <div className="dlq-admin__detail-item">
                <label>Atualizado em:</label>
                <span className="dlq-admin__detail-value">
                  {dlqService.formatDate(selectedEntry.updated_at)}
                </span>
              </div>

              {selectedEntry.resolved_at && (
                <div className="dlq-admin__detail-item">
                  <label>Resolvido em:</label>
                  <span className="dlq-admin__detail-value">
                    {dlqService.formatDate(selectedEntry.resolved_at)}
                  </span>
                </div>
              )}

              {selectedEntry.resolution_notes && (
                <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                  <label>Notas de Resolução:</label>
                  <span className="dlq-admin__detail-value">{selectedEntry.resolution_notes}</span>
                </div>
              )}

              {selectedEntry.notification_payload && (
                <div className="dlq-admin__detail-item dlq-admin__detail-item--full">
                  <label>Payload:</label>
                  <pre className="dlq-admin__detail-value dlq-admin__detail-value--code">
                    {JSON.stringify(selectedEntry.notification_payload, null, 2)}
                  </pre>
                </div>
              )}
            </div>

            <div className="dlq-admin__detail-actions">
              {(selectedEntry.status === 'pending' || selectedEntry.status === 'retrying') && (
                <>
                  <Button
                    onClick={() => {
                      handleRetry(selectedEntry.id)
                      setShowDetails(false)
                    }}
                    disabled={actionLoading === selectedEntry.id}
                  >
                    Retentar
                  </Button>
                  <Button
                    variant="secondary"
                    onClick={() => {
                      handleDiscard(selectedEntry.id)
                      setShowDetails(false)
                    }}
                    disabled={actionLoading === selectedEntry.id}
                  >
                    Descartar
                  </Button>
                </>
              )}
              <Button variant="ghost" onClick={() => setShowDetails(false)}>
                Fechar
              </Button>
            </div>
          </div>
        </Modal>
      )}

      {/* Modal de confirmação */}
      {showConfirmModal && confirmAction && (
        <Modal isOpen={showConfirmModal} onClose={handleCancelConfirm}>
          <div className="dlq-admin__confirm">
            <h2>Confirmar Ação</h2>
            <p>{confirmAction.message}</p>
            <div className="dlq-admin__confirm-actions">
              <Button onClick={handleConfirmAction} disabled={actionLoading === confirmAction.id}>
                Confirmar
              </Button>
              <Button variant="secondary" onClick={handleCancelConfirm}>
                Cancelar
              </Button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  )
}

/**
 * ConsultationRedesign — Container view do Modo Consulta (Santuário Terapêutico).
 * Reutiliza 100% da lógica de dados do Consultation.jsx original.
 * Apenas o presenter muda (ConsultationViewRedesign).
 */

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { getCurrentUser } from '@shared/utils/supabase'
import { cachedAdherenceService } from '@shared/services/cachedServices'
import { getConsultationData } from '@features/consultation/services/consultationDataService'
import ConsultationViewRedesign from '@features/consultation/components/redesign/ConsultationViewRedesign'
import Loading from '@shared/components/ui/Loading'
import { analyticsService } from '@dashboard/services/analyticsService'
import { generateConsultationPDF } from '@features/reports/services/consultationPdfService'
import { formatLocalDate, getNow } from '@utils/dateUtils.js'
import './Consultation.css'

export default function Consultation({ onBack }) {
  const [isLoading, setIsLoading] = useState(true)
  const [consultationData, setConsultationData] = useState(null)
  const [error, setError] = useState(null)

  const { medicines, protocols, logs, stockSummary, stats, dailyAdherence } = useDashboard()

  const dashboardData = useMemo(
    () => ({ medicines, protocols, logs, stockSummary, stats, dailyAdherence }),
    [medicines, protocols, logs, stockSummary, stats, dailyAdherence]
  )

  // Create single 'now' instance for temporal consistency across PDF export, share, and filename generation
  const now = useMemo(() => getNow(), [])

  useEffect(() => {
    let isMounted = true

    const loadConsultationData = async () => {
      try {
        setIsLoading(true)
        setError(null)
        const user = await getCurrentUser()
        const resolvedName = user?.user_metadata?.name || user?.user_metadata?.full_name || ''
        const resolvedEmail = user?.email || ''
        if (!isMounted) return
        if (!dashboardData.medicines || !dashboardData.protocols) {
          if (isMounted) {
            setConsultationData(null)
            setIsLoading(false)
          }
          return
        }
        const data = getConsultationData(dashboardData, resolvedName, null, resolvedEmail)
        setConsultationData(data)
      } catch {
        if (!isMounted) return
        setError('Não foi possível carregar os dados para consulta.')
      } finally {
        if (isMounted) setIsLoading(false)
      }
    }

    loadConsultationData()
    return () => {
      isMounted = false
    }
  }, [dashboardData])

  const handleGeneratePDF = useCallback(async () => {
    try {
      analyticsService.track('consultation_pdf_generated', { timestamp: getNow().getTime() })
      const resolvedDailyAdherence = await cachedAdherenceService.getDailyAdherenceFromView(30)
      const pdfBlob = await generateConsultationPDF({
        consultationData,
        dashboardData: { ...dashboardData, dailyAdherence: resolvedDailyAdherence },
        period: '30d',
      })
      const url = URL.createObjectURL(pdfBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `consulta-medica-${formatLocalDate(now)}.pdf`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
    } catch (error) {
      console.error('Erro ao gerar PDF:', error)
      alert('Erro ao gerar PDF. Tente novamente.')
    }
  }, [consultationData, dashboardData, now])

  const handleShare = useCallback(async () => {
    try {
      analyticsService.track('consultation_share_initiated', { timestamp: getNow().getTime() })
      const resolvedDailyAdherence = await cachedAdherenceService.getDailyAdherenceFromView(30)
      const pdfBlob = await generateConsultationPDF({
        consultationData,
        dashboardData: { ...dashboardData, dailyAdherence: resolvedDailyAdherence },
        period: '30d',
      })
      const fileName = `consulta-medica-${formatLocalDate(now)}.pdf`

      // 1. Tentar Web Share API (mobile nativo)
      if (navigator.share && navigator.canShare) {
        try {
          const file = new File([pdfBlob], fileName, { type: 'application/pdf' })
          if (navigator.canShare({ files: [file] })) {
            await navigator.share({
              title: 'Dados da Consulta Médica',
              text: 'Relatório de tratamento e adesão aos medicamentos',
              files: [file],
            })
            analyticsService.track('consultation_shared', { method: 'web_share_api' })
            return
          }
        } catch (shareErr) {
          // Se usuário cancelou a share sheet, trata como no-op
          if (shareErr.name === 'AbortError') {
            return
          }
          // Caso contrário, fallback para download
          console.warn('Web Share API failed, falling back to download:', shareErr)
        }
      }

      // 2. Fallback: Download direto do PDF
      const url = URL.createObjectURL(pdfBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = fileName
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)

      alert('PDF baixado com sucesso! Você pode compartilhá-lo manualmente.')
      analyticsService.track('consultation_shared', { method: 'download' })
    } catch (error) {
      if (error.name !== 'AbortError') {
        console.error('Share error:', error)
        alert('Erro ao compartilhar. Tente novamente.')
      }
    }
  }, [consultationData, dashboardData, now])

  const handleBack = useCallback(() => {
    analyticsService.track('consultation_mode_closed', { timestamp: getNow().getTime() })
    onBack?.()
  }, [onBack])

  if (isLoading) {
    return (
      <div className="cr-loading">
        <Loading text="Carregando dados da consulta..." />
      </div>
    )
  }

  if (error || !consultationData) {
    return (
      <div className="cr-error">
        <h2 className="cr-error__title">{error ? 'Erro ao carregar' : 'Nenhum dado disponível'}</h2>
        <p className="cr-error__message">
          {error || 'Cadastre medicamentos e tratamentos para visualizar dados na consulta.'}
        </p>
        <button className="btn-primary" onClick={handleBack}>
          Voltar
        </button>
      </div>
    )
  }

  return (
    <ConsultationViewRedesign
      data={consultationData}
      onGeneratePDF={handleGeneratePDF}
      onShare={handleShare}
      onBack={handleBack}
    />
  )
}

import { useState, useEffect, useMemo, useCallback, useRef } from 'react'
import { cachedLogService as logService } from '@shared/services'
import { analyticsService } from '@dashboard/services/analyticsService'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import {
  useDoseZones,
  expandProtocolsToDoses,
  filterTodayLogs,
} from '@dashboard/hooks/useDoseZones'
import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'
import { getCurrentUser, supabase } from '@shared/utils/supabase'
import { getTodayLocal, getNow, getServerTimestamp } from '@utils/dateUtils'
import Loading from '@shared/components/ui/Loading'
import './Dashboard.css'
import RingGaugeRedesign from '@dashboard/components/RingGaugeRedesign'
import PriorityDoseCard from '@dashboard/components/PriorityDoseCard'
import CronogramaPeriodo from '@dashboard/components/CronogramaPeriodo'
import StockAlertInline from '@dashboard/components/StockAlertInline'
import SmartAlertsRedesign from '@dashboard/components/SmartAlertsRedesign'
import InsightCardRedesign from '@dashboard/components/InsightCardRedesign'
import ReminderSuggestionRedesign from '@features/protocols/components/ReminderSuggestionRedesign'
import {
  analyzeReminderTiming,
  isSuggestionDismissed,
  dismissSuggestion,
} from '@features/protocols/services/reminderOptimizerService'
import insightService from '@dashboard/services/insightService'
import { protocolService } from '@features/protocols/services/protocolService'

/**
 * getMotivationalMessage — Mensagem contextual baseada em adesão e doses restantes
 *
 * @param {number} adherenceScore — Score de 0-100
 * @param {number} remainingDoses — Doses não registradas hoje
 * @returns {string} Mensagem motivacional
 */
function getMotivationalMessage(adherenceScore, remainingDoses) {
  if (remainingDoses === 0) {
    return '✅ Perfeito!'
  }
  if (adherenceScore >= 80) {
    return '🌟 Excelente!'
  }
  if (adherenceScore >= 50) {
    return '💪 Quase lá!'
  }
  return '🎯 Vamos retomar'
}

/**
 * DashboardRedesign — View principal do Santuário Terapêutico.
 *
 * Compartilha TODA a lógica de dados com Dashboard.jsx.
 * Diferença: apenas a camada de apresentação.
 *
 * @param {Function} onNavigate — Callback de navegação (view, params?) => void
 */
export default function Dashboard({ onNavigate }) {
  // ── Dados compartilhados (NÃO duplicar) ──
  const {
    stats,
    stockSummary,
    protocols,
    logs,
    refresh,
    isLoading: contextLoading,
  } = useDashboard()
  const { zones, totals, now } = useDoseZones()
  const { mode: complexityMode } = useComplexityMode()

  // ── Estado local ──
  const [userName, setUserName] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const currentDateRef = useRef(getTodayLocal())
  const [dismissedSuggestionId, setDismissedSuggestionId] = useState(null)
  const [snoozedAlerts, setSnoozedAlerts] = useState({})

  // ── Computadas ──
  // Enriquecer doses com dados de estoque
  const stockByMedicineId = useMemo(() => {
    const map = new Map()
    stockSummary?.items?.forEach((item) => map.set(item.medicineId, item))
    return map
  }, [stockSummary])

  // scheduleAllDoses: fonte separada para CronogramaPeriodo — todos os protocolos expandidos (sem filtro classifyDose)
  const scheduleAllDoses = useMemo(() => {
    if (!protocols?.length) return []
    const todayLogs = filterTodayLogs(logs || [])
    return expandProtocolsToDoses(protocols, todayLogs).map((dose) => ({
      ...dose,
      stockDays: stockByMedicineId.get(dose.medicineId)?.daysRemaining ?? null,
      stockStatus: stockByMedicineId.get(dose.medicineId)?.stockStatus ?? null,
    }))
  }, [protocols, logs, stockByMedicineId])

  // urgentDoses: fonte separada para PriorityDoseCard — zonas late/now filtradas
  const urgentDoses = useMemo(
    () => [
      ...(zones.late || []).filter((d) => !d.isRegistered),
      ...(zones.now || []).filter((d) => !d.isRegistered),
    ],
    [zones]
  )

  const criticalStockItems = useMemo(() => {
    if (!stockSummary?.items) return []
    return stockSummary.items.filter(
      (item) => item.stockStatus === 'critical' || item.stockStatus === 'low'
    )
  }, [stockSummary])

  // ── smartAlerts: alertas inteligentes (estoque + dose atrasada + prescrição) ──
  const smartAlerts = useMemo(() => {
    const alerts = []

    // 1. Stock alerts
    stockSummary?.items?.forEach((item) => {
      if (snoozedAlerts[`stock-${item.medicineId}`]) return
      if (item.stockStatus === 'critical' || item.stockStatus === 'low') {
        const severity = item.stockStatus === 'critical' ? 'critical' : 'warning'
        alerts.push({
          id: `stock-${item.medicineId}`,
          severity,
          title:
            severity === 'critical'
              ? `Estoque crítico — ${item.medicineName}`
              : `Estoque baixo — ${item.medicineName}`,
          message:
            severity === 'critical'
              ? `${item.quantity ?? 0} unidades restantes. Reposição urgente.`
              : `${item.daysRemaining} dias restantes. Programe a compra.`,
          actions: [{ label: 'Registrar Compra', type: 'primary' }],
        })
      }
    })

    // 2. Doses atrasadas (zones.late)
    const lateDoses = (zones.late || []).filter((d) => !d.isRegistered)
    if (lateDoses.length > 0 && !snoozedAlerts['late-doses']) {
      const names = lateDoses
        .slice(0, 2)
        .map((d) => d.medicineName)
        .join(', ')
      const extra = lateDoses.length > 2 ? ` +${lateDoses.length - 2}` : ''
      alerts.push({
        id: 'late-doses',
        severity: 'warning',
        title: `${lateDoses.length} dose${lateDoses.length > 1 ? 's' : ''} atrasada${lateDoses.length > 1 ? 's' : ''}`,
        message: `${names}${extra} — registre agora para manter sua adesão.`,
        actions: [{ label: 'Registrar Agora', type: 'primary' }],
      })
    }

    return alerts.sort((a, b) => {
      const order = { critical: 0, warning: 1, info: 2 }
      return (order[a.severity] ?? 2) - (order[b.severity] ?? 2)
    })
  }, [stockSummary, zones, snoozedAlerts])

  // ── currentInsight: insight rotativo do insightService ──
  const currentInsight = useMemo(() => {
    if (!stats) return null
    const insight = insightService.selectBestInsight({
      stats: {
        score: stats.score ?? 0,
        currentStreak: stats.currentStreak ?? 0,
        longestStreak: stats.longestStreak ?? 0,
        adherence: stats.adherence ?? 0,
        activeProtocols: protocols?.filter((p) => p.active)?.length ?? 0,
      },
      dailyAdherence: [],
      stockSummary: stockSummary?.items ?? [],
      logs: logs ?? [],
      onNavigate,
    })
    return insight
  }, [stats, stockSummary, logs, protocols, onNavigate])

  // ── Carregar nome do usuário ──
  useEffect(() => {
    getCurrentUser()
      .then(async (user) => {
        if (!user) return

        // 1. Prioridade: display_name do perfil (user_settings)
        const { data: settings } = await supabase
          .from('user_settings')
          .select('display_name')
          .eq('user_id', user.id)
          .single()

        if (settings?.display_name) {
          setUserName(settings.display_name.split(' ')[0])
        } else if (user?.user_metadata?.full_name) {
          // 2. Fallback: nome do auth metadata
          setUserName(user.user_metadata.full_name.split(' ')[0])
        } else if (user?.email) {
          // 3. Fallback: prefixo do email
          setUserName(user.email.split('@')[0])
        }
      })
      .catch(() => {})
      .finally(() => setIsLoading(false))
  }, [])

  // ── Refresh automático ao virar o dia (timezone local) ──
  useEffect(() => {
    const interval = setInterval(() => {
      const currentDate = getTodayLocal()
      if (currentDate !== currentDateRef.current) {
        currentDateRef.current = currentDate
        refresh()
      }
    }, 60_000)
    return () => clearInterval(interval)
  }, [refresh])

  // ── Sugestão de lembrete calculada (sem setState em effect) ──
  // isSuggestionDismissed e analyzeReminderTiming são funções estáveis importadas (não reativas)
  const reminderSuggestionData = (() => {
    if (!protocols?.length || !logs?.length) return null
    for (const protocol of protocols) {
      if (!protocol.active) continue
      if (protocol.id === dismissedSuggestionId) continue
      if (isSuggestionDismissed(protocol.id)) continue
      const suggestion = analyzeReminderTiming({ protocol, logs })
      if (suggestion?.shouldSuggest) {
        return {
          suggestion,
          protocolId: protocol.id,
          protocolName: protocol.medicine?.name || protocol.name || '',
        }
      }
    }
    return null
  })()

  // ── Handlers ──
  // Registra dose DIRETAMENTE sem modal (1-click experience)
  const handleRegisterDoseQuick = useCallback(
    async (medicineId, protocolId, dosagePerIntake) => {
      try {
        await logService.create({
          medicine_id: medicineId,
          protocol_id: protocolId,
          quantity_taken: dosagePerIntake,
          taken_at: getServerTimestamp(),
        })
        analyticsService.track('dose_registered_quick', {
          timestamp: getNow().getTime(),
          method: 'priority-card',
        })
        refresh()
      } catch (err) {
        console.error('Erro ao registrar dose:', err)
        alert('Erro ao registrar dose. Tente novamente.')
      }
    },
    [refresh]
  )

  // Registra múltiplas doses em batch (PriorityDoseCard com 2+ doses)
  const handleRegisterDosesAll = useCallback(
    async (doses) => {
      if (!doses || doses.length === 0) return
      try {
        for (const dose of doses) {
          await logService.create({
            medicine_id: dose.medicineId,
            protocol_id: dose.protocolId,
            quantity_taken: dose.dosagePerIntake,
            taken_at: getServerTimestamp(),
          })
        }
        analyticsService.track('doses_registered_batch', {
          timestamp: getNow().getTime(),
          method: 'priority-card',
          count: doses.length,
        })
        refresh()
      } catch (err) {
        console.error('Erro ao registrar doses:', err)
        alert('Erro ao registrar doses. Tente novamente.')
      }
    },
    [refresh]
  )

  const handleSnoozeAlert = useCallback((alertId) => {
    setSnoozedAlerts((prev) => ({ ...prev, [alertId]: true }))
  }, [])

  const handleReminderAccept = useCallback(
    async (newTime) => {
      const protocolId = reminderSuggestionData?.protocolId
      const currentTime = reminderSuggestionData?.suggestion?.currentTime
      if (protocolId && newTime && currentTime) {
        // Atualiza time_schedule: substitui horário antigo pelo sugerido
        const protocol = protocols?.find((p) => p.id === protocolId)
        const currentSchedule = protocol?.time_schedule ?? []
        const updatedSchedule = currentSchedule.map((t) => (t === currentTime ? newTime : t))
        // Se o horário antigo não estava no array (edge case), adiciona o novo
        const finalSchedule = updatedSchedule.includes(newTime)
          ? updatedSchedule
          : [...updatedSchedule, newTime]
        try {
          await protocolService.update(protocolId, { time_schedule: finalSchedule })
        } catch (err) {
          console.error('[DashboardRedesign] Erro ao atualizar horário do protocolo:', err)
        }
      }
      if (protocolId) {
        // Persiste dispensa no localStorage (30 dias) para sobreviver ao reload
        dismissSuggestion(protocolId, false)
        setDismissedSuggestionId(protocolId)
      }
      refresh()
    },
    [refresh, reminderSuggestionData, protocols]
  )

  // ── Loading state ──
  if (isLoading || contextLoading) {
    return (
      <div
        style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '50vh',
        }}
      >
        <Loading text="Carregando..." />
      </div>
    )
  }

  const adherenceScore = stats?.score ?? 0
  const streak = stats?.currentStreak ?? 0
  const today = getNow().toLocaleDateString('pt-BR', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
  })

  return (
    <div
      className="page-container"
      style={{ paddingTop: '1.5rem', paddingBottom: '2rem' }}
      aria-label="Dashboard — Dosiq"
    >
      {/* ─── Smart Alerts (substitui StockAlertInline no topo) ─── */}
      {smartAlerts.length > 0 && (
        <section style={{ marginBottom: '1.25rem' }} aria-label="Alertas inteligentes">
          <SmartAlertsRedesign
            alerts={smartAlerts}
            onAction={(alert, action) => {
              if (action.label === 'Registrar Compra') onNavigate?.('stock')
              if (action.label === 'Registrar Agora') onNavigate?.('dashboard')
            }}
            isComplex={complexityMode !== 'simple'}
            onSnooze={handleSnoozeAlert}
          />
        </section>
      )}

      {/* ─── 2-Column Grid: Left (Ring + Greeting + Priority) | Right (Schedule + Stock + Empty) ─── */}
      <div className="grid-dashboard">
        {/* ═══ LEFT COLUMN (1fr) ═══ */}
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '1.5rem',
            alignItems: 'center',
          }}
        >
          {/* Header + Ring de Adesão */}
          <div className="dr-badge">
            <div className="dr-badge__text">
              <h1
                style={{
                  margin: 0,
                  fontFamily: 'var(--font-display, Public Sans, sans-serif)',
                  fontSize: 'var(--text-headline-md, 1.75rem)',
                  fontWeight: '700',
                  color: 'var(--color-on-surface, #191c1d)',
                  lineHeight: 1.2,
                }}
              >
                {userName ? `Olá, ${userName} 👋` : 'Olá! 👋'}
              </h1>

              <p
                style={{
                  margin: '0.25rem 0 0',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-label-md, 0.75rem)',
                  color: 'var(--color-outline, #6d7a76)',
                  textTransform: 'uppercase',
                  letterSpacing: '0.1em',
                  fontWeight: '600',
                }}
              >
                ADESÃO DIÁRIA
              </p>

              <p
                style={{
                  margin: '0.5rem 0 0',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-body-lg, 1rem)',
                  color: 'var(--color-on-surface-variant, #3e4946)',
                }}
              >
                {getMotivationalMessage(adherenceScore, totals.remaining)}
              </p>
            </div>

            <RingGaugeRedesign score={adherenceScore} streak={streak} size="large" />
          </div>

          {/* Priority Dose Card — 1-Click Registration */}
          {urgentDoses.length > 0 && (
            <div style={{ width: '100%' }}>
              <PriorityDoseCard
                doses={urgentDoses}
                onRegister={(dose) =>
                  handleRegisterDoseQuick(dose.medicineId, dose.protocolId, dose.dosagePerIntake)
                }
                onRegisterAll={handleRegisterDosesAll}
                variant="priority"
              />
            </div>
          )}

          {/* 🆕 Insight Card — coluna esquerda, sob o PriorityDoseCard */}
          {currentInsight && (
            <div style={{ width: '100%' }}>
              <InsightCardRedesign
                insight={currentInsight}
                onAction={(insight) => {
                  if (insight.action?.navigate) onNavigate?.(insight.action.navigate)
                }}
                onDismiss={() => {}}
              />
            </div>
          )}

          {/* 🆕 Reminder Suggestion — coluna esquerda, sob o InsightCard */}
          {reminderSuggestionData && (
            <div style={{ width: '100%' }}>
              <ReminderSuggestionRedesign
                suggestion={reminderSuggestionData.suggestion}
                protocolId={reminderSuggestionData.protocolId}
                protocolName={reminderSuggestionData.protocolName}
                onAccept={handleReminderAccept}
                onDismiss={() => setDismissedSuggestionId(reminderSuggestionData.protocolId)}
              />
            </div>
          )}
        </div>

        {/* ═══ RIGHT COLUMN (2fr) ═══ */}
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '1.5rem',
          }}
        >
          {/* Cronograma do Dia */}
          {scheduleAllDoses.length > 0 && (
            <section aria-label="Cronograma de hoje">
              <div style={{ marginBottom: '1rem' }}>
                <h2
                  style={{
                    margin: 0,
                    fontFamily: 'var(--font-display, Public Sans, sans-serif)',
                    fontSize: 'var(--text-title-lg, 1.125rem)',
                    fontWeight: '600',
                    color: 'var(--color-on-surface, #191c1d)',
                  }}
                >
                  Cronograma de Hoje
                </h2>
                <p
                  style={{
                    margin: '0.25rem 0 0',
                    fontFamily: 'var(--font-body, Lexend, sans-serif)',
                    fontSize: 'var(--text-label-md, 0.75rem)',
                    color: 'var(--color-outline, #6d7a76)',
                    textTransform: 'uppercase',
                    letterSpacing: '0.1em',
                    fontWeight: '600',
                  }}
                >
                  {today}
                </p>
              </div>
              <CronogramaPeriodo
                allDoses={scheduleAllDoses}
                onRegister={(dose) =>
                  handleRegisterDoseQuick(dose.medicineId, dose.protocolId, dose.dosagePerIntake)
                }
                variant={complexityMode === 'simple' ? 'simple' : 'complex'}
