              />
            </section>
          )}

          {/* Empty State */}
          {scheduleAllDoses.length === 0 && !contextLoading && (
            <div
              style={{
                textAlign: 'center',
                padding: '3rem 1rem',
                color: 'var(--color-outline, #6d7a76)',
              }}
              role="status"
            >
              <p style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>💊</p>
              <p
                style={{
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontSize: 'var(--text-body-lg, 1rem)',
                }}
              >
                Nenhuma dose agendada para hoje.
              </p>
              <button
                onClick={() => onNavigate?.('medicines')}
                style={{
                  marginTop: '1rem',
                  padding: '0.625rem 1.125rem',
                  minHeight: '3.5rem',
                  background: 'var(--color-primary)',
                  color: 'var(--color-on-primary)',
                  border: 'none',
                  borderRadius: 'var(--radius-button, 1.25rem)',
                  fontFamily: 'var(--font-body, Lexend, sans-serif)',
                  fontWeight: '600',
                  cursor: 'pointer',
                }}
              >
                Adicionar Medicamento
              </button>
            </div>
          )}

          {/* Stock Alert (Simple Mode: Bottom) */}
          {complexityMode !== 'complex' && criticalStockItems.length > 0 && (
            <section style={{ marginTop: 'auto' }} aria-label="Alertas de estoque">
              <StockAlertInline
                criticalItems={criticalStockItems}
                onNavigateToStock={() => onNavigate?.('stock')}
              />
            </section>
          )}
        </div>
      </div>
    </div>
  )
}

// src/views/redesign/HealthHistoryRedesign.jsx
// Wave 10C — Rewrite completo: componente independente calendar-driven (sem Virtuoso, sem wrapper)

import { useState, useEffect, useCallback, useMemo, useRef, lazy, Suspense } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'
import { cachedLogService as logService, cachedAdherenceService as adherenceService  } from '@shared/services'
import { formatLocalDate, parseLocalDate, getSaoPauloTime, getTodayLocal, getNow, parseISO } from '@utils/dateUtils'
import Calendar from '@shared/components/ui/Calendar'
import Modal from '@shared/components/ui/Modal'
import LogForm from '@shared/components/log/LogForm'
import HistoryKPICards from './history/HistoryKPICards'
import HistoryDayPanel from './history/HistoryDayPanel'
import './history/HistoryRedesign.css'

// Lazy: só carrega em modo complex
const SparklineAdesao = lazy(() => import('@dashboard/components/SparklineAdesao'))
const AdherenceHeatmap = lazy(() => import('@adherence/components/AdherenceHeatmap'))

/**
 * Histórico de Doses — Calendar-Driven.
 *
 * Paradigma: calendário é o controle principal de navegação.
 * Fluxo: Selecionar mês → Clicar dia → Ver doses → Editar/Deletar.
 *
 * Performance: 1 query por mês (getByMonthSlim), dados carregados on-demand.
 * SEM Virtuoso, SEM scroll infinito, SEM paginação global.
 *
 * @param {Object} props
 * @param {Function} props.onNavigate - Callback de navegação (para 'profile', etc.)
 */
export default function HealthHistory({ onNavigate }) {
  // ═══ States ═══
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingLog, setEditingLog] = useState(null)
  const [selectedDate, setSelectedDate] = useState(getTodayLocal())
  const [currentMonthLogs, setCurrentMonthLogs] = useState([])
  const [, setTotalLogs] = useState(0)

  // Dados para modo complex (sparkline + heatmap)
  const [dailyAdherence, setDailyAdherence] = useState([])
  const [adherencePattern, setAdherencePattern] = useState(null)

  // ═══ Context ═══
  const { protocols, stats, refresh } = useDashboard()
  const { mode: complexityMode } = useComplexityMode()
  const isComplex = complexityMode === 'complex'

  // ═══ Refs ═══
  const patternLoadedRef = useRef(false)

  // ═══ Memos ═══

  // Planos de tratamento (para LogForm)
  const treatmentPlans = useMemo(() => {
    const plansById = {}

    protocols.forEach((p) => {
      // Para o LogForm (novo log), só reconstruímos planos que têm protocolos ativos
      if (p.treatment_plan_id && p.active) {
        if (!plansById[p.treatment_plan_id]) {
          plansById[p.treatment_plan_id] = {
            ...(p.treatment_plan || { id: p.treatment_plan_id, name: 'Plano s/ nome' }),
            protocols: []
          }
        }
        plansById[p.treatment_plan_id].protocols.push(p)
      }
    })

    return Object.values(plansById)
  }, [protocols])

  // Somente protocolos ativos para o formulário de registro
  const activeProtocols = useMemo(() => protocols.filter(p => p.active), [protocols])

  // Doses do dia selecionado — filtra dos logs do mês carregado, ordenados ascendente
  const dayLogs = useMemo(() => {
    const dStr = typeof selectedDate === 'string' ? selectedDate : formatLocalDate(selectedDate)

    return currentMonthLogs
      .filter((log) => {
        const logDateStr = formatLocalDate(getSaoPauloTime(parseISO(log.taken_at)))
        return logDateStr === dStr
      })
      .sort((a, b) => parseISO(a.taken_at) - parseISO(b.taken_at))
  }, [currentMonthLogs, selectedDate])

  // Datas marcadas no calendário (array de strings 'YYYY-MM-DD')
  const markedDates = useMemo(
    () => currentMonthLogs.map((log) => formatLocalDate(getSaoPauloTime(parseISO(log.taken_at)))),
    [currentMonthLogs]
  )

  // Contadores do mês (para KPI "Doses este Mês")
  const dosesThisMonth = useMemo(() => currentMonthLogs.length, [currentMonthLogs])

  // ═══ Effects ═══

  const loadData = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const now = getNow()

      // Phase 1: UI-critical — logs do mês atual (calendário + day panel)
      const logsResult = await logService.getByMonthSlim(now.getFullYear(), now.getMonth())
      setCurrentMonthLogs(logsResult.data || [])
      setTotalLogs(logsResult.total || 0)

      // Selecionar dia mais recente com dose (ou hoje)
      if (logsResult.data?.length > 0) {
        setSelectedDate(parseISO(logsResult.data[0].taken_at))
      }

      // UI fica interativa AQUI
      setIsLoading(false)

      // Phase 2: Dados deferidos (só se complex)
      if (isComplex) {
        const scheduleIdle = window.requestIdleCallback || ((cb) => setTimeout(cb, 100))
        scheduleIdle(async () => {
          try {
            const daily = await adherenceService.getDailyAdherenceFromView(90)
            setDailyAdherence(daily)
          } catch (err) {
            console.error('[HistoryRedesign] Erro daily adherence:', err.message)
          }

          // Heatmap: carregar direto (sem IntersectionObserver)
          if (!patternLoadedRef.current) {
            try {
              const pattern = await adherenceService.getAdherencePatternFromView()
              setAdherencePattern(pattern)
              patternLoadedRef.current = true
            } catch (err) {
              console.error('[HistoryRedesign] Erro pattern:', err.message)
            }
          }
        })
      }
    } catch (err) {
      setError('Erro ao carregar dados: ' + err.message)
      setIsLoading(false)
    }
  }, [isComplex])

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    loadData()
  }, [loadData])

  // Escuta evento global de dose salva (GlobalDoseModal) para recarregar
  useEffect(() => {
    const handleDoseSaved = () => loadData()
    window.addEventListener('mr:dose-saved', handleDoseSaved)
    return () => window.removeEventListener('mr:dose-saved', handleDoseSaved)
  }, [loadData])

  // ═══ Handlers ═══

  const showSuccess = useCallback((msg) => {
    setSuccessMessage(msg)
    setTimeout(() => setSuccessMessage(''), 3000)
  }, [])

  const handleCalendarLoadMonth = useCallback(async (year, month) => {
    try {
      const result = await logService.getByMonthSlim(year, month)
      setCurrentMonthLogs(result.data || [])
      setTotalLogs(result.total || 0)
      // Selecionar primeiro dia com dose no novo mês, ou dia 1
      if (result.data?.length > 0) {
        setSelectedDate(parseISO(result.data[0].taken_at))
      } else {
        setSelectedDate(parseLocalDate(`${year}-${String(month + 1).padStart(2, '0')}-01`))
      }
      return result
    } catch (err) {
      console.error('[HistoryRedesign] Erro ao carregar mês:', err)
      return { data: [], total: 0 }
    }
  }, [])

  const handleDayClick = useCallback((date) => {
    setSelectedDate(date)
  }, [])

  const handleLogMedicine = useCallback(
    async (logData) => {
      try {
        if (logData.id) {
          await logService.update(logData.id, logData)
          showSuccess('Registro atualizado!')
        } else if (Array.isArray(logData)) {
          await logService.createBulk(logData)
          showSuccess('Plano registrado!')
        } else {
          await logService.create(logData)
          showSuccess('Dose registrada!')
        }
        setIsModalOpen(false)
        setEditingLog(null)
        await loadData()
        refresh()
      } catch (err) {
        console.error('[HistoryRedesign] Erro ao salvar/atualizar log:', err)
        throw new Error(err.message)
      }
    },
    [loadData, refresh, showSuccess]
  )

  const handleDeleteLog = useCallback(
    async (id) => {
      try {
        await logService.delete(id)
        showSuccess('Registro removido!')
        // Remover do state local (otimismo) — evita reload completo
        setCurrentMonthLogs((prev) => prev.filter((log) => log.id !== id))
        setTotalLogs((prev) => Math.max(0, prev - 1))
        refresh()
      } catch (err) {
        setError('Erro ao remover: ' + err.message)
      }
    },
    [refresh, showSuccess]
  )

  const handleEditClick = useCallback((log) => {
    setEditingLog(log)
    setIsModalOpen(true)
  }, [])

  // ═══ Render ═══

  if (isLoading) {
    return (
      <div className="hhr-view">
        <div className="hhr-loading">
          <div className="hhr-loading__spinner" />
          <span>Carregando histórico...</span>
        </div>
      </div>
    )
  }

  return (
    <div className="hhr-view">
      {/* ── Header ── */}
      <div className="hhr-header">
        {onNavigate && (
          <button
            className="hhr-back-btn"
            onClick={() => onNavigate('profile')}
            aria-label="Voltar"
          >
            ← Voltar
          </button>
        )}
        <h1 className="hhr-header__title">Histórico de Doses</h1>
        <p className="hhr-header__subtitle">
          Acompanhe sua jornada de saúde e adesão ao tratamento.
        </p>
      </div>

      {/* ── Feedback messages ── */}
      {successMessage && <div className="hhr-banner hhr-banner--success">{successMessage}</div>}
      {error && <div className="hhr-banner hhr-banner--error">{error}</div>}

      {/* ── KPI Cards ── */}
      <HistoryKPICards
        adherenceScore={stats?.score ?? 0}
        currentStreak={stats?.currentStreak ?? 0}
        dosesThisMonth={dosesThisMonth}
      />

      {/* ── Calendar + Day Panel ── */}
      <div className="hhr-calendar-section">
        <div className="hhr-calendar-card">
          <Calendar
            selectedDate={selectedDate}
            onDayClick={handleDayClick}
            onLoadMonth={handleCalendarLoadMonth}
            markedDates={markedDates}
            enableLazyLoad={true}
            enableSwipe={true}
            enableMonthPicker={true}
          />
        </div>

        <HistoryDayPanel
          selectedDate={selectedDate}
          dayLogs={dayLogs}
          onEditLog={handleEditClick}
          onDeleteLog={handleDeleteLog}
        />
      </div>

      {/* ── Sparkline 30d (complex only) ── */}
      {isComplex && dailyAdherence.length > 0 && (
        <div className="hhr-chart-card">
          <h3 className="hhr-section-title">Adesão 30 Dias</h3>
          <Suspense fallback={<div className="hhr-chart-skeleton" aria-busy="true" />}>
            <SparklineAdesao adherenceByDay={dailyAdherence} size="expanded" />
          </Suspense>
        </div>
      )}

      {/* ── Adherence Heatmap (complex only) ── */}
      {isComplex && adherencePattern && (
        <div className="hhr-chart-card">
          <h3 className="hhr-section-title">Padrão por Período</h3>
          <Suspense fallback={<div className="hhr-chart-skeleton" aria-busy="true" />}>
            <AdherenceHeatmap pattern={adherencePattern} />
          </Suspense>
        </div>
      )}

      {/* ── Modal de edição ── */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingLog(null)
        }}
      >
        <LogForm
          protocols={activeProtocols}
          treatmentPlans={treatmentPlans}
          initialValues={editingLog}
          onSave={handleLogMedicine}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingLog(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useMemo, useCallback } from 'react'
import { Pill, Plus, CheckCircle2, AlertCircle } from 'lucide-react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import { medicineService } from '@shared/services'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import EmptyState from '@shared/components/ui/EmptyState'
import MedicineForm from '@medications/components/MedicineForm'
import MedicineCardRedesign from '@medications/components/redesign/MedicineCardRedesign'
import ConfirmDialog from '@shared/components/ui/ConfirmDialog'
import './Medicines.css'

export default function Medicines({ onNavigateToProtocol }) {
  // 1. Context & Memos
  const {
    medicines: contextMedicines,
    protocols,
    stockSummary,
    isLoading,
    refresh,
  } = useDashboard()

  // 2. States
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingMedicine, setEditingMedicine] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [filterType, setFilterType] = useState('all')
  const [deleteTarget, setDeleteTarget] = useState(null)
  const [showProtocolPrompt, setShowProtocolPrompt] = useState(false)
  const [newMedicineId, setNewMedicineId] = useState(null)

  // 3. Calculate dependencies from dashboard context in-memory
  const medicineDependencies = useMemo(() => {
    const deps = {}
    if (!contextMedicines || !protocols || !stockSummary) return deps

    contextMedicines.forEach((med) => {
      const hasProtocols = protocols.some((p) => p.medicine_id === med.id)
      const hasStock = stockSummary.some((s) => s.medicine_id === med.id)
      deps[med.id] = { hasProtocols, hasStock }
    })
    return deps
  }, [contextMedicines, protocols, stockSummary])

  // 3. Feedback handlers
  const showSuccess = (msg) => {
    setSuccessMessage(msg)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  // 4. Action handlers
  const handleAdd = () => {
    setEditingMedicine(null)
    setIsModalOpen(true)
  }

  const handleEdit = (medicine) => {
    setEditingMedicine(medicine)
    setIsModalOpen(true)
  }

  const handleSave = useCallback(
    async (medicineData) => {
      try {
        if (editingMedicine) {
          await medicineService.update(editingMedicine.id, medicineData)
          showSuccess('Medicamento atualizado com sucesso!')
        } else {
          const newMedicine = await medicineService.create(medicineData)
          showSuccess('Medicamento cadastrado com sucesso!')
          // Show protocol prompt instead of window.confirm()
          setNewMedicineId(newMedicine.id)
          setShowProtocolPrompt(true)
          setIsModalOpen(false)
          setEditingMedicine(null)
          refresh({ force: true })
          return // Don't close modal yet after refetch
        }
        setIsModalOpen(false)
        setEditingMedicine(null)
        refresh({ force: true })
      } catch (err) {
        setError('Erro ao salvar medicamento: ' + err.message)
      }
    },
    [editingMedicine, refresh]
  )

  const handleDeleteRequest = useCallback((medicine) => {
    setDeleteTarget(medicine)
  }, [])

  const handleDeleteConfirm = useCallback(async () => {
    if (!deleteTarget) return
    try {
      await medicineService.delete(deleteTarget.id)
      showSuccess('Medicamento excluído com sucesso!')
      refresh({ force: true })
    } catch (err) {
      setError('Erro ao excluir medicamento: ' + err.message)
    } finally {
      setDeleteTarget(null)
    }
  }, [deleteTarget, refresh])

  const handleProtocolPromptConfirm = () => {
    setShowProtocolPrompt(false)
    if (onNavigateToProtocol && newMedicineId) {
      onNavigateToProtocol(newMedicineId)
    }
    setNewMedicineId(null)
  }

  const handleProtocolPromptCancel = useCallback(() => {
    setShowProtocolPrompt(false)
    setNewMedicineId(null)
    setIsModalOpen(false)
    setEditingMedicine(null)
  }, [])

  // 5. Derived state
  const filteredMedicines = useMemo(
    () => contextMedicines?.filter((m) => filterType === 'all' || m.type === filterType) || [],
    [contextMedicines, filterType]
  )

  if (isLoading) {
    return (
      <div className="sr-medicines">
        <Loading text="Carregando medicamentos..." />
      </div>
    )
  }

  return (
    <div className="sr-medicines">
      {/* Header */}
      <div className="sr-medicines__header">
        <div>
          <div className="sr-medicines__title-group">
            <div className="sr-medicines__title-icon">
              <Pill size={22} />
            </div>
            <h2 className="sr-medicines__title">Medicamentos</h2>
          </div>
          <p className="sr-medicines__subtitle">Gerencie seus medicamentos cadastrados</p>
        </div>
        <button className="btn-primary" onClick={handleAdd}>
          <Plus size={18} /> Adicionar
        </button>
      </div>

      {/* Filter Chips */}
      <div className="sr-medicines__filters">
        {[
          { key: 'all', label: 'Todos' },
          { key: 'medicamento', label: 'Medicamentos' },
          { key: 'suplemento', label: 'Suplementos' },
        ].map(({ key, label }) => (
          <button
            key={key}
            className={`sr-filter-chip ${filterType === key ? 'sr-filter-chip--active' : ''}`}
            onClick={() => setFilterType(key)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Feedback Banners */}
      {successMessage && (
        <div className="sr-medicines__success">
          <CheckCircle2 size={18} /> {successMessage}
        </div>
      )}
      {error && (
        <div className="sr-medicines__error">
          <AlertCircle size={18} /> {error}
        </div>
      )}

      {/* Content */}
      {contextMedicines?.length === 0 ? (
        <EmptyState
          illustration="protocols"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar sua saúde"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={handleAdd}
        />
      ) : (
        <div className="sr-medicines__grid">
          {filteredMedicines.map((medicine) => (
            <MedicineCardRedesign
              key={medicine.id}
              medicine={medicine}
              onEdit={handleEdit}
              onDelete={handleDeleteRequest}
              hasDependencies={
                medicineDependencies[medicine.id]?.hasProtocols ||
                medicineDependencies[medicine.id]?.hasStock
              }
            />
          ))}
        </div>
      )}

      {/* Modal: Edit/Create */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingMedicine(null)
        }}
      >
        <MedicineForm
          medicine={editingMedicine}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingMedicine(null)
          }}
        />
      </Modal>

      {/* ConfirmDialog: Delete */}
      <ConfirmDialog
        isOpen={!!deleteTarget}
        title={`Excluir "${deleteTarget?.name}"?`}
        message={
          medicineDependencies[deleteTarget?.id]?.hasProtocols ||
          medicineDependencies[deleteTarget?.id]?.hasStock
            ? 'Este medicamento possui tratamentos e/ou estoque associados. Esta ação não pode ser desfeita.'
            : 'Esta ação não pode ser desfeita.'
        }
        confirmLabel="Excluir"
        variant="danger"
        onConfirm={handleDeleteConfirm}
        onCancel={() => setDeleteTarget(null)}
      />

      {/* ConfirmDialog: Create Protocol Prompt */}
      <ConfirmDialog
        isOpen={showProtocolPrompt}
        title="Medicamento criado!"
        message="Deseja criar um tratamento para ele agora?"
        confirmLabel="Criar Tratamento"
        cancelLabel="Depois"
        variant="default"
        onConfirm={handleProtocolPromptConfirm}
        onCancel={handleProtocolPromptCancel}
      />
    </div>
  )
}

